export const MATTHEW: Record<number, { verse: number; text: string }[]> = {
 1: [
  { verse: 1, text: "წიგნი შობისა იესო ქრისტესი, ძისა დავითისა, ძისა აბრაამისა." },
  { verse: 2, text: "აბრაამმა შვა ისააკი; ისააკმა შვა იაკობი; იაკობმა შვა იუდა და მისი ძმები." },
  { verse: 3, text: "ხოლო იუდამ შვა ფარეზი და ზარა თამარისაგან; ფარეზმა შვა ესრომი; ესრომმა შვა არამი." },
  { verse: 4, text: "არამმა შვა ამინადაბი; ამინადაბმა შვა ნაასონი; ნაასონმა შვა სალმონი." },
  { verse: 5, text: "სალმონმა შვა ბოოსი რაქაბისაგან; ბოოსმა შვა იობედი რუთისაგან; იობედმა შვა იესე; იესემ შვა მეფე დავითი." },
  { verse: 6, text: "მეფე დავითმა შვა სოლომონი ურიას ცოლისაგან." },
  { verse: 7, text: "სოლომონმა შვა რობოამი; რობოამმა შვა აბია; აბიამ შვა ასა." },
  { verse: 8, text: "ასამ შვა იოსაფატი; იოსაფატმა შვა იორამი; იორამმა შვა ოზია." },
  { verse: 9, text: "ოზიამ შვა იოთამი; იოთამმა შვა აქაზი; აქაზმა შვა ეზეკია." },
  { verse: 10, text: "ეზეკიამ შვა მანასე; მანასემ შვა ამონი;. ამონმა შვა იოსია." },
  { verse: 11, text: "იოსიამ შვა იექონია და მისი ძმები ბაბილონის ტყვეობის ჟამს." },
  { verse: 12, text: "ხოლო ბაბილონის ტყვეობის შემდეგ იექონიამ შვა სალათიელი; სალათიელმა შვა ზორობაბელი." },
  { verse: 13, text: "ზორობაბელმა შვა აბიუდი; აბიუდმა შვა ელიაკიმი; ელიაკიმმა შვა აზორი." },
  { verse: 14, text: "აზორმა შვა სადოკი; სადოკმა შვა აქიმი; აქიმმა შვა ელიუდი." },
  { verse: 15, text: "ელიუდმა შვა ელეაზარი; ელეაზარმა შვა მატთანი; მატთანმა შვა იაკობი." },
  { verse: 16, text: "ხოლო იაკობმა შვა იოსები, ქმარი მარიამისა, ვისგანაც იშვა იესო, რომელსაც ჰქვია ქრისტე." },
  { verse: 17, text: "ასე რომ, მთელი შთამომავლობა აბრაამიდან დავითამდე თოთხმეტი თაობა, და დავითიდან ბაბილონის ტყვეობამდე თოთხმეტი თაობა და ბაბილონის ტყვეობიდან ვიდრე ქრისტემდე თოთხმეტი თაობა." },
  { verse: 18, text: "ხოლო იესო ქრისტეს შობა ასე მოხდა: დედამისი მარიამი დანიშნული იყო იოსებზე, და მათ შეერთებამდე აღმოჩნდა, რომ მუცლად ეღო სული წმიდისაგან." },
  { verse: 19, text: "ხოლო იოსები, მისი ქმარი, მართალი იყო, არ უნდოდა მისი შერცხვენა და განიზრახა ფარულად გაეშვა იგი." },
  { verse: 20, text: "ეს რომ დააპირა, აჰა, ანგელოზი უფლისა ეჩვენა სიზმრად და უთხრა: იოსებ, დავითის ძეო, ნუ შიშობ მოიყვანო მარიამი, ცოლი შენი: რადგან ვინც მასში ჩასახულია, სული წმიდისაგან არის." },
  { verse: 21, text: "და შობს ძეს და უწოდებ სახელად იესოს, რადგან ის იხსნის თავის ხალხს მათი ცოდვებისაგან." },
  { verse: 22, text: "ხოლო ყოველივე ეს მოხდა, რათა აღსრულდეს სიტყვა უფლისა, წინასწარმეტყველის მიერ თქმული:" },
  { verse: 23, text: "აჰა, ქალწული მუცლად იღებს, და შობს ძეს, და უწოდებენ მას სახელად ემმანუელს, რაც თარგმანით ნიშნავს: ჩვენთან არს ღმერთი." },
  { verse: 24, text: "გამოიღვიძა იოსებმა ძილისგან და ისე მოიქცა, როგორც უბრძანა ანგელოზმა უფლისა, და მოიყვანა თავისი ცოლი." },
  { verse: 25, text: "და არ უცვნია იგი, ვიდრე არა შვა ძე თვისი პირმშო, და უწოდა სახელი მისი იესო." },
],

2: [
  { verse: 1, text: "ხოლო როცა იუდეის ბეთლემში დაიბადა იესო ქრისტე, ჰეროდეს მეფობის ჟამს, აჰა, აღმოსავლეთით მოვიდნენ მოგვნი იერუსალიმს," },
  { verse: 2, text: "და თქვეს: სად არის იუდეველთა ახალშობილი მეფე? ვინაიდან ვიხილეთ მისი ვარსკვლავი აღმოსავლეთში და მოვედით, რათა თაყვანი ვცეთ მას." },
  { verse: 3, text: "ეს რომ გაიგო, შეძრწუნდა მეფე ჰეროდე და მთელი იერუსალიმი მასთან ერთად." },
  { verse: 4, text: "შეკრიბა ყველა მღვდელმთავარი და ერის მწიგნობარნი და გამოიკითხა მათგან, სად უნდა შობილიყო იესო ქრისტე." },
  { verse: 5, text: "ხოლო მათ უთხრეს: იუდეის ბეთლემში; ვინაიდან ასე დაიწერა წინასწარმეტყველის მიერ:" },
  { verse: 6, text: "და შენ, ბეთლემ, იუდას ქვეყანაო, არაფრითა ხარ უმცირესი იუდას მთავართა შორის, ვინაიდან შენგან გამოვა მთავარი, რომელიც დამწყემსავს ჩემს ერს ისრაელს." },
  { verse: 7, text: "მაშინ ჰეროდემ ფარულად მოუწოდა მოგვებს და გამოიკითხა მათგან ვარსკვლავის გამოჩენის ჟამი." },
  { verse: 8, text: "წარგზავნა ისინი ბეთლემს და უთხრა: წადით და გამოწვლილვით გამოიძიეთ ყრმის ამბავი, და როდესაც ჰპოვებთ, მაცნობეთ მე, რათა თავადაც მივიდე და თაყვანი ვცე მას." },
  { verse: 9, text: "ხოლო მათ უსმინეს მეფეს და წავიდნენ. და, აჰა, ვარსკვლავი, რომელიც იხილეს აღმოსავლეთით, წინ მიუძღოდა მათ, სანამ არ მივიდა და თავს დაადგა იმ ადგილს, სადაც ყრმა იყო." },
  { verse: 10, text: "ხოლო მათ, ვარსკვლავის დანახვისას, ძალიან დიდი სიხარულით გაიხარეს." },
  { verse: 11, text: "როდესაც შევიდნენ სახლში, იხილეს ყრმა მარიამთან, თავის დედასთან ერთად, დაემხნენ და თაყვანი სცეს მას; გახსნეს თავიანთი საუნჯე და მიართვეს მას ძღვენი: ოქრო, გუნდრუკი და მური." },
  { verse: 12, text: "და ეუწყათ სიზმრად, არ დაბრუნებულიყვნენ ჰეროდესთან და სხვა გზით მიიქცნენ თავიანთ ქვეყნად." },
  { verse: 13, text: "ხოლო მათი წასვლის შემდეგ, აჰა, ანგელოზი უფლისა ეჩვენა სიზმრად იოსებს და უთხრა: ადექი, წაიყვანე ყრმა და დედა მისი და გაიქეცი ეგვიპტეს; და იყავი იქ, სანამ არ გეტყვი შენ; ვინაიდან ჰეროდეს სურს მოძებნოს ყრმა და მოაკვდინოს იგი." },
  { verse: 14, text: "ისიც ადგა, წაიყვანა ყრმა და დედა მისი ღამით, და წავიდა ეგვიპტეს." },
  { verse: 15, text: "და იყო იქ ჰეროდეს აღსასრულამდე; რათა აღსრულებულიყო სიტყვა უფლისა, თქმული წინასწარმეტყველის მიერ: ეგვიპტით მოვუხმე ჩემს ძეს." },
  { verse: 16, text: "მაშინ, რა იხილა ჰეროდემ, რომ მოტყუებულ იქნა მოგვების მიერ, ძალზე განრისხდა, წარგზავნა ხალხი და ამოაწყვეტინა ყოველი ყრმა ბეთლემსა და მთელს მის შემოგარენში, ორ-ორი წლისა და უმრწემესნი, თანახმად ასაკისა, რომელიც გამოიკითხა მოგვებისაგან." },
  { verse: 17, text: "მაშინ აღსრულდა თქმული იერემია წინასწარმეტყველის მიერ, რომელიც ამბობს:" },
  { verse: 18, text: "ხმა გაისმა რამაში გოდებისა და დიდი გლოვისა: რაქელი დასტირის თავის შვილებს და არა სურს ნუგეში, ვინაიდან აღარ არიან." },
  { verse: 19, text: "ხოლო როდესაც აღესრულა ჰეროდე, აჰა, ანგელოზი უფლისა გამოეცხადა სიზმრად იოსებს ეგვიპტეში," },
  { verse: 20, text: "და უთხრა: ადექი და წაიყვანე ყრმა და დედამისი და წადი ისრაელის ქვეყნად, ვინაიდან მოკვდნენ ისინი, ვინც ეძიებდნენ ყრმის სულს." },
  { verse: 21, text: "ისიც ადგა და წამოიყვანა ყრმა და დედამისი და მოვიდა ისრაელის ქვეყნად." },
  { verse: 22, text: "მაგრამ, როდესაც გაიგო, არქელაოსი მეფობსო იუდეაში მამამისის ჰეროდეს ნაცვლად, შეეშინდა იქ მისვლა და სიზმარეული ჩვენებით გაფრთხილებულმა მიაშურა გალილეის მხარეს." },
  { verse: 23, text: "მივიდა და დაესახლა ქალაქში, რომელსაც ჰქვია ნაზარეთი, რათა აღსრულებულიყო თქმული წინასწარმეტყველთა მიერ: ნაზარეველად იწოდებისო." }
],
3: [
  { verse: 1, text: "ხოლო იმ დღეებში მოვიდა იოანე ნათლისმცემელი იუდეის უდაბნოში საქადაგებლად." },
  { verse: 2, text: "და ამბობდა: მოინანიეთ, ვინაიდან მოახლოვდა ცათა სასუფეველი." },
  { verse: 3, text: "რადგან ეს არის, ვისთვისაც ითქვა ესაია წინასწარმეტყველის მიერ: ხმა უდაბნოში მღაღადებლისა: გაამზადეთ გზა უფლისა, გაასწორეთ მისი ბილიკნი." },
  { verse: 4, text: "ხოლო თვით იოანეს ემოსა აქლემის ბეწვი და წელს ერტყა ტყავის სარტყელი: და საზრდელი მისი იყო კალია და ველური თაფლი." },
  { verse: 5, text: "მაშინ გამოდიოდა მისკენ იერუსალიმი, მთელი იუდეა და მთელი შემოგარენი იორდანესი." },
  { verse: 6, text: "ინათლებოდნენ მისგან იორდანეში და აღიარებდნენ თავიანთ ცოდვებს." },
  { verse: 7, text: "როდესაც დაინახა მისკენ მოსანათლად მომავალი ფარისეველნი და სადუკეველნი, უთხრა მათ: იქედნეს ნაშიერნო, ვინ გასწავლათ გაექეცითო მომავალ რისხვას?" },
  { verse: 8, text: "მაშ, გამოიღეთ ნაყოფი, ღირსი სინანულისა." },
  { verse: 9, text: "ნუ გგონიათ, რომ შეგიძლიათ უთხრათ თქვენს თავს: მამად გვივისო აბრაამი; რადგანაც გეუბნებით თქვენ: ღმერთს ხელეწიფება თვით ამ ქვათაგანაც აღუდგინოს ძენი აბრაამს." },
  { verse: 10, text: "ვინაიდან აწ უკვე ცული ხეების ფესვთან დევს. ყოველი ხე, რომელიც არ გამოიღებს კეთილ ნაყოფს, მოიჭრება და ცეცხლს მიეცემა." },
  { verse: 11, text: "მე წყლით გნათლავთ, რომ მოინანიოთ, ხოლო ჩემს შემდეგ მომავალი ჩემზე უძლიერესია, ვისი ხამლის ტარებისაც არა ვარ ღირსი; და ის მოგნათლავთ სული წმიდითა და ცეცხლით." },
  { verse: 12, text: "მას ხელთ უპყრია თვისი არნადი და გაწმენდს თავის კალოს, და შეინახავს ხორბალს ბეღელში, ხოლო ბზეს მისცემს უშრეტ ცეცხლს." },
  { verse: 13, text: "მაშინ მოვიდა იესო გალილეით იორდანეს პირას, იოანესთან, რათა მონათლულიყო მისგან." },
  { verse: 14, text: "იოანე კი არ უშვებდა და ეუბნებოდა: მე მმართებს შენგან მონათვლა და შენ მოდინარ ჩემთან?" },
  { verse: 15, text: "ხოლო იესომ მიუგო და უთხრა: დე, ასე იყოს ახლა, რადგან ჩვენ გვმართებს აღვასრულოთ მთელი სიმართლე. მაშინღა მიუშვა იგი." },
  { verse: 16, text: "და როცა მოინათლა იესო, მაშინვე ამოვიდა წყლიდან, და, აჰა, გაეხსნენ მას ცანი და იხალა სული ღმრთისა, დაბლა რომ ეშვებოდა მტრედივით და გადმოდიოდა მასზე." },
  { verse: 17, text: "და გაისმა ხმა ზეცით, რომელმაც თქვა: ეს არის ძე ჩემი საყვარელი, რომელიც შევიტკბე მე." }
],
4: [
  { verse: 1, text: "მაშინ იესო აყვანილ იქნა უდაბნოში სულის მიერ, ეშმაკისაგან საცდუნებლად." },
  { verse: 2, text: "და იმარხულა ორმოცი დღე და ორმოცი ღამე და ბოლოს მოშივდა." },
  { verse: 3, text: "მაშინ მიადგა მაცდური და უთხრა: თუ ძე ხარ ღმრთისა, თქვი, რომ ეს ქვები პურებად იქცნენ." },
  { verse: 4, text: "ხოლო იესომ მიუგო და უთხრა: დაწერილია: არა მხოლოდ პურით იცოცხლებს კაცი, არამედ ყოველი სიტყვით, რომელიც გამოდის ღმერთის პირიდან." },
  { verse: 5, text: "მაშინ ეშმაკმა წაიყვანა იგი წმიდა ქალაქში, დააყენა ტაძრის ქიმზე" },
  { verse: 6, text: "და უთხრა: თუ ძე ხარ ღვთისა, გადავარდი აქედან, რადგანაც დაწერილია: თავის ანგელოზებს უბრძანებს შენს გამო, და აგიტაცებენ ხელში, რათა არსად წამოჰკრა ქვას ფეხი შენი." },
  { verse: 7, text: "იესომ მიუგო: ესეც დაწერილია: არ გამოსცადო უფალი ღმერთი შენი." },
  { verse: 8, text: "კვლავ აიყვანა იგი ეშმაკმა ძალიან მაღალ მთაზე, და უჩვენა მას ქვეყნის ყველა სამეფო და დიდება მათი." },
  { verse: 9, text: "და უთხრა: ყოველივე ამას მოგცემ, თუ დაეცემი და თაყვანს მცემ მე." },
  { verse: 10, text: "მაშინ მიუგო მას იესომ: გამშორდი, სატანა, რადგანაც დაწერილია: უფალს ღმერთს შენსას თაყვანი ეცი და მხოლოდ მას ემსახურე." },
  { verse: 11, text: "მაშინ მიატოვა იგი ეშმაკმა, და აჰა, ანგელოზები მოვიდნენ და ემსახურებოდნენ მას." },
  { verse: 12, text: "ხოლო როდესაც გაიგო იესომ, იოანე შეუპყრიათო, გალილეას გაემართა." },
  { verse: 13, text: "მიატოვა ნაზარეთი, მივიდა და დაემკვიდრა ზღვისპირა კაპერნაუმს, ზაბულონის და ნეფთალემის მხარეს," },
  { verse: 14, text: "რათა აღსრულდეს თქმული ესაია წინასწარმეტყველის მიერ, რომელიც ამბობს:" },
  { verse: 15, text: "ქვეყანა ზაბულონისა და ქვეყანა ნეფთალემისა, გზა ზღვისა იორდანეს გაღმა, გალილეა წარმართთა;" },
  { verse: 16, text: "ბნელში მსხდომარე ხალხმა იხილა ნათელი დიდი, და ქვეყნად და სიკვდილის ჩრდილში მსხდომთ გამოუბრწყინდა ნათელი." },
  { verse: 17, text: "შემდგომ ამისა, დაიწყო იესომ ქადაგება და ამბობდა: მოინანიეთ, ვინაიდან მოახლოვდა ცათა სასუფეველი." },
  { verse: 18, text: "და როცა გალილეის ზღვის პირას მიდიოდა იგი, დაინახა ორი ძმა: სიმონი, პეტრედ წოდებული, და მისი ძმა ანდრია, ბადეს რომ ისროდნენ ზღვაში, ვინაიდან მებადურები იყვნენ." },
  { verse: 19, text: "და უთხრა მათ: გამომყევით და კაცთა მებადურებად გაქცევთ." },
  { verse: 20, text: "მათაც მყისვე მიატოვეს ბადე და გაჰყვნენ მას." },
  { verse: 21, text: "იქიდან წამოსულმა დაინახა ორი სხვა ძმა: იაკობი ზებედესი და მისი ძმა იოანე, რომლებიც ზებედესთან, თავიანთ მამასთან ერთად ბადეს კემსავდნენ ნავში, და უხმო მათ." },
  { verse: 22, text: "მათაც მყისვე მიატოვეს თავიანთი ნავიც და მამაც, და გაჰყვნენ მას." },
  { verse: 23, text: "მიმოდიოდა იესო მთელს გალილეაში, ასწავლიდა მათ სინაგოგებში, ქადაგებდა სახარებას სასუფევლისას და კურნავდა ყოველგვარ სენსა და ყოველგვარ უძლურებას ხალხში." },
  { verse: 24, text: "და მოედო მისი ამბავი მთელს სირიას: მოჰყავდათ მასთან უძლურნი, სხვადასხვა სენითა და ჭირით სნეულნი, ეშმაკეულნი, მთვარეულნი და დავრდომილნი, და კურნავდა მათ." },
  { verse: 25, text: "და მისდევდა მას დიდძალი ხალხი გალილეიდან და ათქალაქიდან, იერუსალიმიდან, იუდეიდან და იორდანეს გაღმიდან." }
],
5: [
  { verse: 1, text: "ხალხი რომ იხილა, მთაზე ავიდა, და როცა დაჯდა, მიუახლოვდნენ მისი მოწაფენი." },
  { verse: 2, text: "განახვნა ბაგენი, ასწავლიდა მათ და ამბობდა:" },
  { verse: 3, text: "ნეტარ არიან გლახაკნი სულითა, ვინაიდან მათია ცათა სასუფეველი." },
  { verse: 4, text: "ნეტარ არიან მგლოვიარენი, ვინაიდან ისინი ნუგეშცემულნი იქნებიან." },
  { verse: 5, text: "ნეტარ არიან თვინიერნი, ვინაიდან ისინი დაიმკვიდრებენ მიწას." },
  { verse: 6, text: "ნეტარ არიან სიმართლისთვის მშიერ-მწყურვალნი, ვინაიდან ისინი გაძღებიან." },
  { verse: 7, text: "ნეტარ არიან მოწყალენი, ვინაიდან ისინი შეწყალებულნი იქნებიან." },
  { verse: 8, text: "ნეტარ არიან წმიდანი გულითა, ვინაიდან ისინი ღმერთს იხილავენ." },
  { verse: 9, text: "ნეტარ არიან მშვიდობისმყოფელნი, ვინაიდან ისინი ღმრთის ძეებად იწოდებიან." },
  { verse: 10, text: "ნეტარ არიან სიმართლისათვის დევნილნი, ვინაიდან მათია ცათა სასუფეველი." },
  { verse: 11, text: "ნეტარნი ხართ თქვენ, როცა დაგიწყებენ გმობას, დევნას და ცრუმეტყველნი დაგწამებენ ყოველგვარ ბოროტს ჩემი გულისთვის." },
  { verse: 12, text: "გიხაროდეთ და ილხენდეთ, ვინაიდან დიდია თქვენი საზღაური ცაში, რადგან ასევე სდევნიდნენ წინასწარმეტყველთაც, რომელნიც თქვენზე უწინარეს იყვნენ." },
  { verse: 13, text: "თქვენა ხართ მარილი მიწისა: და თუ მარილი გამტკნარდა, რაღათი დაამარილებ? აღარად ვარგა, თუ არა გადასაყრელად და კაცთა მიერ ფეხით სათელად." },
  { verse: 14, text: "თქვენა ხართ ნათელი ქვეყნისა. ვერ დაიმალება ქალაქი, მთის მწვერვალზე გაშენებული." },
  { verse: 15, text: "როდესაც ანთებენ სანთელს, საწყაოს ქვეშ კი არ დგამენ, არამედ სასანთლეზე, და უნათებს ყველა შინ მყოფს." },
  { verse: 16, text: "დაე, ასევე ნათობდეს თქვენი ნათელი კაცთა წინაშე, რათა ისინი ხედავდნენ თქვენს კეთილ საქმეებს და ადიდებდნენ მამას თქვენსას ზეციერს." },
  { verse: 17, text: "ნუ გგონიათ, თითქოს მოვედი რჯულის, გინდა წინასწარმეტყველთა გასაუქმებლად. გასაუქმებლაღ კი არ მოვედი, არამედ აღსასრულებლად." },
  { verse: 18, text: "რადგანაც ჭეშმარიტად გეუბნებით თქვენ: სანამ არ გადავა ცა და მიწა, ერთი იოტიც ან ერთი წერტილიც არ გადავა რჯულისაგან, ვიდრე ყოველივე არ აღსრულდება." },
  { verse: 19, text: "ამრიგად, ვინც დაარღვევს თუნდაც ერთს ამ უმცირეს მცნებათაგანს და ასე ასწავლის კაცთაც, უმცირესად იწოდება ცათა სასუფეველში; ხოლო ვინც აღასრულებს და ასწავლის, უდიდესად იწოდება ცათა სასუფეველში." },
  { verse: 20, text: "რადგანაც გეუბნებით თქვენ: თუკი თქვენი სიმართლე არ აღემატა მწიგნობართა და ფარისეველთა სიმართლეს, ვერ შეხვალთ ცათა სასუფეველში." },
  { verse: 21, text: "თქვენ გსმენიათ წინაპართა მიმართ თქმული: არა კაც ჰკლა; ხოლო ვინც მოჰკლავს სამართალში უნდა მიეცეს." },
  { verse: 22, text: "მე კი გეუბნებით თქვენ: ვინც უმიზეზოდ ურისხდება თავის ძმას, სამართალში უნდა მიეცეს; ხოლო ვინც ეტყვის თავის ძმას: რაკა, სინედრიონს უნდა წარუდგეს; და ვინც ეტყვის თავის ძმას: შლეგო, ცეცხლის გეენაში ჩავარდეს." },
  { verse: 23, text: "ხოლო თუ მიგაქვს შესაწირავი საკუთრხეველთან და იქ გაიხსენებ, რომ შენი ძმა ძვირს იზრახავს შენთვის," },
  { verse: 24, text: "დაუტევე შენი შესაწირავი საკურთხევლის წინ, წადი, ჯერ შემოირიგე შენი ძმა, და მხოლოდ შემდეგ მიდი და შესწირე შესაწირავი." },
  { verse: 25, text: "დაუზავდი საჩქაროდ შენს მომჩივანს, სანამ ერთად ადგიხართ გზას, რათა მომჩივანმა არ მიგცეს მსაჯულს, ხოლო მსაჯულმა - მსახურს, და ჩავარდე საპყრობილეში." },
  { verse: 26, text: "ჭეშმარიტად გეუბნები შენ: ვერ გამოხვალ იქიდან, სანამ არ გაიღებ უკანასკნელ კოდრანტს." },
  { verse: 27, text: "თქვენ გსმენიათ წინაპართა მიმართ თქმული: არა იმრუშო." },
  { verse: 28, text: "ხოლო მე გეუბნებით თქვენ: ყველამ, ვინც ნდომით შეხედა ქალს, უკვე იმრუშა მასთან საკუთარ გულში." },
  { verse: 29, text: "თუკი გაცთუნებს შენი მარჯვენა თვალი, ამოითხარე და გადააგდე, ვინაიდან გიჯობს დაჰკარგო ერთი შენი ასოთაგანი, ვიდრე მთელი შენი სხეული ჩავარდეს გეენას." },
  { verse: 30, text: "ხოლო თუ გაცთუნებს შენი მარჯვენა ხელი, მოიკვეთე და გადააგდე, ვინაიდან გიჯობს დაჰკარგო ერთი შენი ასოთაგანი, ვიდრე მთელი შენი სხეული ჩავარდეს გეენას." },
  { verse: 31, text: "ესეცა თქმულა: ვინც გაუშვებს თავის ცოლს, უნდა მისცეს გაყრის წერილი." },
  { verse: 32, text: "ხოლო მე გეუბნებით თქვენ: ვინც გაუშვებს თავის ცოლს სიძვის მიზეზის გარეშე, ამრუშებს მას, და ვინც განაშვებს შეირთავს, მრუშობს." },
  { verse: 33, text: "კვლავაც გსმენიათ წინაპართა მიმართ თქმული: ნუ დაიფიცავ ტყუილად, არამედ შეუსრულე უფალს შენი ფიცი." },
  { verse: 34, text: "ხოლო მე გეუბნებით თქვენ: სულაც ნუ დაიფიცავ: ნურც ცას, ვინაიდან ღმერთის ტახტია;" },
  { verse: 35, text: "ნურც მიწას, ვინაიდან მისი ტერფების კვარცხლბეკია; ნურც იერუსალიმს, ვინაიდან დიდი მეუფის ქალაქია." },
  { verse: 36, text: "ნურც შენს თავს დაიფიცავ, ვინაიდან არ შეგიძლია არც ერთი ღერი თმის გათეთრება ან გაშავება." },
  { verse: 37, text: "არამედ თქვენი სიტყვა იყოს: ჰო, ჰო; და - არა, არა; ვინაიდან რაც ამაზე მეტია, ბოროტისმიერია." },
  { verse: 38, text: "თქვენ გსმენიათ, რომ თქმულა: თვალი თვალისა წილ და კბილი კბილისა წილ." },
  { verse: 39, text: "ხოლო მე გეუბნებით თქვენ: ნუ აღუდგებით წინ ბოროტს: არამედ ვინც შემოგკრას მარჯვენა ყვრიმალში, მეორეც მიუშვირე მას." },
  { verse: 40, text: "და თუ ვინმეს სურს გიჩივლოს და წაგართვას შენი პერანგი, მიეცი მას მოსასხამიც." },
  { verse: 41, text: "ანდა თუ ვინმე გაიძულებს ერთი მილის მანძილზე გამომყევიო, ორზე გაჰყევი მას." },
  { verse: 42, text: "მთხოვნელს მიეცი და სესხების მსურველს ზურგს ნუ შეაქცევ." },
  { verse: 43, text: "თქვენ გსმენიათ, რომ თქმულა: გიყვარდეს მოყვასი შენი და გძულდეს მტერი შენი." },
  { verse: 44, text: "ხოლო მე გეუბნებით თქვენ: გიყვარდით თქვენი მტერნი; დალოცეთ თქვენი მაწყევარნი; კეთილი უყავით თქვენს მოძულეთ და ილოცეთ თქვენსავ მდევნელთა და შეურაცხმყოფელთათვის." },
  { verse: 45, text: "რათა იყოთ შვილნი თქვენი ზეციერი მამისა, ვისაც თავისი მზე ამოჰყავს კეთილთა და ბოროტთათვის და წვიმას უგზავნის მართალთაც და უსამართლოთაც." },
  { verse: 46, text: "რადგანაც თუ გეყვარებათ თქვენი მოყვასნი, რა იქნება თქვენი საზღაური? განა ასევე არ იქცევიან მებაჟენიც?" },
  { verse: 47, text: "ანდა თუ მოიკითხავთ მხოლოდ თქვენს მოძმეთ, უჩვეულოს რას სჩადიხართ? განა ასევე არ იქცევიან წარმართნიც?" },
  { verse: 48, text: "მაშ, იყავით სრულქმნილნი, როგორც სრულქმნილია თქვენი ზეციერი მამა." }
],
6: [
  { verse: 1, text: "ეკრძალეთ სიმართლის ქმნას კაცთა წინაშე, მათ დასანახად; თორემ ვერ მიიღებთ საზღაურს თქვენი ზეციერი მამისგან." },
  { verse: 2, text: "და როცა გასცემ მოწყალებას, ნუ აყვირებ შენს წინაშე ბუკ-ნაღარას, როგორც იქცევიან თვალთმაქცნი სინაგოგებსა თუ ქუჩაბანდებში, რათა განადიდოს ისინი ხალხმა. ჭეშმარიტად გეუბნებით თქვენ: უკვე მიიღეს თავიანთი საზღაური." },
  { verse: 3, text: "ხოლო როცა შენ გასცემ მოწყალებას, დაე, ნუ ეცოდინება შენს მარცხენა ხელს, რას აკეთებს მარჯვენა," },
  { verse: 4, text: "რათა შენი მოწყალება დაფარული დარჩეს, და მამამ შენმა, რომელიც ხედავს დაფარულს, მოგაგოს შენ ცხადად." },
  { verse: 5, text: "ხოლო როდესაც ლოცულობთ, ნუ ემსგავსებით თვალთმაქცთ, რომელთაც უყვართ სინაგოგებსა თუ ქუჩის კუთხეში დგომა და ლოცვა, რათა თავი მოაჩვენონ ხალხს. ჭეშმარიტად გეუბნებით თქვენ: უკვე მიიღეს თავიანთი საზღაური." },
  { verse: 6, text: "შენ კი, როდესაც ლოცულობ, შედი შენს სენაკში, მოიხურე კარი და ილოცე შენი ფარული მამის მიმართ. და მამა შენი, რომელიც ხედავს დაფარულს, მოგაგებს შენ ცხადად." },
  { verse: 7, text: "ხოლო ლოცვისას ნუ იტყვით ზედმეტს, წარმართთა მსგავსად, რომელთაც ჰგონიათ, რომ სიტყვამრავლობის გამო შესმენილ იქნებიან." },
  { verse: 8, text: "ნუ ემსგავსებით მათ, ვინაიდან მამამ თქვენმა, ვიდრე სთხოვდეთ, მანამდეც იცის, რა გჭირდებათ." },
  { verse: 9, text: "ხოლო ლოცვით ასე ილოცეთ: მამაო ჩვენო, რომელი ხარ ცათა შინა, წმიდა იყოს სახელი შენი." },
  { verse: 10, text: "მოვიდეს სუფევა შენი, იყოს ნება შენი, როგორც ცაში, ისე ქვეყანაზედაც." },
  { verse: 11, text: "პური ჩვენი არსობისა მოგვეც ჩვენ დღეს." },
  { verse: 12, text: "და მოგვიტევე ჩვენი ვალები, როგორც ჩვენ მივუტევებთ ჩვენს მოვალეთა." },
  { verse: 13, text: "და ნუ შეგვიყვან ჩვენ განსაცდელში, არამედ გვიხსენ ბოროტისაგან, რადგან შენია სუფევა და ძალი და დიდება უკუნისამდე. ამინ." },
  { verse: 14, text: "თუ მიუტევებთ ადამიანებს მათს შეცოდებებს, თქვენც მოგიტევებთ მამა თქვენი ზეციერი." },
  { verse: 15, text: "ხოლო თუ არ მიუტევებთ ადამიანებს მათს შეცოდებებს, არც თქვენს შეცოდებებს მოგიტევებთ მამა თქვენი ზეციერი." },
  { verse: 16, text: "და როდესაც მარხულობთ, ნუ იქნებით მწუხარენი, თვალთმაქცთა მსგავსად, თავ-პირი რომ ჩამოსტირით, რათა მმარხველებად ეჩვენონ ხალხს. ჭეშმარიტად გეუბნებით თქვენ: უკვე მიიღეს თავიანთი საზღაური." },
  { verse: 17, text: "ხოლო შენ, როდესაც მარხულობ, თავს იცხე და დაიბანე პირი შენი." },
  { verse: 18, text: "რათა ხალხს კი არ ეჩვენო მმარხველად, არამედ დაფარულში მყოფ მამას შენსას; და მამა შენი, რომელიც ხედავს დაფარულს, მოგაგებს შენ ცხადად." },
  { verse: 19, text: "ნუ იუნჯებთ თქვენს საუნჯეს ამ ქვეყნად, სადაც ჟანგი და მღილი ღრღნის მას, და სადაც მპარავნი თხრიან და იპარავენ." },
  { verse: 20, text: "არამედ დაიუნჯეთ თქვენი საუნჯე ზეცად, სადაც ვერც ჟანგი და ვერც მღილი ვერა ღრღნის მას, და სადაც მპარავნი ვერ თხრიან და ვერ იპარავენ." },
  { verse: 21, text: "ვინაიდან სადაც არის საუნჯე თქვენი, იქვე იქნება გული თქვენი." },
  { verse: 22, text: "სხეულის სანთელი არის თვალი. თუ შენი თვალი წმიდაა, ნათელი იქნება მთელი შენი სხეულიც." },
  { verse: 23, text: "ხოლო თუ შენი თვალი უწმინდურია, ბნელი იქნება მთელი შენი სხეულიც. მაგრამ თუ შენში ნათელიც ბნელია, როგორიღა იქნება ბნელი?" },
  { verse: 24, text: "არავის ძალუძს ორი ბატონის მონობა: რადგან ან ერთს შეიყვარებს და მეორეს შეიძულებს, ან კიდევ ერთს შეითვისებს და მეორეს შეიზიზღებს. ვერ შესძლებთ ღმერთსაც ემონოთ და მამონასაც." },
  { verse: 25, text: "ამიტომაც გეუბნებით თქვენ: ნუ ზრუნავთ თქვენი სიცოცხლისათვის, რა ვჭამოთ ანდა რა ვსვათო; ნურც თქვენი სხეულისათვის, რით შევიმოსოთო. განა სიცოცხლე უფრო მეტი არ არის, ვიდრე საზრდელი და სხეული - უფრო მეტი, ვიდრე სამოსელი?" },
  { verse: 26, text: "შეხედეთ ცის ფრინველთ: არც თესავენ, არც მკიან, არც ბეღლებს ავსებენ, და მამა თქვენი ზეციერი არჩენს მათ. ნუთუ თქვენ არა სჯობიხართ ფრინველთ?" },
  { verse: 27, text: "ან რომელ თქვენგანს ხელეწიფება, ბევრიც ეცადოს, თუნდ ერთი ციდით მოიმატოს სიმაღლე?" },
  { verse: 28, text: "ან სამოსლისთვის რაღადა ზრუნავთ? შეხედეთ, როგორ იზრდებიან ველის შროშანნი: არც შრომობენ, არც ართავენ." },
  { verse: 29, text: "მაგრამ გეუბნებით თქვენ: თვით სოლომონი მთელი თავისი დიდებით არ იყო ისე შემოსილი, როგორც თვითეული მათგანი." },
  { verse: 30, text: "ხოლო თუ ველის ბალახს, რომელიც დღეს არის და ხვალ თონეს შეენთება, ასეთნაირად მოსავს ღმერთი, განა თქვენ უკეთ არ შეგმოსავთ, მცირედ მორწმუნენო?" },
  { verse: 31, text: "ნუ ზრუნავთ და იტყვით: რა ვჭამოთ, რა ვსვათ, ანდა რით შევიმოსოთო?" },
  { verse: 32, text: "ვინაიდან ყოველივე ამას ეძებენ წარმართნი, და ვინაიდან მამამ თქვენმა ზეციერმა იცის, რომ ყოველივე ეს გჭირდებათ." },
  { verse: 33, text: "მაშ, ეძებეთ უპირველესად უფლის სასუფეველი და სიმართლე მისი, და ყოველივე ეს მოგეცემათ თქვენ." },
  { verse: 34, text: "ნუ ზრუნავთ ხვალინდელი დღისათვის, რადგან ხვალე თვითონ იზრუნებს თავისას: ყოველ დღეს ეყოფა თავისი საზრუნავი." }
],
7: [
  { verse: 1, text: "ნუ განსჯით, რათა არ განისაჯოთ." },
  { verse: 2, text: "ვინაიდან როგორი განსჯითაც განსჯით, იმნაირითვე განისჯებით, და რომელი საწყაულითაც მიუწყავთ, იმითვე მოგეწყვით თქვენ." },
  { verse: 3, text: "ან რატომ ხედავ ბეწვს შენი ძმის თვალში, ხოლო შენსაში დირესაც ვერა გრძნობ?" },
  { verse: 4, text: "ანდა როგორ ეუბნები შენს ძმას: მოიცა, ამოგიღო ბეწვი თვალიდან, და თვითონ შენ კი დირე გაქვს თვალში." },
  { verse: 5, text: "თვალთმაქცო, ჯერ შენი თვალიდან ამოიღე დირე და მერეღა ნახავ, როგორ ამოიღო შენი ძმის თვალიდან ბეწვი." },
  { verse: 6, text: "ნუ მისცემთ სიწმინდეს ძაღლებს: ნურც თქვენს მარგალიტს დაუყრით ღორებს, რათა არ გათელონ იგი თავიანთი ფეხით და მოგიბრუნდნენ და დაგფლითონ თქვენ." },
  { verse: 7, text: "ითხოვეთ და მოგეცემათ; ეძებეთ და ჰპოვებთ; დააკაკუნეთ და გაგიღებენ." },
  { verse: 8, text: "რადგან ყველა მთხოვნელს მიეცემა, მძებნელი ჰპოვებს და ვინც აკაკუნებს, გაუღებენ." },
  { verse: 9, text: "თუ გეგულებათ თქვენს შორის კაცი, შვილმა რომ პური სთხოვოს და ქვა მისცეს მას?" },
  { verse: 10, text: "ან თევზი სთხოვოს და გველი მისცეს მას?" },
  { verse: 11, text: "ხოლო თუ თქვენ, უკეთურთ, შეგიძლიათ კეთილი საბოძვარი მისცეთ თქვენს შვილებს, რაოდენ უფრო მეტ სიკეთეს მისცემს მამა თქვენი ზეციერი მის მიმართ მთხოვნელთ?" },
  { verse: 12, text: "როგორც თქვენ გსურთ გექცეოდნენ კაცნი, თქვენც ასევე მოექეცით მათ, ვინაიდან ესაა რჯული და წინასწარმეტყველნი." },
  { verse: 13, text: "შედით ვიწრო ბჭით, ვინაიდან ვრცელია ბჭე და ფართოა გზა, რომელსაც მივყავართ წარსაწყმედლად, და მრავალნი დადიან მასზე." },
  { verse: 14, text: "ვინაიდან ვიწროა ბჭე და ძნელია გზა, რომელსაც მივყავართ სიცოცხლისაკენ, და მცირედნი ჰპოვებენ მას." },
  { verse: 15, text: "ეკრძალეთ ცრუ წინასწარმეტყველთ, რომელნიც მოვლენ თქვენთან ცხვრის სამოსით, ხოლო შიგნით არიან მტაცებელი მგლები." },
  { verse: 16, text: "თავიანთი ნაყოფით იცნობთ მათ; განა ეკალზე კრეფენ ყურძენს, ან ნარზე ლეღვს?" },
  { verse: 17, text: "ასე, ყველა ვარგის ხეს ვარგისი ნაყოფი გამოაქვს, და ყველა უვარგის ხეს უვარგისი ნაყოფი გამოაქვს." },
  { verse: 18, text: "არ შეუძლია ვარგის ხეს უვარგისი ნაყოფის გამოღება და უვარგის ხეს ვარგისი ნაყოფის გამოღება." },
  { verse: 19, text: "ყოველი ხე, რომელიც არ გამოიღებს ვარგის ნაყოფს, მოიჭრება და ცეცხლს მიეცემა." },
  { verse: 20, text: "ასე რომ, თავიანთი ნაყოფით იცნობთ მათ." },
  { verse: 21, text: "ვინც მეუბნება: უფალო, უფალო! ყველა როდი შევა ცათა სასუფეველში, არამედ ის, ვინც აღასრულებს ჩემი ზეციერი მამის ნებას." },
  { verse: 22, text: "მრავალნი მეტყვიან იმ დღეს: უფალო, უფალო! განა შენი სახელით არ ვწინასწარმეტყველებდით? განა შენი სახელით არ ვაძევებდით ეშმაკთ? და შენი სახელით არ ვახდენდით მრავალ სასწაულს?" },
  { verse: 23, text: "და მაშინ ვეტყვი მათ: არასოდეს მიცვნიხართ თქვენ: გამშორდით, ურჯულოების მოქმედნო." },
  { verse: 24, text: "ყველას, ვინც ისმენს ჩემს სიტყვებს და ასრულებს მათ, მე ვამსგავსებ გონიერ კაცს, რომელმაც კლდეზე დააშენა თავისი სახლი." },
  { verse: 25, text: "მოვიდა წვიმა, მოვარდნენ მდინარენი, დაქროლეს ქარებმა და ეკვეთნენ ამ სახლს, მაგრამ ვერ დასცეს, ვინაიდან კლდეზე იყო დაფუძნებული." },
  { verse: 26, text: "და ყველას, ვინც ისმენს ჩემს სიტყვებს, მაგრამ არ ასრულებს მათ, მე ვამსგავსებ უგუნურ კაცს, რომელმაც ქვიშაზე ააშენა თავისი სახლი." },
  { verse: 27, text: "მოვიდა წვიმა, მოვარდნენ მდინარენი, დაქროლეს ქარებმა და ეკვეთნენ ამ სახლს და დასცეს; და დიდი იყო დაცემა მისი." },
  { verse: 28, text: "და როცა დაასრულა იესომ სიტყვა, უკვირდა ხალხს მისი მოძღვრება." },
  { verse: 29, text: "ვინაიდან ის ასწავლიდა მათ როგორც ძალმოსილი, და არა როგორც მათი მწიგნობარნი." },
],
8: [
  { verse: 1, text: "როდესაც ჩამოვიდა მთიდან, თან გაჰყვა დიდძალი ხალხი." },
  { verse: 2, text: "და, აჰა, მიუახლოვდა ერთი კეთროვანი, თაყვანი სცა და უთხრა: უფალო, თუ გნებავს, შეგიძლია ჩემი განწმენდა." },
  { verse: 3, text: "გაიწოდა ხელი იესომ, შეახო მას და უთხრა: მნებავს, განიწმინდე. და მყისვე განიწმინდა იგი კეთრისგან." },
  { verse: 4, text: "და უთხრა მას იესომ: იცოდე, ნურავის ეტყვი; არამედ წადი, ეჩვენე მღვდელს, და შესწირე შესაწირავი, რომელიც დააწესა მოსემ მათთვის სამოწმებლად." },
  { verse: 5, text: "ხოლო როდესაც შევიდა იესო კაპერნაუმში, მიუახლოვდა ასისთავი და ვედრებით უთხრა:" },
  { verse: 6, text: "უფალო, დავრდომილი მსახური მიწევს სახლში და სასტიკად იტანჯება." },
  { verse: 7, text: "იესომ მიუგო: მოვალ და განვკურნავ მას." },
  { verse: 8, text: "ხოლო ასისთავმა პასუხად უთხრა: უფალო, არა ვარ იმის ღირსი, რომ ჩემს ჭერქვეშ შემოხვიდე; არამედ მხოლოდ სიტყვა ბრძანე და განიკურნება ჩემი მსახური." },
  { verse: 9, text: "ვინაიდან, თუმცა სხვისი ქვეშევრდომი ვარ, თავადაც ხელქვეითებად მყვანან მეომრები: და ვეტყვი ერთს: წადი, და მიდის; და მეორეს: მოდი, და მოდის; და ჩემს მსახურს: გააკეთე ეს, და აკეთებს." },
  { verse: 10, text: "ეს რომ გაიგონა, გაუკვირდა იესოს და უთხრა უკან მომავალთ: ჭეშმარიტად გეუბნებით თქვენ: ისრაელშიც არ შევხვედრივარ ამნაირ რწმენას." },
  { verse: 11, text: "ამასაც გეუბნებით თქვენ: მრავალნი მოვლენ აღმოსავლეთით და დასავლეთით, და აბრაამთან, ისააკსა და იაკობთან ერთად დასხდებიან ცათა სასუფეველში;" },
  { verse: 12, text: "ხოლო სასუფევლის ძენი გარესკნელის ბნელში გაიყრებიან; და იქნება იქ ტირილი და კბილთა ღრჭიალი." },
  { verse: 13, text: "და უთხრა იესომ ასისთავს: წადი და შენი რწმენისამებრ მოგეგოს შენ. და მაშინვე განიკურნა მისი მსახური." },
  { verse: 14, text: "ხოლო იესო შევიდა პეტრეს სახლში, და იხილა მისი სიდედრი, რომელიც ცხელებით შეპყრობილი იწვა." },
  { verse: 15, text: "და შეეხო თუ არა მის ხელს, გაუარა მას ცხელებამ; წამოდგა და ემსახურებოდა მათ." },
  { verse: 16, text: "ხოლო შებინდებისას მიჰგვარეს მას მრავალი ეშმაკეული, და განდევნა სულები სიტყვით, და განკურნა ყველა სნეული." },
  { verse: 17, text: "რათა აღსრულდეს თქმული ესაია წინასწარმეტყველის მიერ, რომელიც ამბობს: მან თავს იდო ჩვენი უძლურებანი და იტვირთა ჩვენი სნებანი." },
  { verse: 18, text: "ხოლო როდესაც იხილა იესომ გარსშემოჯარული ხალხი, გაღმა გასვლა უბრძანა მათ." },
  { verse: 19, text: "მაშინ მიუახლოვდა ერთი მწიგნობარი და უთხრა: მოძღვარო, თან გეახლები, სადაც უნდა წახვიდე." },
  { verse: 20, text: "იესომ მიუგო: მელიებს სოროები აქვთ, და ცის ფრინველებს - ბუდეები, ძეს კაცისას კი არა აქვს, სად მიიდრიკოს თავი." },
  { verse: 21, text: "ხოლო ერთმა მოწაფეთაგანმა უთხრა მას: უფალო, ნება მიბოძე, ჯერ მივიდე და დავმარხო მამაჩემი." },
  { verse: 22, text: "ხოლო იესომ მიუგო მას: შენ მე გამომყევ, და მკვდრებს მიანდე თავიანთი მკვდრების დამარხვა." },
  { verse: 23, text: "ჩაჯდა ნავში და გაჰყვნენ მისი მოწაფეები." },
  { verse: 24, text: "და, აჰა, საშინლად აღელდა ზღვა, ისე რომ, ტალღებით იფარებოდა ნავი: მას კი ეძინა." },
  { verse: 25, text: "მივიდნენ მისი მოწაფეები, გააღვიძეს და უთხრეს: უფალო, გვიხსენ, ვიღუპებით." },
  { verse: 26, text: "მიუგო მათ: რამ შეგაშინათ, მცირედ მორწმუნენო? მერე წამოდგა, შერისხა ქარები და ზღვა, და ჩამოვარდა სიმყუდროვე დიდი." },
  { verse: 27, text: "ბოლო განცვიფრებული ხალხი ამბობდა: ვინ არის იგი, ქარებიც და ზღვაც რომ მორჩილებენ?" },
  { verse: 28, text: "და როცა მიაღწია მეორე ნაპირს, გადარელთა მხარეს, შემოხვდა ორი ეშმაკეული, სამარხებიდან გამოსულნი და ძალზე მძვინვარენი, ისე რომ, ვერავინ ბედავდა ამ გზაზე გავლას." },
  { verse: 29, text: "და, აჰა, შეჰყვირეს და თქვეს: რა ხელი გაქვს ჩვენთან, იესო, ძეო ღმრთისაო? ვადაზე ადრე მოსულხარ აქ ჩვენს სატანჯველად." },
  { verse: 30, text: "ხოლო მათგან მოშორებით ბალახობდა ღორების დიდი კოლტი." },
  { verse: 31, text: "ეშმაკები შეევედრნენ მას და უთხრეს: თუ განგვდევნი, ნება გვიბოძე, ღორების კოლტს შევერიოთ." },
  { verse: 32, text: "და უბრძანა მათ, წადითო; ისინიც წავიდნენ და შეერივნენ ღორების კოლტს; და აჰა, მთელი კოლტი კბოდედან გადაეშვა ზღვაში და წყალში დაინთქა." },
  { verse: 33, text: "ხოლო მეღორეები გაიქცნენ, ქალაქში მივიდნენ და მოჰყვნენ ყველაფერს, რაც შეემთხვა ეშმაკეულებს." },
  { verse: 34, text: "და, აჰა, მთელი ქალაქი გამოვიდა იესოს შესახვედრად; და როდესაც იხილეს იგი, სთხოვეს, აქაურობას გაეცალეო." },
],
9: [
  { verse: 1, text: "მაშინ ჩაჯდა ნავში, უკანვე გამოცურა და მივიდა თავის ქალაქში." },
  { verse: 2, text: "და, აჰა, სარეცლით მიჰგვარეს მას დავრდომილი; იხილა იესომ მათი რწმენა და უთხრა დავრდომილს: გამხნევდი, შვილო, მოგეტევა შენი ცოდვები." },
  { verse: 3, text: "ზოგიერთი მწიგნობარი გულში ამბობდა: ღმერთს გმობსო იგი." },
  { verse: 4, text: "ხოლო იესო მიხვდა მათ ზრუნვას და თქვა: რატომ იზრახავთ ბოროტს თქვენს გულში?" },
  { verse: 5, text: "რა უფრო ადვილია: ამის თქმა - მოგეტევოს შენი ცოდვები: თუ ამისა - აღდეგ და წადი?" },
  { verse: 6, text: "ხოლო რათა იცოდეთ, რომ ძეს კაცისას ძალა შესწევს ამ ქვეყნად ცოდვების მიტევებისა, - ასე უთხრა დავრდომილს - აღდეგ, აიღე შენი სარეცელი და წადი შენს სახლში." },
  { verse: 7, text: "ისიც მაშინვე აღდგა და წავიდა თავის სახლში." },
  { verse: 8, text: "ამის მხილველი ხალხი განცვიფრდა და ადიდებდა ღმერთს, რომელმაც ასეთი ძალა მისცა ადამიანებს." },
  { verse: 9, text: "იქიდან წამოსულმა იესომ დაინახა საბაჟოში მჯდომარე კაცი, რომელსაც მათე ერქვა სახელად, და უთხრა მას გამომყევიო; ისიც ადგა და გაჰყვა." },
  { verse: 10, text: "და როცა ინახად იჯდა სახლში, აჰა, მოვიდა მრავალი მებაჟე და ცოდვილი, და ინახად დასხდნენ იესოსა და მის მოწაფეებთან." },
  { verse: 11, text: "ეს რომ დაინახეს, ფარისევლებმა მის მოწაფეებს უთხრეს: რატომ ჭამს და სვამს თქვენი მოძღვარი მებაჟეებსა და ცოდვილებთან ერთად?" },
  { verse: 12, text: "ხოლო იესომ გაიგონა ეს და უთხრა მათ: კარგად მყოფთ კი არ სჭირდებათ მკურნალი, არამედ ავადმყოფთ." },
  { verse: 13, text: "თქვენ კი წადით და ისწავლეთ, რას ნიშნავს ეს: წყალობა მნებავს და არა მსხვერპლი; ვინაიდან მართალთა სახმობლად კი არ მოვსულვარ, არამედ ცოდვილთა სინანულად." },
  { verse: 14, text: "მაშინ მივიდნენ მასთან იოანეს მოწაფეები და უთხრეს: რატომ ვმარხულობთ ჩვენ და ფარისევლები, შენი მოწაფეები კი არ მარხულობენ?" },
  { verse: 15, text: "ხოლო იესომ მიუგო მათ: განა შეიძლება წუხდნენ მექორწილენი, ვიდრე მათთანაა სიძე? მოვა დრო, როცა სიძე აღარ ეყოლებათ, და მაშინ იმარხულებენ." },
  { verse: 16, text: "არავინ ადებს ახალ საკერებელს დახეულ სამოსს, ვინაიდან ახალს ვერ დაიჭერს ძველი, და უფრო დაიხევა." },
  { verse: 17, text: "არც ახალ ღვინოს ასხამენ ძველ ტიკებში, თორემ დასკდება ტიკები, ღვინოც დაიქცევა და ტიკებიც უვარგისი გახდება; არამედ ახალ ღვინოს ასხამენ ახალ ტიკებში და ორივე ინახება." },
  { verse: 18, text: "ამ საუბარში გართულს მიუახლოვდა ერთი მთავარი, თაყვანი სცა და უთხრა: ჩემი გოგონა ეს-ესაა მოკვდა; წამოდი, ხელი დაადე და გაცოცხლდება." },
  { verse: 19, text: "წამოდგა იესო და მოწაფეებითურთ თან გაჰყვა მას." },
  { verse: 20, text: "და, აჰა, ქალი, რომელიც თორმეტ წელიწადს სისხლის დენით იტანჯებოდა, უკნიდან მიუახლოვდა და შეეხო მისი სამოსის კალთას." },
  { verse: 21, text: "რადგან გულში ამბობდა: თუ შევეხები მის სამოსს, მეშველებაო." },
  { verse: 22, text: "ხოლო იესო მიუბრუნდა, დაინახა იგი და უთხრა: გამხნევდი, შვილო, შენმა რწმენამ გადაგარჩინა. და განიკურნა ქალი იმავე წამს." },
  { verse: 23, text: "შევიდა იესო მთავრის სახლში და იხილა იქ მოზარენი და მოყაყანე ბრბო;" },
  { verse: 24, text: "და უთხრა მათ: გადით აქედან, რადგან გოგონა კი არ მომკვდარა, არამედ სძინავს; ხოლო ისინი დასცინოდნენ მას." },
  { verse: 25, text: "და როდესაც გაიყვანეს ხალხი, მივიდა იესო, აიღო გოგონას ხელი, და ისიც აღდგა." },
  { verse: 26, text: "და მოედო მისი ამბავი მთელ იმ მხარეს." },
  { verse: 27, text: "იქიდან წამოსულს ორი უსინათლო გამოედევნა ყვირილით: შეგვიწყალე, იესო, დავითის ძეო!" },
  { verse: 28, text: "და როდესაც მივიდა სახლში, მიეახლნენ უსინათლონი; და უთხრა მათ იესომ: გწამთ თუ არა, რომ შემიძლია ამისი ქმნა? ხოლო მათ თქვეს: დიახ, უფალო." },
  { verse: 29, text: "მაშინ თვალებზე შეეხო ბრმებს და უთხრა მათ: თქვენი რწმენისამებრ მოგეგოთ თქვენ!" },
  { verse: 30, text: "და აეხილათ თვალები, ხოლო იესომ მკაცრად გააფრთხილა და უთხრა მათ: იცოდეთ, არავინ გაიგოს." },
  { verse: 31, text: "ისინი კი გამოვიდნენ და მთელ იმ მხარეს მოსდეს მისი ამბავი." },
  { verse: 32, text: "ხოლო მათი გამოსვლისთანავე მიჰგვარეს მას ერთი კაცი, მუნჯი და ეშმაკეული." },
  { verse: 33, text: "და როცა ეშმაკი განდევნილ იქნა, მუნჯმა ენა ამოიდგა; უკვირდა ხალხს და ამბობდა: არ მოსწრებია ისრაელს ამგვარი რამე." },
  { verse: 34, text: "ხოლო ფარისეველნი ამბობდნენ: ეშმაკთა მთავრის შეწევნით აძევებსო ეშმაკთ." },
  { verse: 35, text: "და მოივლიდა იესო ყველა ქალაქსა და დაბას, ასწავლიდა მათ სინაგოგებში და ქადაგებდა სახარებას სასუფევლისას, და კურნავდა ყოველგვარ სენსა და ყოველგვარ უძლურებას ხალხში." },
  { verse: 36, text: "და როდესაც იხილა ამდენი ხალხი, შეებრალა ისინი, ვინაიდან დაღლილ-დაქანცულნი და დაფანტულნი იყვნენ, როგორც უმწყემსო ცხვრები." },
  { verse: 37, text: "მაშინ თავის მოწაფეებს უთხრა: სამკალი ბევრია, მაგრამ ცოტანი არიან მომკალნი." },
  { verse: 38, text: "მაშ, ევედრეთ სამკალის უფალს, რათა მომკალნი მოავლინოს თავის სამკალში." },
],
10: [
  { verse: 1, text: "მოუხმო თავის თორმეტ მოწაფეს, და მისცა მათ ხელმწიფება უწმინდურ სულთა განდევნისა და ყოველგვარი სენისა თუ ყოველგვარი უძლურების განკურნებისა." },
  { verse: 2, text: "ხოლო ამ თორმეტი მოციქულის სახელებია: პირველად სიმონი, პეტრედ წოდებული, და მისი ძმა ანდრია; იაკობი ზებედესი და მისი ძმა იოანე;" },
  { verse: 3, text: "ფილიპე და ბართლომე; თომა და მათე მებაჟე; იაკობი ალფესისა და ლებეოსი, თადეოსად სახელდებული;" },
  { verse: 4, text: "სიმონ კანანელი და იუდა ისკარიოტელი, რომელმაც გასცა იგი." },
  { verse: 5, text: "აი, ეს თორმეტი წარგზავნა იესომ, უბრძანა და უთხრა მათ: წარმართთა გზით ნუ ივლით, და ნუ შეხვალთ სამარიელთა ქალაქში." },
  { verse: 6, text: "არამედ მიაკითხეთ უპირატესად ისრაელის სახლის დაკარგულ ცხვრებს." },
  { verse: 7, text: "მიაკითხეთ და უქადაგეთ, რომ მოახლოვდა ცათა სასუფეველი." },
  { verse: 8, text: "განკურნეთ სნეულნი, განწმინდეთ კეთროვანნი, აღადგინეთ მკვდარნი, განდევნეთ ეშმაკნი; უსასყიდლოდ მიგიღიათ და უსასყიდლოდვე გაეცით." },
  { verse: 9, text: "ნუ წაიტანებთ სარტყლით ნურც ოქროს, ნურც ვერცხლს, ნურც რვალს;" },
  { verse: 10, text: "ნურც აბგას გზაში, ნურც ორ ხელ სამოსს, ნურც ფეხსაცმელს, ნურც არგანს, ვინაიდან ღირსია მაშვრალი თავისი საგზლისა." },
  { verse: 11, text: "რომელ ქალაქში ან დაბაშიც უნდა შეხვიდეთ, გამოიკითხეთ, ვინ არის იქ ღირსეული, და მისას დადექით, ვიდრე გამოსვლამდე." },
  { verse: 12, text: "ხოლო სახლში შესვლისას მიესალმეთ მას და თქვით: მშვიდობა ამ სახლს." },
  { verse: 13, text: "და თუ სახლი ღირსი იქნება, თქვენი მშვიდობა მიუვა მას, თუ არა და, თქვენი მშვიდობა თქვენავე დაგიბრუნდებათ." },
  { verse: 14, text: "და თუ არავინ მიგიღებთ და არც შეისმენს თქვენს სიტყვებს, იმ სახლიდან თუ ქალაქიდან გამოსვლისას ჩამოიბერტყეთ თქვენი ფეხიდან მტვერი." },
  { verse: 15, text: "ჭეშმარიტად გეუბნებით თქვენ: განკითხვის დღე სოდომისა და გომორის მხარისათვის უფრო ასატანი იქნება, ვიდრე იმ ქალაქისათვის." },
  { verse: 16, text: "აჰა, მე გგზავნით თქვენ როგორც ცხვრებს მგლების ხროვაში; მაშ, იყავით გონიერნი, როგორც გველები, და უმანკონი, როგორც მტრედები." },
  { verse: 17, text: "ეკრძალეთ ადამიანებს, ვინაიდან ისინი მიგცემენ სამართალში და თავიანთ სინაგოგებში მათრახით გცემენ თქვენ." },
  { verse: 18, text: "და მიგიყვანენ ჩემს გამო მთავრებისა და მეფეების წინაშე, მათთვის და წარმართთათვის სამოწმებლად." },
  { verse: 19, text: "ხოლო როდესაც გაგცემენ, ნუ იზრუნებთ, როგორ ვთქვათ, ანდა რა ვთქვათო; ვინაიდან თავად მოგეცემათ მაშინ სათქმელი." },
  { verse: 20, text: "რადგან თქვენ კი არ ილაპარაკებთ, არამედ სული თქვენი მამისა ილაპარაკებს თქვენში." },
  { verse: 21, text: "და გასცემს ძმა სასიკვდილოდ ძმას, და მამა - შვილს; შვილები აღდგებიან მშობლების წინააღმდეგ და დახოცავენ მათ." },
  { verse: 22, text: "და მოგიძულებთ ყველა ჩემი სახელის გამო; ხოლო ვინც ბოლომდე დაითმენს, იგი ცხონდება." },
  { verse: 23, text: "და როდესაც დაგიწყებენ დევნას ერთ ქალაქში, მიაშურეთ მეორეს. ჭეშმარიტად გეუბნებით თქვენ: ვერ მოასწრებთ ისრაელის ყველა ქალაქის მოვლას, რომ მოვა ძე კაცისა." },
  { verse: 24, text: "არ არის მოწაფე, თავის მოძღვარზე უმეტესი, და არც მონა, თავის მბრძანებელზე უპირატესი." },
  { verse: 25, text: "საკმარისია მოწაფისათვის, იყოს ისეთი, როგორც მისი მოძღვარი, და მონისათვის - როგორც მისი მბრძანებელი. თუ სახლის პატრონს ბელზებულად უხმობენ, მით უმეტეს, სახლეულს მისას." },
  { verse: 26, text: "მაშ, ნუ გეშინიათ მათი, ვინაიდან არ არსებობს დაფარული, რომ არ გამოჩნდეს, და არც რამ საიდუმლო, რომ არ გამჟღავნდეს." },
  { verse: 27, text: "რასაც სიბნელეში გეუბნებით, სინათლეზე თქვით, და რაც ყურში ჩაგესმით, ერდოებზე იქადაგეთ." },
  { verse: 28, text: "ნუ გეშინიათ მათი, რომელნიც ჰკლავენ ხორცს, მაგრამ არ შეუძლიათ სულის მოკვლა; არამედ უფრო გეშინოდეთ იმისა, ვისაც შეუძლია სულიცა და ხორციც წარწყმიდოს გეენას." },
  { verse: 29, text: "განა ორი ბეღურა ერთ ასარად არ იყიდება? მაგრამ ერთი მათგანიც არ დავარდება მიწაზე, თუ არ იქნა თქვენი მამის ნება." },
  { verse: 30, text: "ხოლო თქვენს თავზე ყოველი ღერი თმაც სათითაოდ დათვლილია." },
  { verse: 31, text: "მაშ, ნუ შიშობთ, ვინაიდან უთვალავ ბეღურაზე უმჯობესნი ხართ." },
  { verse: 32, text: "ყველას, ვინც მაღიარებს კაცთა წინაშე, მეც ვაღიარებ ჩემი ზეციერი მამის წინაშე." },
  { verse: 33, text: "ხოლო ვინც უარმყოფს კაცთა წინაშე, მეც უარვყოფ ჩემი ზეციერი მამის წინაშე." },
  { verse: 34, text: "ნუ გგონიათ, თითქოს მოვედი, რათა მშვიდობა მომეტანა ამ ქვეყნად; მშვიდობის მომტანად კი არ მოვედი, არამედ მახვილისა." },
  { verse: 35, text: "ვინაიდან მოვედი, რათა გავყარო ვაჟი მამამისს, ქალი - დედამისს, და რძალი - დედამთილს მისას." },
  { verse: 36, text: "და კაცს მტრებად ვუქციო მისი სახლეულნი." },
  { verse: 37, text: "ვისაც მამა ან დედა ჩემზე მეტად უყვარს, არ არის ჩემი ღირსი; და ვისაც ძე ან ასული ჩემზე მეტად უყვარს, არ არის ჩემი ღირსი;" },
  { verse: 38, text: "ვინც არ აიღებს თავის ჯვარს და არ გამომყვება, არ არის ჩემი ღირსი." },
  { verse: 39, text: "ვინც ჰპოვებს თავის სულს, დაჰკარგავს მას; და ვინც ჩემი გულისათვის დაჰკარგავს თავის სულს, მოიპოვებს მას." },
  { verse: 40, text: "ვინც თქვენ შეგიწყნარებთ, მე შემიწყნარებს; ხოლო ვინც მე შემიწყნარებს, შეიწყნარებს ჩემს მომავლინებელს." },
  { verse: 41, text: "ვინც წინასწარმეტყველის სახელით შეიწყნარებს წინასწარმეტყველს, წინასწარმეტყველის საზღაურს მიიღებს; და ვინც მართლის სახელით შეიწყნარებს მართალს, მართლის საზღაურს მიიღებს." },
  { verse: 42, text: "და ვინც მოწაფის სახელით მიაწვდის ცივ წყალს ერთს ამ მცირეთაგანს, ჭეშმარიტად გეუბნებით თქვენ, არ დაეკარგება თავისი საზღაური." }
],
11: [
  { verse: 1, text: "და როდესაც დაასრულა იესომ შეგონება თავისი თორმეტი მოწაფის მიმართ, წავიდა იქიდან მათს ქალაქებში სასწავლად და საქადაგებლად." },
  { verse: 2, text: "ხოლო იოანემ შეიტყო საპყრობილეში ქრისტეს საქმენი, და გამოგზავნა თავისი ორი მოწაფე." },
  { verse: 3, text: "რათა ეკითხათ მისთვის: შენა ხარ მომავალი, თუ სხვა ვინმეს უნდა ველოდეთ?" },
  { verse: 4, text: "ხოლო იესომ მიუგო მათ: მიდით და უთხარით იოანეს, რასაც ისმენთ და ხედავთ:" },
  { verse: 5, text: "ბრმანი ხედავენ, კოჭლნი დადიან, კეთროვანნი იწმინდებიან და ყრუნი ისმენენ: მკვდარნი აღდგებიან და გლანაკნი სახარებით ხარობენ." },
  { verse: 6, text: "ნეტარ არს, ვინც არ შემცდარა ჩემში." },
  { verse: 7, text: "ხოლო მათი წასვლის შემდეგ იესომ იოანეზე ჩამოუგდო სიტყვა ხალხს: რისთვის დადიოდით უდაბნოში? ქარისაგან რხეული ლერწმის ხილვად?" },
  { verse: 8, text: "რისთვის დადიოდით უდაბნოში? ლბილი სამოსით მოსილი კაცის ხილვად? მაგრამ ლბილი სამოსით მოსილნი მეფეთა დარბაზებში არიან." },
  { verse: 9, text: "რისთვის დადიოდით უდაბნოში? წინასწარმეტყველის ხილვად? დიახ, გეტყვით თქვენ, წინასწარმეტყველისა და უფრო მეტისაც." },
  { verse: 10, text: "რადგან ეს არის იგი, ვისთვისაც დაიწერა: აჰა, მე ვგზავნი ჩემს ანგელოზს შენს წინაშე, რომელიც განამზადებს შენს გზას შენსავ წინაშე." },
  { verse: 11, text: "ჭეშმარიტად გეუბნებით თქვენ: დედისაგან შობილი არვინ აღმდგარა იოანე ნათლისმცემელზე უმეტესი, ხოლო ცათა სასუფეველში უმცირესიც მასზე უმეტესია." },
  { verse: 12, text: "ვინაიდან იოანე ნათლისმცემლიდან მოყოლებული დღემდე, ცათა სასუფეველი ძალით იღება, და ძალისმხმეველნი მიიტაცებენ მას." },
  { verse: 13, text: "რადგან ყველა წინასწარმეტყველი, და თვით რჯული იოანემდე წინასწარმეტყველებდნენ." },
  { verse: 14, text: "და თუ გნებავთ გაიგოთ, ეს არის ელია, რომელიც უნდა მოვიდეს." },
  { verse: 15, text: "ვისაც აქვს ყურნი სმენად, ისმინოს!" },
  { verse: 16, text: "ან ვის ვამსგავსო ეს მოდგმა? ვამსგავსებ მოედანზე მსხდომ ბალღებს, თავიანთ ტოლებს რომ უყვირიან" },
  { verse: 17, text: "და ამბობენ: თქვენთვის ვუკრავდით, და არ იცეკვეთ; თქვენთვის ვგოდებდით, და არ იგლოვეთ." },
  { verse: 18, text: "ვინაიდან მოვიდა იოანე; არც ჭამს და არც სვამს, და ამბობენ: ეშმაკი ჰყავსო." },
  { verse: 19, text: "მოვიდა ძე კაცისა; კიდეც ჭამს და კიდეც სვამს, და ამბობენ: აჰა, კაცი მჭამელი და ღვინის მსმელი, მებაჟეთა და ცოდვილთა მეგობარიო. მაგრამ გამართლდა სიბრძნე მისი შვილებისაგან." },
  { verse: 20, text: "მაშინ დაიწყო იესომ იმ ქალაქთა გმობა, სადაც ყველაზე მეტი ძალნი გამოავლინა, მაგრამ მათ არ შეინანეს:" },
  { verse: 21, text: "ვაი შენდა, ქორაზინ, და ვაი შენდა, ბეთსაიდა; რადგან ტიროსსა და სიდონს რომ მოვლენოდა თქვენში მოვლენილი ძალნი, რა ხანია ძაძითა და ნაცრით შეინანებდნენ." },
  { verse: 22, text: "ამიტომ გეუბნებით თქვენ: განკითხვის დღე ტიროსისა და სიდონისათვის უფრო ასატანი იქნება, ვიდრე თქვენთვის." },
  { verse: 23, text: "და შენ, კაპერნაუმ, თვით ზეცამდე ამაღლებულო, ჯოჯოხეთამდე დაემხობი: რადგან სოდომს რომ მოვლენოდა შენში მოვლენილი ძალნი, იქნებ კიდევაც მდგარიყო დღევანდელ დღემდე." },
  { verse: 24, text: "ამიტომ გეუბნები შენ: განკითხვის დღე სოდომის მხარისთვის უფრო ასატანი იქნება, ვიდრე შენთვის." },
  { verse: 25, text: "იმ ხანად იესომ პასუხად თქვა: გადიდებ, მამაო, ცისა და მიწის უფალო, ვინაიდან ბრძენთა და გონიერთ დაუფარე ყოველივე ეს, და გაუცხადე ჩვილ ბალღებს." },
  { verse: 26, text: "დიახ, მამაო, ასე კეთილინებე შენ." },
  { verse: 27, text: "ყველაფერი მამისაგან მომეცა მე და არავინ იცის ძე, გარდა მამისა; და არც მამა იცის ვინმემ, გარდა ძისა და იმისა, ვისთვისაც ძე ინებებს მის გამოცხადებას." },
  { verse: 28, text: "მოდით ჩემთან ყოველი მაშვრალნი და ტვირთმძიმენი, და მე მოგიფონებთ თქვენ." },
  { verse: 29, text: "დაიდგით ქედზე ჩემი უღელი და ისწავლეთ ჩემგან, ვინაიდან მშვიდი ვარ და გულით მდაბალი, და მოიპოვებთ სულის სიმშვიდეს." },
  { verse: 30, text: "ვინაიდან უღელი ჩემი ამოა, და ტვირთი ჩემი - მსუბუქი." },
],
12: [
  { verse: 1, text: "ერთხელ, შაბათ დღეს, ყანაში მიდიოდა იესო; მოშივდათ მის მოწაფეებს და დაიწყეს თავთავების კრეფა და ჭამა." },
  { verse: 2, text: "ეს რომ დაინახეს, ფარისევლებმა უთხრეს მას: აი, შენი მოწაფეები იმას სჩადიან, რაც ნებადართული არ არის შაბათს." },
  { verse: 3, text: "ხოლო იესომ უთხრა მათ: არ წაგიკითხავთ, როგორ მოიქცა დავითი, როცა მოშივდა მასაც და მის მხლებლებსაც?" },
  { verse: 4, text: "როგორ მევიდა ღმერთის სახლში და შეჭამა შესაწირავი პური, რისი ქმნა არც მისთვის იყო ნებადართული და არც მისი მხლებლებისათვის, და რისი ნებაც მხოლოდ მღვდლებს ჰქონდათ?" },
  { verse: 5, text: "არც ის ამოგიკითხავთ რჯულში, რომ შაბათობით მღვდლები ტაძარში არღვევენ შაბათს, და მაინც უცოდველნი არიან?" },
  { verse: 6, text: "ხოლო მე გეუბნებით თქვენ: აქ არის ის, ვინც ტაძარზეც უმეტესია." },
  { verse: 7, text: "რომ იცოდეთ, რას ნიშნავს: წყალობა მნებავს და არა მსხვერპლი, აღარასოდეს შეაჩვენებდით უცოდველთ." },
  { verse: 8, text: "რადგან ძე კაცისა შაბათის უფალიც არის." },
  { verse: 9, text: "წამოვიდა იქიდან იესო და შევიდა მათ სინაგოგაში." },
  { verse: 10, text: "და, აჰა, იყო იქ ერთი ხელგამხმარი კაცი, და ჰკითხეს იესოს, რათა ბრალი დაედოთ მისთვის: თუ შეიძლება კაცი განკურნო შაბათს?" },
  { verse: 11, text: "ხოლო იესომ პასუხად უთხრა მათ: რომელიმე თქვენგანს ერთი ცხვარი რომ ჰყავდეს და შაბათ დღეს ორმოში ჩაუვარდეს, ნუთუ ხელს არ ჩასჭიდებს და არ ამოიყვანს მას?" },
  { verse: 12, text: "ხოლო კაცი რამდენად უმჯობესია ცხვარზე? ამიტომაც შეიძლება შაბათ დღეს სიკეთის ქმნა." },
  { verse: 13, text: "და უთხრა მაშინ კაცს: გაიწოდე შენი ხელი! მანაც გაიწოდა და ისევე გაუმრთელდა, როგორც მეორე." },
  { verse: 14, text: "ხოლო ფარისევლები გამოვიდნენ და მოითათბირეს მის წინააღმდეგ, თუ როგორ დაეღუპათ იგი." },
  { verse: 15, text: "მაგრამ იესომ გაიგო ეს და გაეცალა იქაურობას; თან მისდევდა დიდძალი ხალხი და განკურნა ყველა." },
  { verse: 16, text: "და უბრძანა მათ, არ გამთქვათო." },
  { verse: 17, text: "რათა აღსრულდეს თქმული ესაია წინასწარმეტყველის მიერ, რომელიც ამბობს:" },
  { verse: 18, text: "აჰა, მსახური ჩემი, რომელიც ავირჩიე; საყვარელი ჩემი, რომელიც შევიტკბე სულით; დავსდებ მასზე ჩემს სულს, და აუწყებს სამართალს ხალხებს." },
  { verse: 19, text: "არ იდავებს, არ იყვირებს და ვერც ვერავინ მოისმენს ქუჩებში მის ხმას." },
  { verse: 20, text: "მოტეხილ ლერწამს არ გადატეხს და მბჟუტავ პატრუქს არ დაშრეტს, ვიდრე არ მოუპოვებს ძლევას სამართალს." },
  { verse: 21, text: "და მისი სახელი სასოებად ექნება ხალხებს." },
  { verse: 22, text: "მაშინ მიჰგვარეს მას ბრმა და მუნჯი ეშმაკეული, და განკურნა იგი, ისე, რომ ამ ბრმასა და მუნჯს თვალი აეხილა და ამეტყველდა." },
  { verse: 23, text: "უკვირდა ხალხს და ამბობდა: ეს ხომ არ არის დავითის ძეო?" },
  { verse: 24, text: "ხოლო ამის გამგონე ფარისევლები ამბობდნენ: ეს თუ ეშმაკებს აძევებს, მხოლოდ ეშმაკთა მთავრის, ბელზებულის შეწევნითო." },
  { verse: 25, text: "მაგრამ იცოდა იესომ, რასაც ფიქრობდნენ ისინი, და უთხრა მათ: ყოველი სამეფო, თავისი თავის წინააღმდეგ გაყოფილი, გაპარტახდება: და ყოველი ქალაქი, გინდა სახლი, თავისი თავის წინააღმდეგ გაყოფილი, დაიქცევა." },
  { verse: 26, text: "თუკი სატანა აძევებს სატანას, მაშინ ის თავის თავს განეყოფა; როგორღა გაძლებს მასი სამეფო?" },
  { verse: 27, text: "და თუ მე ბელზებულის შეწევნით ვაძევებ ეშმაკთ, ვისი შეწევნითღა აძევებენ მათ თქვენი ძენი? ამიტომ ისინი იქნებიან თქვენი მსაჯულნი." },
  { verse: 28, text: "ხოლო თუ მე ღმერთის სულით ვაძევებ ეშმაკთ, მოუწევია კიდეც თქვენამდე ღმრთის სასუფეველს." },
  { verse: 29, text: "ან როგორ შეძლებს ვინმე შევიდეს ძლიერის სახლში და გაძარცვოს იგი, თუკი თავდაპირველად არ შებოჭავს ძლიერს? მხოლოდ ამის შემდეგ თუ შესძლებს მისი სახლის გაძარცვას." },
  { verse: 30, text: "ვინც ჩემთან არაა, ჩემს წინააღმდეგაა; და ვინც ჩემთან არა კრებს, - ფანტავს." },
  { verse: 31, text: "ამიტომ გეუბნებით თქვენ: ყოველი ცოდვა და გმობა მიეტევება ადამიანებს, მაგრამ სულის გმობა არ მიეტევება მათ." },
  { verse: 32, text: "ვინც იტყვის სიტყვას კაცის ძის წინააღმდეგ, მიეტევება მას; მაგრამ ვინც იტყვის სიტყვას სული წმიდის წინააღმდეგ, არ მიეტევება მას, არც ამ წუთისოფლად და არც საუკუნო სოფლად." },
  { verse: 33, text: "ან სცანით ხე ვარგისად და მისი ნაყოფიც ვარგისად; ან სცანით ხე უვარგისად და მისი ნაყოფიც უვარგისად; ვინაიდან ნაყოფით იცნობა ხე." },
  { verse: 34, text: "იქედნეს ნაშიერნო, როგორ შეგიძლიათ, თავად უკეთურთ, კეთილი სიტყვის თქმა? ვინაიდან გულის სისავსისგან მეტყველებს ბაგე." },
  { verse: 35, text: "კეთილ კაცს კეთილი საუნჯისგან გამოაქვს კეთილი, და ბოროტ კაცს ბოროტი საუნჯისგან გამოაქვს ბოროტი." },
  { verse: 36, text: "ხოლო მე გეუბნებით თქვენ: ყოველი ფუჭი სიტყვისათვის, რომელსაც იტყვიან კაცნი, პასუხს აგებენ ისინი განკითხვის დღეს." },
  { verse: 37, text: "ვინაიდან შენი სიტყვებით გამართლდები, და შენივე სიტყვებით განიკითხები." },
  { verse: 38, text: "მაშინ ზოგმა მწიგნობარმა და ფარისეველმა უთხრა მას: მოძღვარო, გვსურს სასწაული ვიხილოთ შენგან." },
  { verse: 39, text: "ხოლო მან პასუხად თქვა: უკეთური და მემრუშე მოდგმა სასწაულს ეძებს; მაგრამ სასწაული არ მიეცემა მას, გარდა იონა წინასწარმეტყველის სასწაულისა." },
  { verse: 40, text: "ვინაიდან როგორც იონამ დაყო ვეშაპის მუცელში სამი დღე და სამი ღამე, ასევე დაყოფს ძეც კაცისა ქვეყნის გულში სამ დღეს და სამ ღამეს." },
  { verse: 41, text: "ნინეველნი აღსდგებიან განკითხვისას ამ მოდგმასთან ერთად და შეაჩვენებენ მას, ვინაიდან მათ შეინანეს იონას ქადაგებით, და, აჰა, აქ იონაზე უმეტესია." },
  { verse: 42, text: "სამხრეთის დედოფალი აღსდგება განკითხვისას ამ მოდგმასთან ერთად და შეაჩვენებს მას, ვინაიდან ქვეყნის დასალიერიდან მოვიდა სოლომონის სიბრძნის სასმენად, და, აჰა, აქ სოლომონზე უმეტესია." },
  { verse: 43, text: "როდესაც უწმინდური სული გამოვა კაცისაგან, უწყალო ადგილებს დაეძებს განსასვენებლად, და ვერ ჰპოვებს მას." },
  { verse: 44, text: "და მაშინ იტყვის: დავბრუნდები ჩემს სახლში, საიდანაც გამოვედი; და როცა მივა, ჰპოვებს მას ცარიელს, დაგვილსა და დამშვენებულს." },
  { verse: 45, text: "მაშინ წავა და მოიყვანს შვიდ სხვა სულსაც, მასზე უბოროტესს; შევა და დაემკვიდრება იქ; და ამ კაცის უკანასკნელი დღე პირველზე უარესი იქნება. იგივე დღე ელის ამ უკეთურ მოდგმასაც." },
  { verse: 46, text: "და ვიდრე ასე ესაუბრებოდა ხალხს, მისი დედა და ძმები გარეთ იდგნენ და სიტყვის სათქმელად ეძებდნენ მას." },
  { verse: 47, text: "მაშინ ვიღაცამ უთხრა მას: აჰა, დედაშენი და შენი ძმები გარეთ დგანან და სიტყვის სათქმელად გეძებენ შენ." },
  { verse: 48, text: "ხოლო იესომ პასუხად თქვა: ვინ არის დედაჩემი? ან ვინ არიან ჩემი ძმები?" },
  { verse: 49, text: "გაიშვირა ხელი თავისი მოწაფეებისაკენ და თქვა: აჰა, დედაჩემი და ჩემი ძმები." },
  { verse: 50, text: "რადგან ვინც აღასრულებს ჩემი ზეციერი მამის ნებას, იგია ძმაც, დაც და დედაც ჩემი." },
],

13: [
  { verse: 1, text: "იმ დღეს სახლიდან გამოვიდა იესო და ზღვის პირას დაჯდა." },
  { verse: 2, text: "და შემოკრბა მის ირგვლივ დიდძალი ხალხი, ისე, რომ ნავში შევიდა და დაჯდა, ხოლო მთელი ხალნი ნაპირზე იდგა." },
  { verse: 3, text: "ბევრ რასმე ასწავლიდა მათ იგავებით და ამბობდა: აჰა, გამოვიდა მთესავი თესვად." },
  { verse: 4, text: "ხოლო თესვისას ზოგი მარცვალი გზის პირას დავარდა, და მოფრინდნენ ფრინველები და აკენკეს ისინი." },
  { verse: 5, text: "ზოგიც ქვიან ადგილას დავარდა, სადაც ბლომად არ იყო მიწა, და მალე აღმოცენდა, ვინაიდან ნიადაგი არ იყო ღრმა." },
  { verse: 6, text: "მაგრამ ამოვიდა თუ არა მზე, დაჭკნა, და რადგან ფესვი არ ჰქონდა, გახმა." },
  { verse: 7, text: "ზოგი კი ეკალ-ბარდებში ჩაცვივდა; იზარდა ეკალი და ერთიანად მოაშთო ყველა." },
  { verse: 8, text: "ხოლო ზოგი პოხიერ ნიადაგზე დაეცა და ნაყოფიც გამოიღო: ზოგმა ასი, ზოგმა სამოცი და ზოგმაც ოცდაათი." },
  { verse: 9, text: "ვისაც აქვს ყურნი სმენად, ისმინოს!" },
  { verse: 10, text: "მივიდნენ მოწაფეები და უთხრეს მას: რატომ ელაპარაკები მათ იგავებით?" },
  { verse: 11, text: "ხოლო მან მიუგო და უთხრა მათ: იმიტომ, რომ თქვენ მოგეცათ ცათა სასუფევლის საიდუმლოთა ცოდნა, ხოლო ამათ არ მისცემია." },
  { verse: 12, text: "რადგან ვისაც აქვს, მას მიეცემა და მიემატება, ხოლო ვისაც არა აქვს, წაერთმევა ისიც, რაცა აქვს." },
  { verse: 13, text: "იგავებით იმიტომ ველაპარაკები მათ, რომ მხედველნი ვერას ხედავენ, მსმენელნი ვერას ისმენენ, და არც არა გაეგებათ რა." },
  { verse: 14, text: "და მართლდება მათ მიმართ წინასწარმეტყველება ესაიასი, რომელიც ამბობს: სმენით მოისმინეთ და ვერას გაიგებთ, ხილვით იხილავთ და ვერ დაინახავთ." },
  { verse: 15, text: "რადგან გამქისდა ამ ხალხის გული, დაეხშოთ ყური და დაევსოთ თვალი, რათა არ იხილონ თვალით, არ ისმინონ ყურით, არ იგრძნონ გულით, და არ მოიქცნენ, რათა განვკურნო ისინი." },
  { verse: 16, text: "ხოლო ნეტარ არიან თქვენი თვალნი იმიტომ, რომ ხედავენ, და თქვენი ყურნი იმიტომ, რომ ისმენენ." },
  { verse: 17, text: "ჭეშმარიტად გეუბნებით თქვენ: მრავალ წინასწარმეტყველსა და მართალს სურდათ ეხილათ ის, რასაც ხედავთ, და ვერ იხილეს; და ესმინათ ის, რასაც ისმენთ, და ვერ ისმინეს." },
  { verse: 18, text: "მაშ, ისმინეთ მთესავის იგავი:" },
  { verse: 19, text: "ყველას, ვინც ისმენს სასუფევლის სიტყვას, მაგრამ არ ესმის იგი, მიადგება უკეთური და მოსტაცებს გულში ჩათესილს: ეს არის თესლი, გზის პირას რომ დაითესა." },
  { verse: 20, text: "ხოლო ქვიან ადგილას დათესილი ის არის, ვინც ისმენს სიტყვას და მაშინვე სიხარულით იღებს მას." },
  { verse: 21, text: "მაგრამ ფესვი არა აქვს მასში, და ამიტომ უდღეურია; და როდესაც მოაწევს ჭირის დღე ან დევნა სიტყვის გამო, მყისვე ცდუნდება." },
  { verse: 22, text: "ხოლო ეკალ-ბარდებში დათესილი ის არის, ვინც ისმენს სიტყვას, მაგრამ სოფლის საზრუნავი და სიმდიდრის საცდური აშთობენ სიტყვას და უნაყოფოს ხდიან მას." },
  { verse: 23, text: "პოხიერ ნიადაგზე დათესილი კი ის არის, ვინც ისმენს და კიდეც შეიგნებს სიტყვას, და ამიტომაც გამოაქვს ნაყოფი; ერთი ასად, ერთი სამოცად თუ ერთი ოცდაათად." },
  { verse: 24, text: "სხვა იგავიც შესთავაზა და უთხრა მათ: ცათა სასუფეველი მსგავსია კაცისა, საღი თესლი რომ დათესა თავის ყანაში." },
  { verse: 25, text: "ხოლო როდესაც ეძინა ხალხს, მოვიდა მისი მტერი, ღვარძლი ჩათესა ყანაში და წავიდა." },
  { verse: 26, text: "როდესაც აღმოცენდა ჯეჯილი და თავთავი დაისხა, ღვარძლმაც მაშინ იჩინა თავი." },
  { verse: 27, text: "მივიდნენ მონები ყანის პატრონთან და უთხრეს: ბატონო, შენ ხომ საღი თესლი დათესე ყანაში: საიდანღა აქვს ღვარძლი?" },
  { verse: 28, text: "ხოლო მან უთხრა მათ: მტერმა ქნა ეს. მონებმა კი უთხრეს: თუ გნებავს, მივალთ და გავმარგლავთ ყანას." },
  { verse: 29, text: "მაგრამ მან თქვა: არა, რათა მარგვლისას ღვარძლს ჯეჯილიც არ მიაყოლოთ." },
  { verse: 30, text: "აცადეთ, ერთად იზარდონ მკამდე; ხოლო მკისას ვუბრძანებ მომკალთ: თავდაპირველად შეკრიბეთ ღვარძლი, ძნებად შეკარით და ცეცხლი წაუკიდეთ, ხორბალი კი შეინახეთ ჩემს ბეღელში." },
  { verse: 31, text: "სხვა იგავიც შესთავაზა მათ და უთხრა: ცათა სასუფეველი მსგავსია მდოგვის მარცვლისა, რომელიც აიღო კაცმა და დათესა თავის ყანაში;" },
  { verse: 32, text: "ეს მარცვალი ყოველნაირ თესლზე მცირეა, მაგრამ როცა ამოვა, ყველა მწვანილზე დიდი ხდება და ხედ იქცევა, ისე რომ, მოფრინავენ ცის ფრინველები და მის ტოტებზე იბუდებენ." },
  { verse: 33, text: "მერე სხვა იგავიც უთხრა მათ: ცათა სასუფეველი მსგავსია საფუარისა, რომელიც აიღო ქალმა და მოზილა იმით სამი საწყაო ფქვილი, ვიდრე მთელი ცომი არ აფუვდა." },
  { verse: 34, text: "ყოველივე ამას იგავებით ეუბნებოდა ხალხს იესო და გარდა იგავისა არაფერს ეტყოდა მათ." },
  { verse: 35, text: "რათა აღსრულდეს წინასწარმეტყველის მიერ თქმული, რომელიც ამბობს: გავხსნი ჩემს ბაგეს იგავთ სათქმელად, და ვიტყვი, რაც დაფარულია ქვეყნის დასაბამიდან." },
  { verse: 36, text: "მაშინ გაუშვა იესომ ხალხი და სახლში დაბრუნდა. მიუახლოვდნენ მისი მოწაფეები და უთხრეს: განგვიმარტე ღვარძლისა და ყანის იგავი." },
  { verse: 37, text: "ხოლო მან მიუგო და უთხრა მათ: საღი თესლის მთესავი ძეა კაცისა." },
  { verse: 38, text: "ყანა არის ქვეყანა; საღი თესლი სასუფევლის ძენი არიან, ხოლო ღვარძლი - უკეთურის ძენი." },
  { verse: 39, text: "ღვარძლის მთესავი მტერი ეშმაკია: მკა - ქვეყნის დასასრული, და მომკალნი - ანგელოზები." },
  { verse: 40, text: "როგორც შეკრებენ ღვარძლს და ცეცხლს მისცემენ, ასევე იქნება ქვეყნის დასასრულს." },
  { verse: 41, text: "რადგან მოავლინებს ძე კაცისა თავის ანგელოზებს, და შეკრებენ მის სასუფეველში ყოველი საცდურისა და ურჯულოების მოქმედთ." },
  { verse: 42, text: "და ჩაყრიან მათ სახმილის ცეცხლში: და იქნება იქ ტირილი და კბილთა ღრჭიალი." },
  { verse: 43, text: "მაშინ მზესავით გამობრწყინდებიან მართალნი მათი მამის სასუფეველში. ვისაც აქვს ყურნი სმენად, ისმინოს!" },
  { verse: 44, text: "და მერე, მსგავსია ცათა სასუფეველი ყანაში დაფლული განძისა, რომელიც იპოვა კაცმა, დამალა და გახარებული წავიდა; გაყიდა ყველაფერი, რაც ებადა, და იყიდა ის ყანა." },
  { verse: 45, text: "და მერე, მსგავსია ცათა სასუფეველი ვაჭარი კაცისა, რომელიც ეძებს ლამაზ მარგალიტს." },
  { verse: 46, text: "და როცა იპოვის ძვირფას მარგალიტს, წავა, გაჰყიდის ყველაფერს, რაც აბადია, და იყიდის მას." },
  { verse: 47, text: "და მერე, მსგავსია ცათა სასუფეველი ბადისა, რომელსაც ისვრიან ზღვაში, და იჭერს ყოველნაირ თევზს;" },
  { verse: 48, text: "ხოლო როცა გაივსება, ნაპირზე გამოათრევენ, დასხდებიან და ვარგისით გოდრებს დაავსებენ, ხოლო უვარგისთ გადაჰყრიან." },
  { verse: 49, text: "ასე იქნება ქვეყნის დასასრულსაც: მოვლენ ანგელოზები და მართალთაგან განაშორებენ უკეთურთ;" },
  { verse: 50, text: "და ჩაყრიან მათ სახმილის ცეცხლში, და იქნება იქ ტირილი და კბილთა ღრჭიალი." },
  { verse: 51, text: "ჰკითხა მათ იესომ: გესმით თუ არა ყოველივე ეს? და მათ მიუგეს: დიახ, უფალო." },
  { verse: 52, text: "ხოლო იესომ უთხრა მათ: ამიტომ ყოველი მწიგნობარი, რომელიც ცათა სასუფევლის მოწაფე გახდა, მსგავსია სახლის პატრონისა, რომელსაც თავისი საუნჯიდან გამოაქვს ახალიცა და ძველიც." },
  { verse: 53, text: "და როცა დაასრულა იესომ ეს იგავნი, იქაურობას გაეცალა." },
  { verse: 54, text: "მივიდა თავის მამულში და ასწავლიდა მათ სინაგოგაში, ისე რომ, უკვირდათ და ამბობდნენ: ვინ მისცა ესოდენი სიბრძნე და ძალა?" },
  { verse: 55, text: "განა ხუროს შვილი არ არის? განა დედამისს მარიამი არა ჰქვია, ხოლო მის ძმებს - იაკობი და იოსე, სიმონი და იუდა?" },
  { verse: 56, text: "და განა ჩვენს შორის არ არიან მისი დები? ვინ მისცა ყოველივე ეს?" },
  { verse: 57, text: "და ცდებოდნენ მასში. ხოლო იესომ უთხრა მათ: არ არის წინასწარმეტყველი პატივის გარეშე, თუ არა თავის მამულში და თავის სახლში." },
  { verse: 58, text: "და არა მოუხდენია იქ მრავალი სასწაული მათი ურწმუნოების გამო." },
],
14: [
  { verse: 1, text: "იმ ხანად ჰეროდე მეოთხედმთავრამდე მიაღწია იესოს ამბავმა;" },
  { verse: 2, text: "და უთხრა თავის მსახურთ: ეს არის იოანე ნათლისმცემელი; მკვდრეთით აღმდგარა და ამიტომ ძალნი მოქმედებენ მასში." },
  { verse: 3, text: "ვინაიდან ჰეროდემ შეიპყრო იოანე, გათოკა და საპყრობილეში ჩააგდო ჰეროდიადას, თავისი ძმის - ფილიპეს ცოლის გამო." },
  { verse: 4, text: "რადგანაც იოანე ეუბნებოდა: არ შეიძლება შენ გყავდესო იგი." },
  { verse: 5, text: "და უნდოდა მისი მოკვლა, მაგრამ ხალხისა ეშინოდა, ვინაიდან წინასწარმეტყველად მიაჩნდათ იგი." },
  { verse: 6, text: "ხოლო ჰეროდეს დაბადების დღეს ჰეროდიადას ასულმა იცეკვა წვეულთა წინაშე და მოხიბლა ჰეროდე." },
  { verse: 7, text: "ამიტომ ფიცით აღუთქვა მას, მოგცემ, რასაცა მთხოვო." },
  { verse: 8, text: "ხოლო მან, დედამისისგან წინასწარ გაზრახებულმა, სთხოვა ლანგრით მიეცათ იოანე ნათლისმცემლის თავი." },
  { verse: 9, text: "შეწუხდა მეფე, მაგრამ, ფიცისა და თანამეინახეთა რიდით, მიცემა ბრძანა." },
  { verse: 10, text: "წარგზავნა მსახურნი, რათა იოანესთვის თავი მოეკვეთათ საპყრობილეში." },
  { verse: 11, text: "მოართვეს თავი ლანგრით და მისცეს ყმაწვილ ქალს, ხოლო მან მიართვა დედამისს." },
  { verse: 12, text: "იოანეს მოწაფეები მივიდნენ, გამოიტანეს მისი ნეშტი და დამარხეს: მერე კი წავიდნენ და აუწყეს იესოს." },
  { verse: 13, text: "ეს რომ გაიგო, იესო ნავით გაეცალა იქაურობას და უდაბნოში განმარტოვდა, მაგრამ შეიტყო ხალხმა და ფეხდაფეხ მიჰყვა ქალაქებიდან." },
  { verse: 14, text: "გამოვიდა იესო, იხილა დიდძალი ხალხი, შეებრალა ისინი და განკურნა მათი სნეულნი." },
  { verse: 15, text: "ხოლო შებინდებისას მივიდნენ მისი მოწაფეები და უთხრეს: უდაბურია ეს ადგილი და თანაც გვიანია უკვე: გაუშვი ხალხი, რათა წავიდნენ სოფლებში საჭმლის საყიდლად." },
  { verse: 16, text: "მაგრამ იესომ უთხრა მათ: არ დასჭირდებათ წასვლა; თქვენ თვითონ მიეცით საჭმელი." },
  { verse: 17, text: "ხოლო მათ უთხრეს: რომ არაფერი გვაქვს, ხუთი პურისა და ორი თევზის გარდა?" },
  { verse: 18, text: "იესომ უთხრა მათ: აქ მომიტანეთ." },
  { verse: 19, text: "და მოლზე დასხდომა უბრძანა ხალხს: აიღო ხუთი პური და ორი თევზი, ზეცად აღაპყრო თვალნი, აკურთხა და დატეხა პურები და მისცა მოწაფეებს, ხოლო მათ ჩამოურიგეს ხალხს." },
  { verse: 20, text: "ყველამ ჭამა და გაძღა; ნარჩენებით კი გაავსეს თორმეტი კალათი." },
  { verse: 21, text: "ხოლო იყო მჭამელი ასე ხუთიათასამდე კაცი, ქალებისა და ბავშვების გარდა." },
  { verse: 22, text: "და მაშინვე აიძულა თავისი მოწაფეები, ნავში ჩამსხდარიყვნენ და მასზე ადრე გასულიყვნენ გაღმა, სანამდის თვითონ გაისტუმრებდა ხალხს." },
  { verse: 23, text: "ხალხი რომ გაისტუმრა, განმარტოებით ავიდა მთაზე სალოცავად; და მწუხრის ჟამს მარტო იყო იქ." },
  { verse: 24, text: "ხოლო ნავი უკვე შუაგულ ზღვაში იყო, და ტალღები ეხეთქებოდნენ მას, ვინაიდან პირქარი ქროდა." },
  { verse: 25, text: "და ღამის მეოთხე გუშაგობისას იესო ზღვაზე სვლით მივიდა მათთან." },
  { verse: 26, text: "ზღვაზე მომავალი რომ დაინახეს, მოწაფეები შეძრწუნდნენ და თქვეს: მოჩვენება არისო, და შიშით შეჰყვირეს." },
  { verse: 27, text: "მყისვე შეეხმიანათ იესო: მხნედ იყავით; მე ვარ, ნუ გეშინიათ." },
  { verse: 28, text: "მიუგო პეტრემ და უთხრა მას: უფალო, თუ მართლა შენა ხარ, მიბრძანე, რომ ზღვით მოვიდე შენთან." },
  { verse: 29, text: "მანაც უბრძანა: მოდი! და გადმოვიდა პეტრე ნავიდან, რათა ზღვაზე სვლით მისულიყო იესოსთან." },
  { verse: 30, text: "მაგრამ რა იხილა ძლიერი ქარი, შეშინდა, ჩაძირვა იწყო და შეჰღაღადა: უფალო, მიხსენ მე!" },
  { verse: 31, text: "მყისვე გაუწოდა ხელი იესომ, ჩასჭიდა მას და უთხრა: მცირედ მორწმუნეო, რამ შეგაეჭვა?" },
  { verse: 32, text: "და ავიდნენ თუ არა ნავზე, მაშინვე ჩადგა ქარი." },
  { verse: 33, text: "ხოლო ნავში მყოფნი მიეახლნენ, თაყვანი სცეს და უთხრეს: ჭეშმარიტად ღმრთის ძე ხარ შენ." },
  { verse: 34, text: "ასე გავიდნენ გაღმა და მიადგნენ გენესარეთის მხარეს." },
  { verse: 35, text: "და იცნეს იგი იქაურებმა, ხალხი დაგზავნეს მთელს მხარეში და მიჰგვარეს ყველა სნეული." },
  { verse: 36, text: "ევედრებოდნენ, ხელი შეგვახებინე შენი სამოსის კალთისთვისო; და ვინც შეახო, განიკურნა." },
],
15: [
  { verse: 1, text: "მაშინ მივიდნენ იესოსთან იერუსალიმელი მწიგნობრები და ფარისევლები და უთხრეს:" },
  { verse: 2, text: "რატომ არღვევენ შენი მოწაფეები უხუცესთა ჩვეულებას? ვინაიდან ხელს არ იბანენ პურის ჭამისას." },
  { verse: 3, text: "ხოლო იესომ პასუხად მიუგო მათ: კი მაგრამ, თქვენ რატომღა არღვევთ ღმერთის მცნებას თქვენი ჩვეულებით?" },
  { verse: 4, text: "ვინაიდან ღმერთმა ბრძანა: პატივი ეცი მამას შენსას და დედას; და კიდევ: ვინც მამისა თუ დედის ძვირს იტყვის, სიკვდილით მოკვდეს." },
  { verse: 5, text: "ხოლო თქვენ ამბობთ: ყველა, ვინც ეტყვის თავის მამას ან დედას: ღმერთს ვწირავ იმას, რითაც შემეძლო შენ შეგწეოდი, -" },
  { verse: 6, text: "პატივს არა სცემს არც მამას და არც დედას; და ამრიგად, თქვენი ჩვეულებით არღვევთ ღმრთის მცნებას." },
  { verse: 7, text: "თვალთმაქცნო, მართლად იწინასწარმეტყველა თქვენთვის ესაიამ, რომელმაც თქვა:" },
  { verse: 8, text: "ეს ხალხი მადიდებს თავისი ბაგით, მაგრამ მისი გული შორსაა ჩემგან." },
  { verse: 9, text: "ამაოდ მადიდებენ, რადგან ასწავლიან ადამიანურ მოძღვრებებსა და მცნებებს." },
  { verse: 10, text: "მოუხმო ხალხს და უთხრა: ისმინეთ და შეიმეცნეთ:" },
  { verse: 11, text: "პირით შემავალი კი არ შებილწავს კაცს, არამედ პირიდან გამომავალია ის, რაც ბილწავს კაცს." },
  { verse: 12, text: "მაშინ მიუახლოვდნენ მისი მოწაფეები და უთხრეს: თუ იცი, რომ ფარისევლები ამ სიტყვის მოსმენით შეცდნენ?" },
  { verse: 13, text: "ხოლო მან პასუხად თქვა: ყოველი ნერგი, რომელიც არ დაურგავს ჩემს ზეციერ მამას, ძირფესვიანად აღმოიფხვრება." },
  { verse: 14, text: "მოეშვით მათ: ბრმები არიან და ბრმებისვე წინამძღოლნი; ხოლო თუ ბრმა წინ უძღვის ბრმას, ორივენი ორმოში ჩაცვივიან." },
  { verse: 15, text: "მიუგო პეტრემ და უთხრა მას: განგვიმარტე ეს იგავი." },
  { verse: 16, text: "ბოლო იესომ თქვა: ნუთუ თქვენც არა გაგეგებათ რა?" },
  { verse: 17, text: "ნუთუ არ გესმით, რომ ყველაფერი, რაც პირით შევა, მუცელს გაივლის და გარეთ გამოვა." },
  { verse: 18, text: "ხოლო პირით გამომავალი გულიდან გამოდის და სწორედ ის ბილწავს კაცს." },
  { verse: 19, text: "ვინაიდან გულიდან გამოვლენ: უკეთური ზრახვანი, კაცისკვლანი, მრუშობანი, სიძვანი, პარვანი, ცილისწამებანი, გმობანი;" },
  { verse: 20, text: "ესენი არიან კაცის შემბილწველნი, ხოლო ხელდაუბანლად ჭამა არ ბილწავს კაცს." },
  { verse: 21, text: "წამოვიდა იქიდან იესო, და მივიდა ტიროსისა და სიდონის მხარეს." },
  { verse: 22, text: "და აჰა, ერთი ქანაანელი ქალი, იმ საზღვრებიდან გამოსული, მიჰყვიროდა მას და ამბობდა: შემიწყალე მე, უფალო, დავითის ძეო: ჩემი ასული საშინლად იტანჯება ეშმაკისაგან." },
  { verse: 23, text: "ხოლო მან ხმა არ გასცა. მიადგნენ მისი მოწაფეები და სთხოვეს: გაუშვი ეგ, რადგანაც ჩვენ მოგვყვირის." },
  { verse: 24, text: "ხოლო მან პასუხად თქვა: სხვას როდი მოვვლენივარ, არამედ მხოლოდ ისრაელის სახლის დაღუპულ ცხვრებს." },
  { verse: 25, text: "ამასობაში ქალიც მოვიდა, თაყვანი სცა და უთხრა: უფალო, შემეწიე მე!" },
  { verse: 26, text: "ხოლო მან პასუხად თქვა: არ ვარგა, შვილებს წაართვა და ძაღლებს მიუგდო პური." },
  { verse: 27, text: "ქალმა კი უთხრა: დიახ, უფალო, მაგრამ ძაღლებიც ხომ ჭამენ პატრონის ტაბლიდან დაცვენილ ნასუფრალს." },
  { verse: 28, text: "მაშინ იესომ პასუხად მიუგო მას: ეჰა, ქალო! დიდია შენი რწმენა, და შენი სურვილისამებრ მოგეგოს შენ! და განიკურნა მისი ასული იმავე წამს." },
  { verse: 29, text: "წამოვიდა იქიდან იესო, მივიდა გალილეის ზღვის პირას, მთაზე ავიდა და იქ დაჯდა." },
  { verse: 30, text: "და მივიდა მასთან დიდძალი ხალხი, თან მოიყოლეს კოჭლნი, ბრმანი, ყრუნი, საპყარნი და სხვანიც მრავალნი, ფერხთით დაუსხეს იესოს და მანაც განკურნა ისინი;" },
  { verse: 31, text: "ასე რომ, უკვირდა ხალხს, როცა ხედავდა, რომ ლაპარაკობდნენ მუნჯნი, იკურნებოდნენ საპყარნი, დადიოდნენ კოჭლნი და ხედავდნენ ბრმანი: და ადიდებდნენ ისრაელის ღმერთს." },
  { verse: 32, text: "ხოლო იესომ მოუხმო თავის მოწაფეებს და უთხრა: მეცოდება ეს ხალხი, რადგან უკვე სამი დღეა ჩემთან არიან და არაფერი აქვთ საჭმელი. არ მინდა, უზმოდ გავუშვა ისინი, რათა არ დაუძლურდნენ გზაში." },
  { verse: 33, text: "უთხრეს მას მოწაფეებმა: სადა გვაქვს ამ უდაბნოში იმდენი პური, რომ მთელი ხალხი დავაპუროთ?" },
  { verse: 34, text: "ჰკითხა მათ იესომ: მაინც რამდენი პური გაქვთ? და მათ მიუგეს: შვიდი, და ცოტაოდენი თევზი." },
  { verse: 35, text: "მაშინ მიწაზე დასხდომა უბრძანა ხალხს." },
  { verse: 36, text: "აიღო შვიდი პური და თევზი, მადლი შესწირა, დატეხა და მისცა თავის მოწაფეებს, ხოლო მოწაფეებმა - ხალხს." },
  { verse: 37, text: "ყველამ ჭამა და გაძღა. და გაავსეს ნარჩენებით შვიდი კალათი." },
  { verse: 38, text: "ხოლო იყო მჭამელი ოთხი ათასი კაცი, ქალებისა და ბავშვების გარდა." },
  { verse: 39, text: "და გაისტუმრა ხალხი, თვითონ კი ნავში ჩაჯდა და მიადგა მაგდალას საზღვარს." },
],

16: [
  { verse: 1, text: "მიუახლოვდნენ საცდუნებლად ფარისეველნი და სადუკეველნი და სთხოვეს, ზეცით სასწაული ეჩვენებინა მათთვის." },
  { verse: 2, text: "ხოლო მან მიუგო და უთხრა მათ: საღამოს ამბობთ: ხვალ დარი იქნება, ვინაიდან ცა წითელია." },
  { verse: 3, text: "დილით კი ამბობთ: დღეს გაავდრდება, ვინაიდან ცა მოქუფრულია. თვალთმაქცნო, ცის ფერს არჩევთ, დროის ნიშანთა გარჩევა კი არ შეგიძლიათ." },
  { verse: 4, text: "უკეთური და მემრუშე მოდგმა სასწაულს ეძებს: მაგრამ სასწაული არ მიეცემა მას, გარდა იონა წინასწარმეტყველის სასწაულისა. მიატოვა ისინი და წავიდა." },
  { verse: 5, text: "ხოლო მის მოწაფეებს, გაღმა გასვლისას, დაავიწყდათ პურის წაღება." },
  { verse: 6, text: "იესომ უთხრა მათ: ფხიზლად იყავით, ერიდეთ ფარისეველთა და სადუკეველთა საფუარს." },
  { verse: 7, text: "ისინი კი გულში ფიქრობდნენ: ალბათ, იმიტომ გვეუბნება, პურის წამოღება რომ დაგვავიწყდაო." },
  { verse: 8, text: "მიუხვდა იესო და უთხრა მათ: რას ფიქრობთ, მცირედ მორწმუნენო: პურის წამოღება დაგვავიწყდაო?" },
  { verse: 9, text: "ნუთუ არ გესმით, ან არ გახსოვთ ხუთი პურით ხუთი ათასი კაცის პურობა, და რამდენი კალათი დაავსეთ კიდევ?" },
  { verse: 10, text: "არც შვიდი პურით ოთხი ათასი კაცის პურობა, და რამდენი კალათი დაავსეთ კიდევ?" },
  { verse: 11, text: "ნუთუ არ გესმით, რომ პურის გამო როდი მითქვამს: ერიდეთ ფარისეველთა და სადუკეველთა საფუარს-მეთქი?" },
  { verse: 12, text: "მაშინღა მიხვდნენ, რომ ის აფრთხილებდა მათ, მორიდებოდნენ არა ცომის საფუარს, არამედ ფარისეველთა და სადუკეველთა მოძღვრებას." },
  { verse: 13, text: "ხოლო როდესაც ფილიპეს კესარიის მხარეს მივიდა, იესომ ჰკითხა თავის მოწაფეებს: რას ამბობს ხალხი, ვინ არისო ძე კაცისა?" },
  { verse: 14, text: "მათ მიუგეს: ზოგს იოანე ნათლისმცემელი ჰგონიხარ, ზოგს - ელია, ზოგს - იერემია თუ ერთ-ერთი წინასწარმეტყველი." },
  { verse: 15, text: "კვლავ ჰკითხა მათ: თქვენ თვითონ ვინღა გგონივართ მე?" },
  { verse: 16, text: "სიმონმა, იმავე პეტრემ, მიუგო: შენა ხარ ქრისტე, ძე ცოცხალი ღმრთისა." },
  { verse: 17, text: "ხოლო იესომ პასუხად თქვა: ნეტარი ხარ შენ, სიმონ, იონას ძეო, რადგან ხორცმა და სისხლმა კი არ გაგიცხადა ეს, არამედ ჩემმა ზეციერმა მამამ." },
  { verse: 18, text: "და მე გეუბნები: შენა ხარ კლდე, და ამ კლდეზე ავაშენებ ჩემს ეკლესიას, და ჯოჯოხეთის ბჭენი ვერ სძლევენ მას." },
  { verse: 19, text: "მოგცემ შენ ცათა სასუფევლის გასაღებს, და რასაც შეკრავ მიწაზე, შეკრული იქნება ცაშიც, ხოლო რასაც დახსნი მიწაზე, დახსნილი იქნება ცაშიც." },
  { verse: 20, text: "მაშინ უბრძანა თავის მოწაფეებს, არავისთან გაეთქვათ, რომ ის არის იესო ქრისტე." },
  { verse: 21, text: "მას აქეთ დაიწყო იესომ თავისი მოწაფეებისთვის იმის გამხელა, რომ უნდა წასულიყო იერუსალიმს, დაეთმინა მრავალი ტანჯვა უხუცესთა, მღვდელმთავართა და მწიგნობართაგან, სასიკვდილოდ მიეცა თავი, და აღმდგარიყო მესამე დღეს." },
  { verse: 22, text: "მაშინ გაიხმო იგი პეტრემ, კიცხვა დაუწყო და უთხრა: შორს შენგან, უფალო; ღმერთმა ნუ ქნას ეგ!" },
  { verse: 23, text: "ხოლო ის მიუბრუნდა პეტრეს და უთხრა: გამშორდი, სატანა! ჩემი საცთური ხარ! რადგან ღმერთისას კი არ ფიქრობ, არამედ კაცისას." },
  { verse: 24, text: "მაშინ უთხრა იესომ თავის მოწაფეებს: ვისაც სურს მე მომდიოს, განუდგეს თავის თავს, აიღოს თავისი ჯვარი, და გამომყვეს მე." },
  { verse: 25, text: "რადგან ვისაც სურს სულის ხსნა, დაჰკარგავს მას: და ვინც ჩემი გულისთვის დაჰკარგავს სულს, ის ჰპოვებს მას." },
  { verse: 26, text: "რას გამორჩება კაცი, თუ მოიგებს მთელს ქვეყანას და სულს კი წააგებს? ანდა რას მისცემს კაცი თავისი სულის სანაცვლოდ?" },
  { verse: 27, text: "რადგან მოვა ძე კაცისა მამის თვისის დიდებითა და თავის ანგელოზთა თანხლებით, და მისი საქმისამებრ მიაგებს თვითეულს." },
  { verse: 28, text: "ჭეშმარიტად გეუბნებით თქვენ: ზოგი აქ მყოფთაგანი არ იგემებს სიკვდილს, სანამ არ იხილავს ძეს კაცისას, მომავალს თავის სასუფეველში." },
],

17: [
  { verse: 1, text: "ექვსი დღის შემდეგ წაიყვანა იესომ პეტრე, იაკობი და მისი ძმა იოანე, და მაღალ მთაზე აიყვანა ისინი განმარტოებით." },
  { verse: 2, text: "და იცვალა მათ წინაშე ფერი, და გაბრწყინდა მისი სახე, როგორც მზე, და გათეთრდა მისი სამოსი, როგორც ნათელი." },
  { verse: 3, text: "და, აჰა, მოევლინენ მათ მოსე და ელია, იესოსთან მოსაუბრენი." },
  { verse: 4, text: "და უთხრა პეტრემ იესოს: უფალო, რა გვიჯობს აქ ყოფნას? თუ გნებავს, გაგიკეთებთ სამ კარავს: ერთს შენ, ერთს მოსეს და ერთსაც ელიას." },
  { verse: 5, text: "სიტყვის დასრულება ვერც კი მოასწრო, რომ, აჰა, ნათელმა ღრუბელმა ჩრდილით დაბურა ისინი. და გაისმა ხმა ღრუბლით რომელმაც თქვა: ეს არის ძე ჩემი საყვარელი, რომელიც შევიტკბე მე. მას უსმინეთ." },
  { verse: 6, text: "ეს რომ ჩაესმათ მოწაფეებს შეძრწუნებულნი პირქვე დაემხნენ." },
  { verse: 7, text: "მაგრამ მივიდა იესო, ხელი შეახო მათ და უთხრა: ადექით, ნუ გეშინიათ." },
  { verse: 8, text: "და როცა ზე აიხედეს, ვერავინ დაინახეს, იესოს გარდა." },
  { verse: 9, text: "ხოლო მთიდან ჩამოსვლისას იესომ უბრძანა და უთხრა მათ: ნურავის გაანდობთ ამ ხილვას, ვიდრე ძე კაცისა არ აღდგება მკვდრეთით." },
  { verse: 10, text: "ჰკითხეს მას მოწაფეებმა და უთხრეს: რატომ ამბობენ მწიგნობარნი, პირველად ელია უნდა მოვიდესო?" },
  { verse: 11, text: "ხოლო მან პასუხად თქვა: ელია მართლაც პირველად მოვა და აღადგენს ყოველს;" },
  { verse: 12, text: "მაგრამ გეუბნებით თქვენ: ელია უკვე მოვიდა, და ვერ იცნეს იგი, არამედ როგორც უნდოდათ, ისე მოექცნენ. იგივე ტანჯვა ელის მათგან კაცის ძესაც." },
  { verse: 13, text: "მაშინ მიხვდნენ მოწაფეები, რომ იოანე ნათლისმცემელზე ელაპარაკებოდა მათ." },
  { verse: 14, text: "როდესაც ხალხთან მივიდნენ, ერთი კაცი მიუახლოვდა, მუხლი მოიყარა მის წინაშე" },
  { verse: 15, text: "და უთხრა: უფალო! შეიწყალე ჩემი ძე: მთვარეულია და საშინლად იტანჯება, ვინაიდან ხშირად ცეცხლში და ხშირად კიდევ წყალში ვარდება." },
  { verse: 16, text: "მივუყვანე შენს მოწაფეებს, მაგრამ ვერ განკურნეს იგი." },
  { verse: 17, text: "ხოლო იესომ პასუხად თქვა: ო, ურწმუნო და უკუღმართო მოდგმავ: როდემდის ვიქნები თქვენთან? როდემდის მოგითმენთ თქვენ? აქ მომგვარეთ." },
  { verse: 18, text: "შერისხა იგი იესომ და გავიდა ეშმაკი მისგან: და განიკურნა ყმაწვილი იმავე წამს." },
  { verse: 19, text: "მაშინ მოწაფეებმა დაიმარტოხელეს იესო და ჰკითხეს: რატომ ჩვენ ვერ შევძელით მისი განდევნა?" },
  { verse: 20, text: "ხოლო იესომ მიუგო მათ: თქვენი მცირე რწმენის გამო: თუ გექნებათ მდოგვის მარცვლის ოდენა რწმენა, უბრძანეთ ამ მთას: გადაადგილდიო, და ისიც გადაადგილდება, და არაფერი იქნება შეუძლებელი თქვენთვის." },
  { verse: 21, text: "ეს მოდგმა კი მხოლოდ ლოცვითა და მარხვით განიდევნება." },
  { verse: 22, text: "გალილეაში ყოფნისას უთხრა მათ იესომ: ძე კაცისა მიეცემა კაცთა ხელში." },
  { verse: 23, text: "მოკლავენ მას, და მესამე დღეს აღდგება. და დიდად დამწუხრდნენ ისინი." },
  { verse: 24, text: "ხოლო როდესაც მიადგნენ კაპერნაუმს, მივიდნენ პეტრესთან დიდრაქმის ამკრებნი და უთხრეს: თქვენი მოძღვარი არ გადაიხდის დიდრაქმას?" },
  { verse: 25, text: "მან მიუგო: დიახ. და როდესაც შევიდა სახლში, იესომ დაასწრო და ჰკითხა: როგორ გგონია, სიმონ? ვისგან კრებენ მიწიერი მეფენი ხარკს და ბეგარას: თავიანთ შვილთაგან თუ უცხოთაგან?" },
  { verse: 26, text: "პეტრემ მიუგო: უცხოთაგან. ხოლო იესომ უთხრა მას: ასე რომ, შვილები თავისუფალნი არიან." },
  { verse: 27, text: "მაგრამ რათა არ ვაცდუნოთ ისინი, წადი ზღვის პირას, ჩააგდე ანკესი, აიღე პირველივე თევზი, რომელსაც დაიჭერ, გაუღე პირი, და შიგ ჰპოვებ სტატირს: მიიტანე და მიეცი მათ ჩემი და შენი სახელით." },
],
18: [
  { verse: 1, text: "იმ ხანად მივიდნენ მოწაფეები იესოსთან და ჰკითხეს: ვინ უფრო დიდია ცათა სასუფეველში?" },
  { verse: 2, text: "იესომ დაუძახა ბავშვს, მათ შორის ჩააყენა" },
  { verse: 3, text: "და თქვა: ჭეშმარიტად გეუბნებით თქვენ: თუ არ მოიქცევით და არ იქნებით, როგორც ბავშვები, ვერ შეხვალთ ცათა სასუფეველში." },
  { verse: 4, text: "ამრიგად, ვინც დაიმდაბლებს თავს, როგორც ეს ბავშვი, ის არის უდიდესი ცათა სასუფეველში." },
  { verse: 5, text: "და ვინც შეიწყნარებს ერთ ამნაირ ბავშვს ჩემი სახელით, მე შემიწყნარებს." },
  { verse: 6, text: "ხოლო ვინც აცდუნებს ერთ ამ მცირეთაგანს, რომელსაც მე ვწამვარ, უჯობს წისქვილის დოლაბი დაჰკიდონ ყელზე და ზღვის უფსკრულში დანთქან." },
  { verse: 7, text: "ვაი ამ ქვეყანას საცდურთაგან, ვინაიდან საცდური გარდუვალია: მაგრამ ვაი იმ კაცს, ვისგანაც მოდის საცდური." },
  { verse: 8, text: "თუ შენი ხელი ანდა შენი ფეხი გაცდუნებს, მოიკვეთე და გადააგდე: გიჯობს უხელოდ ან უფეხოდ შეხვიდე სიცოცხლეში, ვიდრე ორივე ხელით ან ორივე ფეხით ჩავარდე საუკუნო ცეცხლში." },
  { verse: 9, text: "თუ შენი თვალი გაცდუნებს, ამოითხარე და გადააგდე: გიჯობს ცალთვალა შეხვიდე სიცოცხლეში, ვიდრე ორივე თვალის მქონე ჩავარდე ცეცხლის გეენაში." },
  { verse: 10, text: "ეკრძალეთ, ნუ შეურაცხყოფთ ნურცერთ ამ მცირეთაგანს, რადგანაც გეუბნებით თქვენ, რომ მათი ანგელოზები ცაში თვალს არ აშორებენ ჩემი ზეციერი მამის სახეს." },
  { verse: 11, text: "რადგან ძე კაცისა მოვიდა, რათა იხსნას დაკარგულნი." },
  { verse: 12, text: "როგორ გგონიათ, კაცს რომ ასი ცხვარი ჰყავდეს და ერთი მათგანი დაეკარგოს, განა არ მიატოვებს მთაში ოთხმოცდაცხრამეტს, და არ წავა დაკარგულის საძებნად?" },
  { verse: 13, text: "და თუ მოხდა ისე, რომ იპოვა, ჭეშმარიტად გეუბნებით თქვენ, მას უფრო მეტად შეჰხარის, ვიდრე იმ ოთხმოცდაცხრამეტს, რომლებიც არ დაჰკარგვია." },
  { verse: 14, text: "ასევე არ ნებავს ჩემს ზეციერ მამას, რომ დაიღუპოს ერთი ამ მცირეთაგანი." },
  { verse: 15, text: "ხოლო თუ შენი ძმა შესცოდავს შენს მიმართ, მიდი და ამხილე, როცა მარტო იქნებით ორივენი; თუ შეისმინა შენი, შეგიძენია ძმა შენი." },
  { verse: 16, text: "ხოლო თუ არ შეისმინა, მიიყვანე ერთი ან ორი კაცი, რათა ორი თუ სამი მოწმის პირით დადასტურდეს ყოველი სიტყვა." },
  { verse: 17, text: "და თუ არც მათსას შეისმენს, უთხარი ეკლესიას; ხოლო თუ არც ეკლესიისას შეისმენს, მაშინ იქნება იგი შენთვის როგორც მებაჟე ან წარმართი." },
  { verse: 18, text: "ჭეშმარიტად გეუბნებით თქვენ: რასაც შეკრავთ მიწაზე, შეკრული იქნება ცაშიც, და რასაც დახსნით მიწაზე, დახსნილი იქნება ცაშიც." },
  { verse: 19, text: "კვლავ ჭეშმარიტად გეუბნებით თქვენ: თუ ორი თქვენგანი შეთანხმდება ამ ქვეყნად და ერთად ითხოვს რასმე, მაშინ, რასაც უნდა ითხოვდნენ, მიეცემათ ჩემი ზეციერი მამისგან." },
  { verse: 20, text: "რადგან სადაც ორი თუ სამი შეიყრება ჩემი სახელით, მეც იქვე ვარ, მათ შორის." },
  { verse: 21, text: "მაშინ მიუახლოვდა მას პეტრე და უთხრა: უფალო, რამდენჯერ მივუტევო ჩემს ძმას, რომელიც ჩემს წინააღმდეგ სცოდავს? შვიდჯერ?" },
  { verse: 22, text: "იესომ მიუგო: არ გეუბნები: შვიდჯერ-მეთქი, არამედ სამოცდაათგზის შვიდჯერ." },
  { verse: 23, text: "ამითა ჰგავს ცათა სასუფეველი მეფეს, რომელმაც გადაწყვიტა ანგარიში გაესწორებინა თავისი მონებისათვის." },
  { verse: 24, text: "და როცა ანგარიშსწორება დაიწყო, წარუდგინეს მას ერთი, რომელსაც მისი ათი ათასი ტალანტი ემართა." },
  { verse: 25, text: "და რაკი გადახდის თავი არ ჰქონდა, მისმა მეფემ ბრძანა, გაეყიდათ ისიც, მისი ცოლიც, მისი შვილებიც, მთელი მისი სარჩო-საბადებელიც და ვალი დაეფარათ." },
  { verse: 26, text: "დაემხო მონა, თაყვანი სცა და უთხრა: შემიბრალე, მეფეო, და მთელ ვალს გადაგიხდი." },
  { verse: 27, text: "შეიბრალა მეფემ თავისი მონა, გაუშვა და ვალიც აპატია." },
  { verse: 28, text: "მაგრამ წავიდა ეს მონა და ერთ თავის ამხანაგს შეხვდა, რომელსაც მისი ასი დინარი ემართა: ყელში სწვდა, დახრჩობა დაუპირა და შესძახა: ჩემი ვალი დამიბრუნეო." },
  { verse: 29, text: "ამხანაგი ფეხებში ჩაუვარდა და შეევედრა: ცოტაც მაცალე და მთელ ვალს გაგისტუმრებო." },
  { verse: 30, text: "მაგრამ მან ყური არ ათხოვა, არამედ წავიდა და, ვალის გადახდამდე, ციხეში ჩააგდებინა იგი." },
  { verse: 31, text: "ეს რომ მისმა ამხანაგებმა დაინახეს, ძალიან შეწუხდნენ, წავიდნენ და მეფეს მოახსენეს ყველაფერი, რაც მოხდა." },
  { verse: 32, text: "მაშინ მეფემ დაიბარა მონა და უთხრა: შე ბოროტო, მთელი ვალი გაპატიე, რაკიღა მთხოვე." },
  { verse: 33, text: "ნუთუ არა გმართებდა, ისევე შეგებრალებინა შენი ამხანაგი, როგორც მე შეგიბრალე შენ?" },
  { verse: 34, text: "განრისხდა მეფე და მტანჯველებს მისცა ხელში, ვიდრე არ გადაიხდიდა მთელ თავის ვალს." },
  { verse: 35, text: "ასევე მოგექცევათ ჩემი ზეციერი მამა, თუ მთელი გულით არ მიუტევებთ თქვენს ძმას მის შეცოდებებს." },
],

19: [
  { verse: 1, text: "როცა იესომ დაასრულა ეს სიტყვები, წამოვიდა გალილეიდან და მივიღა იუდეის მხარეში, იორდანეს გაღმა." },
  { verse: 2, text: "თან მისდევდა დიდძალი ხალხი, და იქ განკურნა ისინი." },
  { verse: 3, text: "მაშინ საცდუნებლად მიუახლოვდნენ ფარისევლები და უთხრეს: აქვს თუ არა ნება კაცს, ყოველგვარი მიზეზით გაუშვას ცოლი?" },
  { verse: 4, text: "ხოლო მან მიუგო და უთხრა მათ: არ წაგიკითხავთ, რომ შემოქმედმა დასაბამიდან კაცად და ქალად შექმნა ისინი?" },
  { verse: 5, text: "და თქვა: ამიტომ მიატოვებს კაცი თავის დედ-მამას, შეერთვის თავის ცოლს, და იქნებიან ორივენი ერთ ხორც." },
  { verse: 6, text: "ასე რომ, ორნი კი აღარ არიან, არამედ ერთ ხორც. ამრიგად, ვინც ღმერთმა შეაუღლა, დაე, ნუ განაშორებს კაცი." },
  { verse: 7, text: "კვლავ უთხრეს მას: მაშინ რატომღა გვამცნო მოსემ გაყრის წერილის მიცემა და ცოლთან გაყრა?" },
  { verse: 8, text: "მიუგო მათ: მოსემ თქვენი გულქვაობის გამო მოგცათ ცოლებთან გაყრის ნება, თავიდან კი არ იყო ასე." },
  { verse: 9, text: "ხოლო მე გეუბნებით თქვენ: ვინც გაეყრება თავის ცოლს, სიძვის მიზეზის გარეშე, და სხვას შეირთავს, მრუშობს; და ვინც განაშვებს შეირთავს, აგრეთვე მრუშობს." },
  { verse: 10, text: "უთხრეს მას მოწაფეებმა: თუ კაცს ამდენი რამ მართებს ცოლის მიმართ, უმჯობესია სულაც არ შეირთოს." },
  { verse: 11, text: "ხოლო იესომ პასუხად თქვა: ყველას როდი შეუძლია ამ სიტყვის წვდომა, არამედ მხოლოდ იმათ, ვისაც მიეცა." },
  { verse: 12, text: "ვინაიდან არიან საჭურისნი, რომელნიც დედის საშოდანვე ასე იშვნენ; არიან საჭურისნი, რომელნიც კაცთაგან დასაჭურისდნენ; და არიან საჭურისნი, რომელთაც თავად დაისაჭურისეს თავი ცათა სასუფევლის გულისთვის. ვისაც წვდომის თავი აქვს, ჩასწვდეს." },
  { verse: 13, text: "მაშინ მიჰგვარეს მას ბავშვები, რათა ხელი დაედო და დაელოცა ისინი, მოწაფეები კი უშლიდნენ მათ." },
  { verse: 14, text: "ხოლო იესომ თქვა: აცადეთ ბავშვებს და ნუ უშლით ჩემთან მოსვლას, ვინაიდან მაგისთანებისაა ცათა სასუფეველი." },
  { verse: 15, text: "დაადო ხელი და წავიდა იქიდან." },
  { verse: 16, text: "და, აჰა, ვიღაც მიუახლოვდა და უთხრა: კეთილო მოძღვარო, რა სიკეთე ვქნა, რომ საუკუნო სიცოცხლე მქონდეს?" },
  { verse: 17, text: "ხოლო მან მიუგო: რად მეკითხები სიკეთის გამო? არავინაა კეთილი, გარდა ერთის - ღმერთისა, ხოლო თუ გსურს შეხვიდე სიცოცხლეში, დაიცავი მცნებანი." },
  { verse: 18, text: "უთხრა მას: რომელნი? ხოლო იესომ მიუგო მას: არა კაც-ჰკლა; არა იმრუშო; არა იპარო; არა ცილი სწამო;" },
  { verse: 19, text: "პატივი ეცი მამას შენსას და დედას; და შეიყვარე მოყვასი შენი, როგორც თავი შენი." },
  { verse: 20, text: "უთხრა მას ჭაბუკმა: ეს ყოველივე დამიცავს ჩემი სიყრმიდან; რაღა მაკლია კიდევ?" },
  { verse: 21, text: "იესომ მიუგო მას: თუ გინდა, რომ სრულქმნილი იყო, წადი, გაყიდე, რაც გაბადია, მიეცი გლახაკთ, და გექნება საუნჯე ცაში; მერე მოდი და გამომყევ მე." },
  { verse: 22, text: "ეს სიტყვა რომ მოისმინა, ჭაბუკი დაღონებული წავიდა, რადგანაც ძალიან მდიდარი იყო." },
  { verse: 23, text: "ხოლო იესომ თავის მოწაფეებს უთხრა: ჭეშმარიტად გეუბნებით თქვენ: მდიდარი ძნელად თუ შევა ცათა სასუფეველში." },
  { verse: 24, text: "ამასაც გეუბნებით თქვენ: აქლემი უფრო ადვილად გაძვრება ნემსის ყუნწში, ვიდრე მდიდარი შევა ღვთის სასუფეველში." },
  { verse: 25, text: "ეს რომ მოისმინეს, მოწაფეები ძალზე განცვიფრდნენ და თქვეს: კი მაგრამ, ვინღა ცხონდება." },
  { verse: 26, text: "შეხედა იესომ და უთხრა მათ: ეს შეუძლებელია კაცთათვის, ღმერთისთვის კი ყველაფერი შესაძლებელია." },
  { verse: 27, text: "მაშინ პეტრემ მიუგო და უთხრა მას: აი, ჩვენ მივატოვეთ ყველაფერი და გამოგყევით; რა გვექნება ჩვენ?" },
  { verse: 28, text: "ხოლო იესომ მიუგო მათ: ჭეშმარიგად გეუბნებით, რომ ვინც მე გამომყევით, მეორედ შობისას, როცა ძე კაცისა დაჯდება თავისი დიდების ტახტზე, - ერთად დასხდებით თორმეტ ტახტზე ისრაელის თორმეტი ტომის განსჯად." },
  { verse: 29, text: "და ყველა, ვინც მიატოვებს თავის სახლს, ან თავის და-ძმას, თავის ცოლ-შვილს თუ დედ-მამას, ანდა თავის ადგილ-მამულს ჩემი სახელის გულისთვის, ასმაგად მიიღებს საზღაურს და საუკუნო სიცოცსლეს დაიმკვიდრებს." },
  { verse: 30, text: "მაგრამ მრავალი პირველი იქნება უკანასკნელი, და უკანასკნელი - პირველი." },
],

20: [
  { verse: 1, text: "ვინაიდან მსგავსია ცათა სასუფეველი ოჯახის პატრონისა, რომელიც გამოვიდა დილაუთენია, რათა თავის ვენახში სამუშაოდ დაექირავებინა მუშები." },
  { verse: 2, text: "დღეში თითო დინარად გაურიგდა მათ და თავის ვენახში გაგზავნა ისინი." },
  { verse: 3, text: "მერე გამოვიდა დაახლოებით სამ საათზე, და დაინანა მოედანზე უქმად მდგომი სხვა მუშები." },
  { verse: 4, text: "და უთხრა მათ: წადით თქვენც ჩემს ვენახში, და რაც გერგებათ, მოგცემთ." },
  { verse: 5, text: "ისინიც წავიდნენ. და კვლავ გამოვიდა მეექვსე და მეცხრე საათს და ასევე მოიქცა." },
  { verse: 6, text: "ბოლოს, გამოვიდა ასე თერთმეტ საათზე, დაინახა უქმად მდგომი სხვა მუშები, და უთხრა მათ: რატომ დგახართ მთელი დღე ასე უქმად?" },
  { verse: 7, text: "მათ უთხრეს: იმიტომ, რომ არავინ დაგვიქირავა, ხოლო მან თქვა: წადით თქვენც ჩემს ვენახში, და რაც გერგებათ, მოგცემთ." },
  { verse: 8, text: "რომ მოსაღამოვდა, ვენახის პატრონმა თავის მოურავს უთხრა: დაუძახე მუშებს და მიეცი საზღაური, უკანასკნელთაგან მოყოლებული პირველებამდე." },
  { verse: 9, text: "მოვიდნენ თერთმეტზე დაქირავებულნი, და მიიღეს თითო დინარი." },
  { verse: 10, text: "მოვიდნენ პირველნიც და ეგონათ, უფრო მეტი მოგვიწევსო, მაგრამ მათაც თითო დინარი მიიღეს." },
  { verse: 11, text: "და როცა მიიღეს, ყვედრება დაუწყეს ვენახის პატრონს" },
  { verse: 12, text: "და თქვეს: ეს უკანასკნელნი მხოლოდ ერთ საათს მუშაობდნენ და ჩვენ კი გაგვითანაბრე, რომელთაც ვიტვირთეთ სიმძიმე დღისა და სიცხე." },
  { verse: 13, text: "ხოლო მან პასუხად უთხრა ერთ მათგანს: მეგობარო, უსამართლოდ არ მოგქცევივარ: განა ერთ დინარად არ მომირიგდი?" },
  { verse: 14, text: "მიიღე შენი და წადი: მე მინდა, ამ უკანასკნელსაც იგივე მივცე, რაც შენ." },
  { verse: 15, text: "იქნებ ნება არა მაქვს, როგორც მსურს, ისე მოვექცე ჩემსას? ან იქნებ შენი თვალია უკეთური, იმიტომ, რომ მე ვარ კეთილი?" },
  { verse: 16, text: "ასე იქნებიან უკანასკნელნი - პირველნი, და პირველნი - უკანასკნელნი, ვინაიდან მრავალნი არიან ხმობილნი და მცირედნი - რჩეულნი." },
  { verse: 17, text: "და როცა ადიოდა იერუსალიმს, იესომ ცალკე გაიხმო გზაში თავისი თორმეტი მოწაფე და უთხრა მათ:" },
  { verse: 18, text: "აჰა, ავდივართ იერუსალიმს, და ძე კაცისა მიეცემა მღვდელმთავრებსა და მწიგნობრებს, და მიუსჯიან მას სიკვდილს;" },
  { verse: 19, text: "და საგინებლად, საგვემად და ჯვარზე საცმელად მისცემენ მას წარმართთ: და აღდგება მესამე დღეს." },
  { verse: 20, text: "მაშინ ზებედეს ძეთა დედა თავისი ვაჟებითურთ მიეახლა მას, თაყვანს სცემდა და რაღაცას ევედრებოდა." },
  { verse: 21, text: "მან უთხრა: რა გსურს? ხოლო ქალმა მიუგო მას: თქვი, რომ ეს ჩემი ორი ძე შენს სასუფეველში ერთი შენს მარჯვნივ, მეორე კი შენს მარცხნივ დაჯდეს." },
  { verse: 22, text: "იესომ პასუხად თქვა: არ იცით, რას ითხოვთ. შეგიძლიათ შესვათ სასმისი, რომელიც მე უნდა შევსვა? მათ თქვეს: შეგვიძლია." },
  { verse: 23, text: "ხოლო იესომ უთხრა მათ: ჩემს სასმისს შესვამთ, მაგრამ მე როდი მომეცა, თუ ვინ დაჯდება ჩემს მარჯვნივ და მარცხნივ, არამედ ვისთვისაც ეს გამზადებულია ჩემი მამის მიერ." },
  { verse: 24, text: "ამის მოსმენისას ათი მოწაფე რისხვით აღივსო ორივე ძმის მიმართ." },
  { verse: 25, text: "ხოლო იესომ მიიხმო ისინი და უთხრა: თქვენ იცით, რომ ხალხთა მთავარნი მბრძანებლობენ მათზე, და დიდებულნი განაგებენ მათ." },
  { verse: 26, text: "ხოლო თქვენს შორის ნუ იქნება ასე, არამედ ვინც თქვენში მოისურვებს უფროსობას, თქვენს მსახურად იქცეს." },
  { verse: 27, text: "და ვინც თქვენს შორის მოისურვებს პირველობას, თქვენს მონად იქცეს." },
  { verse: 28, text: "რადგან ძე კაცისა იმისთვის კი არ მოვიდა, რომ სხვები იმსახუროს, არამედ რათა სხვებს ემსახუროს და მრავალთა სახსნელად მისცეს თავისი სული." },
  { verse: 29, text: "როდესაც გამოვიდნენ იერიხონიდან, მისდევდა მას დიდძალი ხალხი." },
  { verse: 30, text: "და აჰა, ორი ბრმა იჯდა გზის პირას, და როდესაც გაიგონეს, იესო მოდისო, აყვირდნენ და თქვეს: შეგვიწყალე ჩვენ, უფალო, დავითის ძეო!" },
  { verse: 31, text: "ხოლო ხალხი ტუქსავდა მათ და აჩუმებდა. ისინი კი უფრო ხმამაღლა ყვიროდნენ: შეგვიწყალე ჩვენ, უფალო, დავითის ძეო!" },
  { verse: 32, text: "იესო შეჩერდა, მიიხმო ისინი და უთხრა: რას მოითხოვთ ჩემგან?" },
  { verse: 33, text: "მათ მიუგეს: თვალის ახელას, უფალო." },
  { verse: 34, text: "შეებრალა ისინი იესოს და შეეხო მათ თვალებს; იმ წამსვე აეხილათ თვალი და გაჰყვნენ მას." },
],

21: [
  { verse: 1, text: "როცა მიუახლოვდნენ იერუსალიმს, და მიადგნენ ბეთბაგეში ზეთისხილის მთას, გაგზავნა იესომ ორი მოწაფე." },
  { verse: 2, text: "და უთხრა მათ: წადით სოფელში, რომელიც თქვენს პირდაპირაა, და ხელად იპოვით დაბმულ ვირსა და მის ჩოჩორს: ახსენით და მომიყვანეთ." },
  { verse: 3, text: "ხოლო თუ ვინმე რაიმეს გეტყვით, უთხარით, უფალს სჭირდება-თქო, და მაშინვე გამოგატანთ." },
  { verse: 4, text: "ყოველივე ეს იქმნა, რათა აღსრულდეს წინასწარმეტყველის მიერ თქმული, რომელიც ამბობს:" },
  { verse: 5, text: "უთხარით სიონის ასულს: აჰა, გიახლოვდება შენი მშვიდი მეუფე, ვირსა და ჩოჩორზე, სახედრის ნაშიერზე, მჯდარი." },
  { verse: 6, text: "მოწაფეები წავიდნენ და ისე მოიქცნენ, როგორც უბრძანა მათ იესომ." },
  { verse: 7, text: "მოჰგვარეს ვირი და ჩოჩორი, ზედ დაუფინეს თავიანთი სამოსი, და შეჯდა მათზე." },
  { verse: 8, text: "დიდძალი ხალხი თავის სამოსელს უფენდა გზაზე: სხვები კი ხის ტოტებს ჭრიდნენ და გზაზე უფენდნენ." },
  { verse: 9, text: "ხოლო ხალხი, წინ რომ უძღოდა და უკანაც მისდევდა მას, ღაღადებდა და ამბობდა: ოსანა დავითის ძეს! კურთხეულია მომავალი უფლის სახელით! ოსანა მაღალთა შინა!" },
  { verse: 10, text: "როცა შევიდა იერუსალიმში, მთელი ქალაქი შეიძრა, და ამბობდნენ: ვინ არის ეს?" },
  { verse: 11, text: "ხალხი კი ამბობდა: ეს არის იესო, წინასწარმეტყველი, გალილეის ნაზარეთიდან." },
  { verse: 12, text: "შევიდა იესო ტაძარში, და გამოყარა ტაძრიდან ყველა მყიდველი და გამყიდველი, ააყირავა მეკერმეთა ტაბლები და მტრედებით მოვაჭრეთა მერხები." },
  { verse: 13, text: "და უთხრა მათ: დაწერილია: ჩემი სახლი სალოცავ სახლად იწოდება; თქვენ კი ყაჩაღთა ბუნაგად გიქცევიათ იგი." },
  { verse: 14, text: "მიეახლნენ მას ტაძარში ბრმანი და კოჭლნი, და განკურნა ისინი." },
  { verse: 15, text: "როდესაც იხილეს მღვდელმთავრებმა და მწიგნობრებმა მის მიერ ქმნილი სასწაულნი და ტაძარში მოყიჟინე ბალღები, რომლებიც ამბობდნენ: ოსანა დავითის ძეს! - განრისხდნენ." },
  { verse: 16, text: "და უთხრეს მას: გესმის, რას ამბობენ ისინი? ხოლო იესომ მიუგო მათ: დიახ! არასოდეს წაგიკითხავთ: ჩვილთა და მეძუძურთა პირით დაიმკვიდრე დიდება?" },
  { verse: 17, text: "მიატოვა ისინი, ქალაქიდან გაემართა ბეთანიას და იქ გაათია ღამე." },
  { verse: 18, text: "ხოლო დილით ქალაქისკენ მომავალს მოშივდა;" },
  { verse: 19, text: "დაინახა გზის პირას ერთი ლეღვის ხე, და რაკი ზედ ფოთლების მეტი ვერაფერი ნახა, უთხრა მას: აღარასოდეს გამოგეღოს ნაყოფი უკუნისამდე. და მაშინვე გახმა ლეღვის ხე." },
  { verse: 20, text: "ეს რომ იხილეს, გაუკვირდათ მოწაფეებს და თქვეს: რა უცებ გახმა ლეღვის ხე?" },
  { verse: 21, text: "ხოლო იესომ პასუხად უთხრა მათ: ჭეშმარიტად გეუბნებით თქვენ: თუ გექნებათ რწმენა და არ შეეჭვდებით, არა მარტო იმის ქმნას შესძლებთ, რაც დაემართა ლეღვის ხეს, არამედ თუნდაც ამ მთას უბრძანებთ: აღმოიფხვერი მანდედან და ზღვაში ჩავარდიო, და მოხდება აგრე." },
  { verse: 22, text: "და ყველაფერი, რასაც ლოცვაში ითხოვთ რწმენით, მოგეცემათ." },
  { verse: 23, text: "როცა ტაძარში შევიდა საქადაგებლად, მიადგნენ მას მღვდელმთავარნი და ხალხის უხუცესნი და უთხრეს: რომელი ძალით იქმ ამას? ან ვინ მოგცა ეს ძალა?" },
  { verse: 24, text: "იესომ პასუხად მიუგო მათ: მეც ერთ რამეს გკითხავთ, და თუ მიპასუხებთ, გეტყვით, რომელი ძალით ვიქმ ამას:" },
  { verse: 25, text: "ნათლისცემა იოანესი საიდან იყო: ზეციდან თუ კაცთაგან? ხოლო ისინი ერთმანეთში ბჭობდნენ: თუ ვეტყვით: ზეციდანო, ის გვეტყვის: მაშინ რატომ არ ერწმუნეთ მას?" },
  { verse: 26, text: "ხოლო თუ ვეტყვით: კაცთაგანო, - ხალხისა გვეშინია, ვინაიდან ყველას წინასწარმეტყველად მიაჩნია იოანე." },
  { verse: 27, text: "და პასუხად უთხრეს იესოს, არ ვიცითო, და მანაც მიუგო: მაშინ არც მე გეტყვით, რომელი ძალით ვიქმ ამას." },
  { verse: 28, text: "ამაზე რაღას იტყვით? ერთ კაცს ორი ძე ჰყავდა: მივიდა ერთთან და უთხრა: შვილო, წადი დღეს სამუშაოდ ჩემს ვენახში." },
  { verse: 29, text: "ხოლო მან მიუგო: არ მინდა; ბოლოს კი ინანა და წავიდა." },
  { verse: 30, text: "მივიდა მეორესთან და იგივე უთხრა. ხოლო მან მიუგო: წავალ, ბატონო, და არ წავიდა." },
  { verse: 31, text: "ამ ორთაგან რომელმა შეასრულა მამის ნება? მიუგეს: პირველმა. უთხრა მათ იესომ: ჭეშმარიტად გეუბნებით თქვენ: მებაჟენი და მეძავნი თქვენზე წინ შევლენ ღმრთის სასუფეველში." },
  { verse: 32, text: "ვინაიდან მოვიდა თქვენთან იოანე სიმართლის გზით და არ ირწმუნეთ მისი, ხოლო მებაჟენი და მეძავნი ერწმუნენ მას; თქვენ კი იხილეთ, და მაინც არ მოინანიეთ, რათა გერწმუნათ მისი." },
  { verse: 33, text: "სხვა აგავიც მოისმინეთ: იყო ერთი სახლის პატრონი, რომელმაც ჩაყარა ვაზი, ღობე შემოავლო, შიგ საწნანელი ამოკვეთა, ააგო კოშკი და იჯარით მისცა მევენახეებს, თვითონ კი წავიდა." },
  { verse: 34, text: "და როცა რთვლობამ მოაწია, გაგზავნა თავისი მონები მევენახეებთან, რათა მოსავალი ჩაებარებინათ მათგან." },
  { verse: 35, text: "ხოლო მევენახეებმა დაიჭირეს მისი მონები, ზოგი სცემეს, ზოგი დახოცეს, ზოგიც კიდევ ქვებით ჩაქოლეს." },
  { verse: 36, text: "ახლა სხვა მონები გაგზავნა, უწინდელზე მეტნი, და მათაც იგივე დამართეს." },
  { verse: 37, text: "ბოლოს თავისი ძე გაგზავნა და თქვა: ჩემი ძის მაინც მოერიდებათო." },
  { verse: 38, text: "მაგრამ მევენახეებმა მისი ძე რომ დაინახეს, ერთმანეთს უთხრეს: აგერ მემკვიდრე; მოდით, მოვკლათ და მისი სამკვიდრო დავისაკუთროთ." },
  { verse: 39, text: "შეიპყრეს იგი, ვენახიდან გაიყვანეს და მოკლეს." },
  { verse: 40, text: "მერედა, როცა მოვა ვენახის პატრონი, რას უზამს ამ მევენახეებს?" },
  { verse: 41, text: "უთხრეს მას: ბოროტთ ბოროტად მოაკვდინებს, ხოლო ვენახს სხვა მევენახეებს მისცემს, რომლებიც დროულად ჩააბარებენ მოსავალს." },
  { verse: 42, text: "უთხრა მათ იესომ: ნუთუ არასოდეს ამოგიკითხავთ წერილში: ქვა, რომელიც დაიწუნეს მშენებლებმა, კუთხის თავად დაიდვა? უფლის მიერ იქნა ეს, და საოცრებად უჩანს ჩვენს თვალს." },
  { verse: 43, text: "ამიტომაც გეუბნებით თქვენ: წაგერთმევათ ღმრთის სასუფეველი, და მიეცემა ხალხს, რომელიც გამოიღებს მის ნაყოფს." },
  { verse: 44, text: "ვინც ამ ქვაზე დაეცემა, დაიმტვრევა, ხოლო ვისაც იდაეცემა, გასრესს." },
  { verse: 45, text: "როცა მღვდელმთავრებმა და ფარისევლებმა მოისმინეს მისი იგავნი, მიხვდნენ, რომ მათზე ამბობდა ამას." },
  { verse: 46, text: "და უნდოდათ მისი შეპყრობა, მაგრამ ხალხისა შეეშინდათ, ვინაიდან წინასწარმეტყველად მიაჩნდათ იგი." },
],
22: [
  { verse: 1, text: "კვლავ იგავებით მიუგო იესომ და უთხრა მათ:" },
  { verse: 2, text: "ცათა სასუფეველი მსგავსია მეფისა, რომელმაც გამართა თავისი ძის ქორწილი." },
  { verse: 3, text: "და გაგზავნა თავისი მონები ქორწილში წვეულთა საწვევად, მაგრამ არ ინებეს მოსვლა." },
  { verse: 4, text: "კვლავ გაგზავნა სხვა მონები და თქვა: უთხარით წვეულთ: აჰა, გავშალე სუფრა, დავკალი ხარები და ნასუქი საქონელი; ყველაფერი მზადაა, მობრძანდით ქორწილში." },
  { verse: 5, text: "მაგრამ მათ გააწბილეს იგი და წავიდნენ: ვინ თავის ყანაში, ვინ კიდევ თავის სავაჭროში." },
  { verse: 6, text: "დანარჩენებმა კი შეიპყრეს მისი მონები, შეურაცხყვეს და დახოცეს." },
  { verse: 7, text: "ეს რომ გაიგო, განრისხდა მეფე, გაგზავნა თავისი ლაშქარი, ამოაწყვეტინა მკვლელები და გადაწვა მათი ქალაქი." },
  { verse: 8, text: "მაშინ უთხრა თავის მონებს: საქორწინო სუფრა გაშლილია, მაგრამ წვეულნი არ იყვნენ ღირსნი." },
  { verse: 9, text: "მაშ, გადით გზაჯვარედინებზე და ქორწილში მოიწვიეთ ყველა შემხვდური." },
  { verse: 10, text: "გავიდნენ მონები გზაჯვარედინებზე და შეკრიბეს ყველა, ვისაც კი შეხვდნენ, ბოროტი თუ კეთილი, და მეინახეებით აივსო ქორწილი." },
  { verse: 11, text: "შევიდა მეფე მეინახეთა სანახავად და იხილა იქ ერთი კაცი, რომელსაც არ ეცვა საქორწინო სამოსი." },
  { verse: 12, text: "და უთხრა მას: მეგობარო, როგორ შემოხვედი აქ, საქორწინოდ შეუმოსავი? ხოლო ის დუმდა." },
  { verse: 13, text: "მაშინ მეფემ უბრძანა თავის მსახურთ: შეუკარით ხელ-ფეხი და გარეთ გააგდეთ ბნელში. და იქნება იქ ტირილი და კბილთა ღრჭიალი." },
  { verse: 14, text: "ვინაიდან მრავალნი არიან წვეულნი და მცირედნი - რჩეულნი." },
  { verse: 15, text: "მაშინ ფარისევლები წავიდნენ და მოითათბირეს, როგორ დაეჭირათ სიტყვაზე." },
  { verse: 16, text: "ჰეროდელებთან ერთად მიუგზავნეს თავიანთი მოწაფეები და უთხრეს: მოძღვარო, ვიცით, რომ მართალი ხარ, სიმართლით გვასწავლი ღმრთის გზასაც და არც არავის არჩევ, ვინაიდან არ უყურებ სახეს კაცისა." },
  { verse: 17, text: "მაშ, გვითხარი: როგორ გგონია, გვმართებს თუ არა ხარკი ვაძლიოთ კეისარს?" },
  { verse: 18, text: "ხოლო იესო მიუხვდა მათ მზაკვრობას და თქვა: რატომ მაცდუნებთ, თვალთმაქცნო?" },
  { verse: 19, text: "მიჩვენეთ ფული, რომლითაც იხდით ხარკს. და მიართვეს მას დინარი." },
  { verse: 20, text: "და უთხრა მათ: ვისია ეს ხატი და ეს წარწერა?" },
  { verse: 21, text: "მიუგეს: კეისრისა. მაშინ უთხრა მათ: მიაგეთ კეისარს კეისრისა, ხოლო ღმერთს - ღმრთისა." },
  { verse: 22, text: "ეს რომ გაიგონეს, განცვიფრდნენ ისინი, მიატოვეს ის და წავიდნენ." },
  { verse: 23, text: "იმ დღეს მიადგნენ მას სადუკეველნი, რომელნიც ამბობენ, რომ არ არსებობს აღდგომა, და ჰკითხეს:" },
  { verse: 24, text: "მოძღვარო, მოსემ თქვა: თუ კაცი უშვილოდ გადაეგო, დაე, მისმა ძმამ მოიყვანოს მისი ცოლი, რათა აღუდგინოს თავის ძმას მისი თესლი." },
  { verse: 25, text: "იყო ჩვენს შორის შვიდი ძმა: პირველმა ცოლი შეირთო და უშვილოდ მოკვდა, ხოლო ცოლი თავის ძმას დაუტოვა." },
  { verse: 26, text: "ასევე მეორემაც და მესამემაც თვით მეშვიდემდე." },
  { verse: 27, text: "ყველაზე ბოლოს კი ქალიც მოკვდა." },
  { verse: 28, text: "მერედა, აღდგომისას, ამ შვიდთაგან ვისი ცოლი იქნება იგი? ვინაიდან შვიდივეს ცოლად ესვა." },
  { verse: 29, text: "იესომ პასუხად მიუგო მათ: სცდებით, რადგან არც წერილს იცნობთ და არც ღმრთის ძალას." },
  { verse: 30, text: "ვინაიდან აღდგომისას არც ცოლს ირთავენ და არც თხოვდებიან, არამედ არიან როგორც ანგელოზები ცაში." },
  { verse: 31, text: "ხოლო მკვდართა აღდგომისათვის არ წაგიკითხავთ, რა გითხრათ ღმერთმა, რომელიც ამბობს:" },
  { verse: 32, text: "მე ვარ ღმერთი აბრაამისა, ღმერთი ისააკისა და ღმერთი იაკობისა. ღმერთი მკვდრებისა კი არ არის, არამედ - ცოცხლებისა." },
  { verse: 33, text: "ისმენდა ხალხი და უკვირდა მისი მოძღვრება." },
  { verse: 34, text: "ხოლო როდესაც ფარისევლებმა გაიგეს, სადუკეველებს ხმა ჩააკმენდინაო, ერთად შეიკრიბნენ." },
  { verse: 35, text: "და ერთმა მათგანმა, რჯულის მცოდნემ, საცდუნებლად ჰკითხა:" },
  { verse: 36, text: "მოძღვარო, რომელია სჯულის მთავარი მცნება?" },
  { verse: 37, text: "ხოლო იესომ მიუგო მას: გიყვარდეს უფალი ღმერთი შენი მთელი შენი სულით და მთელი შენი გულით და მთელი შენი გონებით." },
  { verse: 38, text: "ეს არის პირველი და მთავარი მცნება." },
  { verse: 39, text: "და მეორე, ამისი მსგავსი: გიყვარდეს მოყვასი შენი, ვითარცა თავი შენი." },
  { verse: 40, text: "ამ ორ მცნებაზეა დამოკიდებული მთელი რჯული და წინასწარმეტყველნი." },
  { verse: 41, text: "ხოლო როდესაც შეიკრიბნენ ფარისეველნი, იესომ ჰკითხა მათ:" },
  { verse: 42, text: "რას იტყვით ქრისტესთვის? ვისი ძე არის იგი? ხოლო მათ მიუგეს: დავითისა." },
  { verse: 43, text: "უთხრა მათ იესომ: კი მაგრამ როგორღა უწოდებს მას სულით შთაგონებული დავითი უფალს, როდესაც ამბობს:" },
  { verse: 44, text: "უთხრა უფალმა ჩემს უფალს: დაჯექი ჩემს მარჯვნივ, ვიდრე ფერხთით დაგიმხობ მტრებს." },
  { verse: 45, text: "ამრიგად, თუ დავითი უფალს უწოდებს მას, როგორღა ეკუთვნის ძედ?" },
  { verse: 46, text: "ვერავინ შესძლო მისთვის სიტყვის მიგება: და იმ დღიდან ვეღარც კითხვას უბედავდა ვინმე." },
],

23: [
  { verse: 1, text: "მაშინ იესომ მიმართა ხალხს და თავის მოწაფეებს:" },
  { verse: 2, text: "მოსეს სავარძელზე მწიგნობარნი და ფარისეველნი სხედან;" },
  { verse: 3, text: "მაშ, ყველაფერი, რის დაცვასაც გირჩევენ, დაიცავით და აღასრულეთ, მაგრამ მათ საქმეს კი ნუ მიბაძავთ, ვინაიდან ამბობენ და არ ასრულებენ." },
  { verse: 4, text: "რადგან მძიმე ტვირთს ჰკრავენ და ძნელად სატვირთველს, და ხალხს მხრებზე ადებენ; თვითონ კი თითის განძრევაც არ სურთ მის დასაძრავად." },
  { verse: 5, text: "და მთელ თავიანთ საქმეს აკეთებენ კაცთა დასანახავად; აგანიერებენ თავიანთ სალოცავ თასმებს და აგრძელებენ თავიანთი სამოსის კალთებს." },
  { verse: 6, text: "უყვართ წვეულებებზე სუფრის თავში წამოჭიმვა და წინა რიგები სინაგოგებში." },
  { verse: 7, text: "და სალმის ძღვნა მოედნებზე, რათა ხალხი მიმართავდეს მათ: რაბი! რაბი!" },
  { verse: 8, text: "თქვენ კი ნუ იწოდებით ასე: რაბი! ვინაიდან ერთია თქვენი მოძღვარი - ქრისტე, ხოლო თქვენ ყველანი ძმები ხართ." },
  { verse: 9, text: "ნურც თქვენს მამას უწოდებთ ვინმეს ამ ქვეყნად, ვინაიდან ერთია მამა თქვენი ზეციერი." },
  { verse: 10, text: "და ნურც წინამძღვრებად იწოდებით, ვინაიდან ერთია თქვენი წინამძღვარი - ქრისტე." },
  { verse: 11, text: "ხოლო თქვენს შორის უდიდესი თქვენი მსახური იყოს." },
  { verse: 12, text: "რადგან ვინც აიმაღლებს თავის თავს, დამდაბლდება, და ვინც დაიმდაბლებს თავის თავს, ამაღლდება." },
  { verse: 13, text: "ვაი თქვენდა, მწიგნობარნო, და ფარისეველნო, თვალთმაქცნო, ცათა სასუფეველს რომ უხშობთ ხალხს, ვინაიდან არც თვითონ შედიხართ და არც შემსვლელთ ანებებთ შესვლას." },
  { verse: 14, text: "ვაი თქვენდა, მწიგნობარნო და ფარისეველნო, თვალთმაქცნო, ვინაიდან ნთქამთ ქვრივთა სახლებს და თანაც პირმოთნედ ლოცულობთ დიდხანს; მით უფრო მძიმე იქნება თქვენი სასჯელი." },
  { verse: 15, text: "ვაი თქვენდა, მწიგნობარნო და ფარისეველნო, თვალთმაქცნო, ვინაიდან დაძრწიხართ ზღვასა თუ ხმელზე, რათა მოაქციოთ თუნდაც ერთი კაცი: და როცა მოაქცევთ, გეენის კერძად აქცევთ მას, თვით თქვენზე ორჯერ მეტად." },
  { verse: 16, text: "ვაი თქვენდა, ბრმა წინამძღვარნო, რომლებიც ამბობთ: თუ ვინმე დაიფიცავს ტაძარს, არაფერია, ხოლო თუ ვინმე დაიფიცავს ტაძრის ოქროს, მოვალეა." },
  { verse: 17, text: "შლეგნო და ბრმანო, რა უფრო მეტია: ოქრო თუ ტაძარი, რომელიც გაწმენდს ოქროს?" },
  { verse: 18, text: "და მერე: თუ ვინმე დაიფიცავს საკურთხევვლს, არაფერია, ხოლო თუ ვინმე დაიფიცავს შესაწირავს, რომელიც დევს საკურთხეველზე, მოვალეა." },
  { verse: 19, text: "შლეგნო და ბრმანო, რა უფრო მეტია: შესაწირავი თუ საკურთხეველი, რომელიც გაწმენდს შესაწირავს?" },
  { verse: 20, text: "რადგან ვინც იფიცავს საკურთხეველს, იფიცავს მას და ყოველივე იმას, რაც საკურთხეველზეა." },
  { verse: 21, text: "და ვინც იფიცავს ტაძარს, იფიცავს მას და მის მკვიდრსაც." },
  { verse: 22, text: "და ვინც იფიცავს ცას, იფიცავს ღმრთის ტახტს და მასზე მჯდომარესაც." },
  { verse: 23, text: "ვაი თქვენდა, მწიგნობარნო და ფარისეველნო, თვალთმაქცნო, რომლებიც იხდით მეათედს პიტნისას, კამისას, კვლიავისას, და დაგიტევებიათ ის, რაც უმთავრესია რჯულში: სამართალი, წყალობა და რწმენა. ეს უნდა გექნათ, და არც ის მიგეტოვებინათ." },
  { verse: 24, text: "ბრმა წინამძღვარნო, რომელნიც გადასწურავთ ქინქლს და აქლემს კი შთანთქამთ." },
  { verse: 25, text: "ვაი თქვენდა, მწიგნობარნო და ფარისეველნო, თვალთმაქცნო, გარედან რომ წმენდთ სასმისსა თუ ჯამს, შიგნით კი სავსენი არიან ნაძარცვითა და ნაოხარით." },
  { verse: 26, text: "თვალდავსილო ფარისეველო, ჯერ შიგნიდან გაწმინდე სასმისი თუ ჯამი, რათა წმიდა იყოს გარეთაც." },
  { verse: 27, text: "ვაი თქვენდა, მწიგნობარნო და ფარისეველნო, თვალთმაქცნო, ასე რომ ჰგავხართ შეფეთქილ საფლავებს, რომლებიც გარედან მშვენიერნი ჩანან, ხოლო შიგნით სავსენი არიან მკვდრების ძვლებითა და ყოველგვარი უწმინდურებით." },
  { verse: 28, text: "ასევე თქვენც გარეგნულად მართალნი ჰგონიხართ ხალხს, შიგნით კი სავსენი ხართ თვალთმაქცობითა და ურჯულოებით." },
  { verse: 29, text: "ვაი თქვენდა, მწიგნობარნო და ფარისეველნო, თვალთმაქცნო, რომელნიც აგებთ წინასწარმეტყველთა სამარხებს და ამკობთ მართალთა ძეგლებს;" },
  { verse: 30, text: "და ამბობთ: ჩვენი მამების დროს რომ გვეცხოვრა, არ ვიქნებოდით მათი თანამოზიარენი წინასწარმეტყველთა სისხლში." },
  { verse: 31, text: "ამრიგად, თქვენი თავის წინააღმდეგ თვითონვე მოწმობთ, რომ წინასწარმეტყველთა მკვლელების ნაშიერნი ხართ." },
  { verse: 32, text: "და აღავსეთ საწყაული თქვენი მამების." },
  { verse: 33, text: "გველნო, იქედნეს ნაშიერნო, როგორ გაექცევით გეენის სასჯელს?" },
  { verse: 34, text: "ამიტომ, აჰა, გიგზავნით წინასწარმეტყველთ, ბრძენთა და მწიგნობართ; და ზოგს მოჰკლავთ და ჯვარს აცვამთ, ზოგს მათრახით სცემთ სინაგოგებში და ზოგსაც ქალაქიდან ქალაქად დაუწყებთ დევნას;" },
  { verse: 35, text: "რათა მოიწიოს თქვენზე ამ ქვეყნად დათხეული ყოველი მართალი სისხლი, აბელ მართლის სისხლიდან ვიდრე სისხლამდე ბარაქიას ძისა, ზაქარიასი, რომელიც მოჰკალით ტაძარსა და საკურთხეველს შორის." },
  { verse: 36, text: "ჭეშმარიტად გეუბნებით თქვენ, რომ ყოველივე ეს მოიწევა ამ მოდგმაზე." },
  { verse: 37, text: "იერუსალიმ, იერუსალიმ, წინასწარმეტყველთა მკვლელო და შენდამი მოვლინებულთა ქვებით ჩამქოლველო! რამდენჯერ ვცადე შემეკრიბა შენი შვილები, როგორც ფრინველი კრებს ბარტყებს თავის ფრთებქვეშ, და არ ისურვე." },
  { verse: 38, text: "და აჰა, გრჩებათ თქვენი სახლი ოხრად." },
  { verse: 39, text: "რადგანაც გეუბნებით თქვენ: ვეღარ მიხილავთ ამიერიდან, სანამ არ იტყვით: კურთხეულია მომავალი უფლის სახელით!" },
],

24: [
  { verse: 1, text: "გამოვიდა იესო ტაძრიდან და წავიდა; მიუახლოვდნენ მისი მოწაფეები, რათა ტაძრის შენობები ეჩვენებინათ მისთვის." },
  { verse: 2, text: "ხოლო იესომ მიუგო მათ: ხომ ხედავთ ყოველივე ამას? ჭეშმარიტად გეუბნებით თქვენ: ქვა ქვაზე არ დარჩება აქ, არამედ ყველაფერი დაინგრევა." },
  { verse: 3, text: "ხოლო როცა ზეთისხილის მთაზე იჯდა განმარტოებით, მიუახლოვდნენ მისი მოწაფეები და ჰკითხეს: გვითხარი, როდის მოხდება ეს? ან რა იქნება ნიშანი შენი მოსვლისა და საუკუნის დასასრულისა?" },
  { verse: 4, text: "იესომ პასუხად მიუგო მათ: ფხიზლად იყავით, რათა არავინ გაცდუნოთ." },
  { verse: 5, text: "ვინაიდან მრავალნი მოვლენ ჩემი სახელით და იტყვიან: მე ვარ ქრისტეო, და მრავალს აცდუნებენ." },
  { verse: 6, text: "გაიგებთ აგრეთვე ომებსა და ომების ამბებს. თქვენ იცით, ნუ შეძრწუნდებით, ვინაიდან ყოველი ეს უნდა მოხდეს, მაგრამ ეს ჯერ კიდევ არ არის დასასრული." },
  { verse: 7, text: "რადგან აღდგება ხალხი ხალხის წინააღმდეგ, და სამეფო სამეფოს წინააღმდეგ: და იქნება შიმშილობა და ჟამიანობა და მიწისძვრანი აქა-იქ." },
  { verse: 8, text: "ხოლო ყოველივე ეს სალმობათა დასაბამია." },
  { verse: 9, text: "მაშინ მიგცემენ სატანჯველად და მოგკლავენ თქვენ; და მოგიძულებთ ყველა ხალხი ჩემი სახელის გამო." },
  { verse: 10, text: "მრავალი შეცდება მაშინ, გასცემენ და შეიძულებენ ერთურთს." },
  { verse: 11, text: "მრავალი ცრუწინასწარმეტყველი აღდგება და აცდუნებს მრავალს." },
  { verse: 12, text: "და ურჯულოების მომრავლების გამო მრავალში განელდება სიყვარული." },
  { verse: 13, text: "ხოლო ვინც ბოლომდე დაითმენს, იგი ცხონდება." },
  { verse: 14, text: "და იქადაგება სასუფევლის ეს სახარება მთელს ქვეყანაზე, ყველა ხალხის სამოწმებლად; და მაშინ მოიწევა დასასრული." },
  { verse: 15, text: "ხოლო როდესაც იხილავთ გაპარტახების სიბილწეს, დანიელ წინასწარმეტყველის მიერ ნათქვამს, რაც წმინდა ადგილას დევს (წამკითხველმა გაიგოს)," },
  { verse: 16, text: "მაშინ იუდეას მყოფნი მთებს შეეფარონ." },
  { verse: 17, text: "და ერდოზე მყოფი ნუ ჩამოვა ძირს, თავისი სახლიდან რაიმეს გამოსატანად." },
  { verse: 18, text: "ხოლო მინდვრად მყოფი ნუ მიბრუნდება შინ, თავისი სამოსის წამოსაღებად." },
  { verse: 19, text: "ვაი ფეხმძიმეთ და მეძუძურთ იმ ხანად." },
  { verse: 20, text: "ილოცეთ, რათა გაქცევამ არ მოგიწიოთ ზამთარში, ანდა შაბათს." },
  { verse: 21, text: "რადგან იქნება მაშინ დიდი ჭირი, რომლის მსგავსი არ ყოფილა ქვეყნის დასაბამიდან დღემდე, და არც იქნება." },
  { verse: 22, text: "და რომ არ მემოკლებულიყვნენ ის დღენი, ვერ გადარჩებოდა ვერცერთი ძე ხორციელი, მაგრამ რჩეულთათვის შემოკლდებიან ის დღენი." },
  { verse: 23, text: "მაშინ, თუ ვინმე გეტყვით: აჰა, აქ არის ქრისტე, ან კიდევ - იქო, ნუ ერწმუნებით." },
  { verse: 24, text: "რადგან აღდგებიან ცრუქრისტენი და ცრუწინასწარმეტყველნი, და მოახდენენ დიდ სასწაულებსა და ნიშებს, რათა, აცდუნონ, თუკი შესძლეს, თვითონ რჩეულნიც." },
  { verse: 25, text: "აჰა, წინასწარ გაუწყეთ თქვენ." },
  { verse: 26, text: "ასე რომ, თუ გეტყვიან: აჰა, უდაბნოშიაო, ნუ გახვალთ; და, აჰა, თავის სენაკშიაო, ნუ ერწმუნებით." },
  { verse: 27, text: "ვინაიდან როგორც ელვა იელვებს აღმოსავლეთიდან დასავლეთამდე, ისე იქნება კაცის ძის მოსვლაც." },
  { verse: 28, text: "რადგან სადაც ეგდება მძორი, იქვე შეიყრებიან სვავებიც." },
  { verse: 29, text: "და მსწრაფლ, იმ დღეთა პირის შემდეგ, დაბნელდება მზე, მთვარე აღარ გამოსცემს ნათელს, ვარსკვლავები ჩამოცვივიან ციდან და შეიძვრიან ციურნი ძალნი." },
  { verse: 30, text: "და მაშინ გამოჩნდება კაცის ძის ნიშანი ცაზე; მაშინ მოთქმას მოჰყვება დედამიწის ყოველი ტომი, და იხილავენ ძეს კაცისას, მომავალს ზეცის ღრუბლებზე ძალითა და დიდებით მრავლით." },
  { verse: 31, text: "მოავლინებს თავის ანგელოზებს მგრგვინავი საყვირით, და შეკრებენ მის რჩეულთ ოთხთავ ქართაგან, ცათა კიდიდან მათ კიდემდე." },
  { verse: 32, text: "ლეღვის ხისაგან ისწავლეთ იგავი: როცა მისი ტოტები რბილდება და ფოთლები გამოაქვს, იცით, რომ ახლოა ზაფხული." },
  { verse: 33, text: "ასევე თქვენც, როცა იხილავთ ყოველივე ამას, იცოდეთ, რომ უკვე ახლოა, კარზეა მომდგარი." },
  { verse: 34, text: "ჭეშმარიტად გეუბნებით თქვეს: არ გადავა ეს მოდგმა, ვიდრე ყოველივე ეს არ აღსრულდება." },
  { verse: 35, text: "ცა და მიწა გადავლენ, ხოლო ჩემი სიტყვები არ გადავლენ." },
  { verse: 36, text: "მაგრამ ის დღე და ის საათი არავინ იცის: არც ციურმა ანგელოზებმა, არამედ მხოლოდ მამამ." },
  { verse: 37, text: "და როგორც იყო ნოეს დღეებში, ისე იქნება კაცის ძის მოსვლაც." },
  { verse: 38, text: "ვინაიდან როგორც წარღვნის წინა დღეებში ჭამდნენ და სვამდნენ, ცოლს ირთავდნენ და თხოვდებოდნენ, იმ დღემდე, როცა ნოე შევიდა კიდობანში," },
  { verse: 39, text: "და არას დაგიდევდნენ, ვიდრე არ მოვიდა წარღვნა და წალეკა ყველანი; ასე იქნება კაცის ძის მოსვლაც." },
  { verse: 40, text: "მაშინ ორნი იქნებიან ველად: ერთი წარიტაცება, მეორე კი დარჩება." },
  { verse: 41, text: "ორი ქალი იქნება წისქვილში: ერთი წარიტაცება, მეორე კი დარჩება." },
  { verse: 42, text: "მაშ, იფხიზლეთ, ვინაიდან არ იცით, რომელ დღეს მოვა თქვენი უფალი." },
  { verse: 43, text: "ესეც გახსოვდეთ: სახლის პატრონმა რომ იცოდეს, რომელ საათზე მოვა ქურდი, ფხიზლად იქნებოდა და ძირს არ გამოათხრევინებდა თავისი სახლისათვის." },
  { verse: 44, text: "ამიტომ თქვენც მზად იყავით, ვინაიდან, როცა არ ელით, სწორედ იმ საათს მოვა ძე კაცისა." },
  { verse: 45, text: "ვინ არის ერთგული და გონიერი მონა, რომელიც მისმა პატრონმა მიუჩინა თავის მსახურთ, რათა დროულად მისცეს საჭმელი მათ?" },
  { verse: 46, text: "ნეტა იმ მონას, რომელსაც ამნაირად მოქმედს ჰპოვებს მისი პატრონი, როდესაც მოვა." },
  { verse: 47, text: "ჭეშმარიტად გეუბნებით თქვენ: მთელს თავის საბადებელს მეთვალყურედ მიუჩენს მას." },
  { verse: 48, text: "მაგრამ თუ ის მონა ბოროტია და გულში იტყვის: აგვიანებს ჩემი პატრონი მოსვლას," },
  { verse: 49, text: "და დაიწყებს თავისივე მსგავსი მონების ცემას და მემთვრალეებთან ჭამას და სმას," },
  { verse: 50, text: "მაშინ მოვა მონის პატრონი იმ დღეს, როდესაც არ ელის, და იმ საათს, რომელიც არ იცის," },
  { verse: 51, text: "შუა გაკვეთს მას და თვალთმაქცებთან დაუდებს წილს, და იქნება იქ ტირილი და კბილთა ღრჭიალი." },
],
25: [
  { verse: 1, text: "მაშინ მიემსგავსება ცათა სასუფეველი ათ ქალწულს, რომლებმაც აიღეს თავიანთი ლამპრები და გადავიდნენ სიძის შესაგებებლად." },
  { verse: 2, text: "ხოლო ხუთი მათგანი გონიერი იყო, ხუთი კი - უგუნური." },
  { verse: 3, text: "უგუნურებმა აიღეს თავიანთი ლამპრები, მაგრამ თან არ წაიღეს ზეთი." },
  { verse: 4, text: "გონიერებმა კი თავიანთ ლამპრებთან ერთად თან წაიღეს ზეთიც თავიანთი ჭურჭლებით." },
  { verse: 5, text: "და რაკი სიძემ დაიგვიანა, ყველას რული მოერია და ჩაეძინა." },
  { verse: 6, text: "მაგრამ შუაღამისას გაისმა ძახილი: აჰა, მოდის სიძე, გამოდით, გამოეგებეთო." },
  { verse: 7, text: "მაშინ ადგა ყველა ქალწული და გამართეს თავიანთი ლამპრები." },
  { verse: 8, text: "და უგუნურებმა უთხრეს გონიერთ: გვიწილადეთ თქვენი ზეთი, ვინაიდან ჩვენი ლამპრები ქრება." },
  { verse: 9, text: "გონიერებმა კი მიუგეს: რომ არ შემოგვაკლდეს ჩვენცა და თქვენც, გიჯობთ წახვიდეთ ვაჭრებთან და იყიდოთ თქვენთვის." },
  { verse: 10, text: "როცა საყიდლად წავიდნენ, მოვიდა სიძე; მზადმყოფნი მასთან ერთად შევიდნენ ქორწილში და დაიხშო კარი." },
  { verse: 11, text: "შემდეგ მოვიდნენ დანარჩენი ქალწულნიც და სთხოვეს: უფალო, უფალო, გაგვიღე ჩვენ." },
  { verse: 12, text: "ხოლო მან პასუხად მიუგო: ჭეშმარიტად გეუბნებით: არ გიცნობთ თქვენ." },
  { verse: 13, text: "მაშ, იფხიზლეთ, ვინაიდან არც დღე იცით და არც საათი, როდის მოვა ძე კაცისა." },
  { verse: 14, text: "რადგანაც იმ კაცივით მოიქცევა, რომელმაც გამგზავრებისას უხმო თავის მონებს და მთელი თავისი ავლადიდება ჩააბარა." },
  { verse: 15, text: "ერთს ხუთი ტალანტი მისცა, მეორეს - ორი, მესამეს - ერთი, თვითეულს - მისი უნარის მიხედვით, და გაემგზავრა." },
  { verse: 16, text: "ხუთი ტალანტის მიმღები წავიდა, ივაჭრა და ხუთი სხვა ტალანტიც მოიგო." },
  { verse: 17, text: "ასევე ორი ტალანტის მიმღებმა მოიგო ორი სხვაც." },
  { verse: 18, text: "ხოლო ერთი ტალანტის მიმღები წავიდა, მიწაში დაფლა და დამალა თავისი პატრონის ვერცხლი." },
  { verse: 19, text: "დიდი ხნის შემდეგ დაბრუნდა იმ მონების პატრონი და ანგარიში მოსთხოვა მათ." },
  { verse: 20, text: "ეახლა ხუთი ტალანტის მიმღები, ხუთი სხვა ტალანტიც მიართვა და უთხრა: ბატონო, შენ მომეცი ხუთი ტალანტი და, აჰა, მათი წყალობით, ხუთი სხვა ტალანტიც მოვიგე." },
  { verse: 21, text: "ხოლო პატრონმა მიუგო მას: კეთილი, სანდო და კეთილო მონავ! რაკიღა მცირედში სანდო იყავ, დიდს განდობ შენ: შემოდი შენი პატრონის სიხარულში." },
  { verse: 22, text: "ეახლა ორი ტალანტის მიმღებიც და უთხრა: ბატონო, შენ მომეცი ორი ტალანტი და აჰა, მათი წყალობით, ორი სხვა ტალანტიც მოვიგე." },
  { verse: 23, text: "ხოლო პატრონმა მიუგო მას: კეთილი, სანდო და კეთილო მონავ! რაკი მცირედში სანდო იყავ, დიდს განდობ შენ: შემოდი შენი პატრონის სიხარულში." },
  { verse: 24, text: "ეახლა ერთი ტალანტის მიმღებიც და უთხრა: ბატონო, ვიცოდი, რომ სასტიკი კაცი ხარ; მოიმკი, სადაც არ დაგითესავს, და კრებ, სადაც არ დაგიბნევია." },
  { verse: 25, text: "ჰოდა, შემეშინდა, წავედი და მიწაში დავფალი შენი ტალანტი; აჰა, შენი შენავე გქონდეს." },
  { verse: 26, text: "ხოლო პატრონმა მიუგო და უთხრა მას: უკეთურო და მცონარა მონავ! იცოდი, რომ მოვიმკი, სადაც არ დამითესავს, და ვკრებ, სადაც არ დამიბნევია." },
  { verse: 27, text: "ამიტომაც გმართებდა ვაჭრებისათვის მიგეცა ჩემი ვერცხლი, რათა დაბრუნებულს მიმეღო ჩემი სესხი მონაგებითურთ." },
  { verse: 28, text: "მაშ, წაართვით მაგას ტალანტი, და მიეცით ათი ტალანტის მქონეს." },
  { verse: 29, text: "რადგან ყველა მქონეს მიეცემა და მიემატება, ხოლო არმქონეს წაერთმევა ისიც, რაცა აქვს." },
  { verse: 30, text: "ხოლო ეგ ურგები მონა გააგდეთ გარესკნელის ბნელში. და იქნება იქ ტირილი და კბილთა ღრჭიალი." },
  { verse: 31, text: "და როდესაც მოვა ძე კაცისა თავისი დიდებით და ყველა წმიდა ანგელოზი მასთან ერთად, მაშინ დაჯდება იგი თავისი დიდების ტახტზე." },
  { verse: 32, text: "შეიყრება მის წინაშე ყველა ხალხი და გაარჩევს მათ ერთმანეთისაგან, როგორც მწყემსი გამოარჩევს ცხვრებს თხებისაგან." },
  { verse: 33, text: "და დააყენებს ცხვრებს თავის მარჯვნივ, ხოლო თხებს - მარცხნივ." },
  { verse: 34, text: "მაშინ ეტყვის მეუფე მის მარჯვნივ მდგომთ: მოდით, კურთხეულნო მამაჩემის მიერ, და დაიმკვიდრეთ სასუფეველი, თქვენთვის გამზადებული ქვეყნის დასაბამიდან." },
  { verse: 35, text: "რადგან მშიოდა და მომეცით საჭმელი; მწყუროდა და მასვით; უცხო ვიყავი და შემიწყნარეთ;" },
  { verse: 36, text: "შიშველი ვიყავი და შემმოსეთ; სნეული ვიყავი და მომხედეთ; საპყრობილეში ვიყავი და მინახულეთ." },
  { verse: 37, text: "მაშინ მართალნი პასუხად ეტყვიან მას: უფალო, როდის გიხილეთ შენ მშიერი და დაგაპურეთ? ანდა მწყურვალი და გასვით შენ?" },
  { verse: 38, text: "როდის გიხილეთ შენ უცხოდ და შეგიწყნარეთ? ანდა შიშველი და შეგმოსეთ შენ?" },
  { verse: 39, text: "როდის გიხილეთ შენ სნეული, ან საპყრობილეში, და გინახულეთ?" },
  { verse: 40, text: "მიუგებს მეუფე და ეტყვის მათ: ჭეშმარიგად გეუბნებით თქვენ: რითაც შეეწიეთ ერთს ამ ჩემს მცირე ძმათაგანს, იმით მე შემეწიეთ." },
  { verse: 41, text: "მაშინ ეტყვის მარცხნივ მდგომთაც: წადით ჩემგან, წყეულნო, საუკუნო ცეცხლში, რომელიც ეშმაკისა და მისი ანგელოზებისთვისაა გამზადებული." },
  { verse: 42, text: "რადგან მშიოდა და არ მომეცით საჭმელი; მწყუროდა და არ მასვით;" },
  { verse: 43, text: "უცხო ვიყავი და არ შემიწყნარეთ; შიშველი ვიყავი და არ შემმოსეთ; სნეული ვიყავი და საპყრობილეში, და არ მინახულეთ." },
  { verse: 44, text: "მაშინ ისინიც პასუხად ეტყვიან მას: უფალო, როდის გიხილეთ შენ მშიერი, ან მწყურვალი, ან უცხოდ მყოფი, ან შიშველი, ან სნეული, ან საპყრობილეში და არ გემსახურეთ?" },
  { verse: 45, text: "მაშინ მიუგებს და ეტყვის მათ: ჭეშმარიტად გეუბნებით თქვენ: რითაც არ შეეწიეთ ერთს ამ ჩემს მცირე ძმათაგანს, იმით არც მე შემეწიეთ." },
  { verse: 46, text: "და წავლენ ესენი საუკუნო სატანჯველში, ხოლო მართალნი - საუკუნო სიცოცხლეში." },
],
26: [
  { verse: 1, text: "და როდესაც დაასრულა იესომ ეს სიტყვები, თავის მოწაფეებს უთხრა:" },
  { verse: 2, text: "თქვენ იცით, რომ ორი დღის შემდეგ იქნება პასექი და ძე კაცისა მიეცემა ჯვარზე საცმელად." },
  { verse: 3, text: "მაშინ შეიკრიბნენ მღვდელმთავარნი, მწიგნობარნი და ხალხის უხუცესნი კაიაფად წოდებული მღვდელმთავრის კარზე." },
  { verse: 4, text: "და მოითათბირეს, მზაკვრობით შეეპყროთ იესო და მოეკლათ იგი." },
  { verse: 5, text: "მაგრამ ამბობდნენ: მხოლოდ არა დღესასწაულზე, რათა ხალხი არ ამბოხდესო." },
  { verse: 6, text: "ხოლო როცა ბეთანიაში იყო იესო, სიმონ კეთროვანის სახლში," },
  { verse: 7, text: "მიუახლოვდა ერთი ქალი, ალებასტრის ჭურჭლით რომ მოჰქონდა ძვირფასი ნელსაცხებელი, და თავზე დაასხა ინახად მჯდომს." },
  { verse: 8, text: "ეს რომ დაინახეს, მისი მოწაფეები განრისხდნენ და თქვეს: რა საჭიროა ასეთი ფლანგვა?" },
  { verse: 9, text: "ვინაიდან შეიძლებოდა დიდ ფასად გაგვეყიდა ნელსაცხებელი და გლახაკთათვის მიგვეცა ფული." },
  { verse: 10, text: "მაგრამ იესო მიუხვდა და უთხრა მათ: რას ერჩით ამ ქალს? მაგან ხომ კეთილი საქმე მიყო:" },
  { verse: 11, text: "ვინაიდან გლახაკნი ყოველთვის გვერდითა გყავთ, მე კი ყოველთვის როდი გეყოლებით." },
  { verse: 12, text: "ნელსაცხებელი რომ მცხო ტანზე, ამით დასამარხათ გამამზადა." },
  { verse: 13, text: "ჭეშმარიტად გეუბნებით თქვენ: მთელს ქვეყანაზე, საღაც იქადაგება ეს სახარება, ყველგან ითქმება მისი საქმე მისსავე მოსაგონებლად." },
  { verse: 14, text: "მაშინ წავიდა ერთი თორმეტთაგანი, იუდა ისკარიოტელად წოდებული, მღვდელმთავრებთან" },
  { verse: 15, text: "და უთხრა მათ: რის მოცემას ინებებთ ჩემთვის, თუკი მას მოგცემთ? ხოლო მათ მიუწონეს ოცდაათი ვერცხლი." },
  { verse: 16, text: "და მას მერე ეძებდა ხელსაყრელ დროს, რათა მათთვის მიეცა იგი." },
  { verse: 17, text: "ხოლო უფუარობის პირველ დღეს მივიდნენ მოწაფეები იესოსთან და უთხრეს: სად გნებავს, რომ მოგიმზადოთ საჭმელად პასექი?" },
  { verse: 18, text: "მან კი თქვა: წადით ქალაქში ამა და ამ კაცთან და უთხარით: მოძღვარი ამბობს: მოაწია ჩემმა დრომ; შენთან ვყოფ პასექს ჩემს მოწაფეებთან ერთად." },
  { verse: 19, text: "მოწაფეები ისე მოიქცნენ, როგორც უბრძანა იესომ, და მოუმზადეს პასექი." },
  { verse: 20, text: "და მწუნრის ჟამს ინახად დაჯდა თორმეტ მოწაფესთან ერთად." },
  { verse: 21, text: "ხოლო როცა ჭამდნენ ისინი, თქვა: ჭეშმარიტად გეუბნებით: ერთი თქვენგანი გამცემს მე." },
  { verse: 22, text: "ისინი დიდად დამწუხრდნენ და ყველამ ცალ-ცალკე დაუწყო კითხვა: მე ხომ არა, უფალო?" },
  { verse: 23, text: "ხოლო მან პასუხად თქვა: ვინც ჩემთან ერთად ჩაყოფს ხელს ჯამში, ის გამცემს მე." },
  { verse: 24, text: "და მართლაც, მიდის ძე კაცისა, როგორც დაიწერა მისთვის: მაგრამ ვაი იმ კაცს, ვის მიერაც გაიცემა ძე კაცისა; ერჩია, სულაც არ შობილიყო ის კაცი." },
  { verse: 25, text: "მაშინ იუდამ, მისმა გამცემმა, თქვა: მე ხომ არა ვარ, რაბი? უთხრა მას: შენ სთქვი." },
  { verse: 26, text: "და როცა ჭამდნენ ისინი, აიღო პური იესომ და აკურთხა, გატეხა, მისცა მოწაფეებს და უთხრა: მიიღეთ, ჭამეთ, ეს არის ჩემი ხორცი." },
  { verse: 27, text: "აიღო სასმისი და აკურთხა, მისცა მათ და თქვა: ამით სვით ყველამ:" },
  { verse: 28, text: "ეს არის ჩემი სისხლი ახალი აღთქმისა, მრავალთათვის დათხეული ცოდვათა მისატევებლად." },
  { verse: 29, text: "ხოლო მე გეუბნებით თქვენ: აღარა ვსვამ ამიერიდან ვაზის ამ ნაყოფისაგან, ვიდრე იმ დღემდე, როცა თქვენთან ერთად შევსვამ ახალს მამაჩემის სასუფეველში." },
  { verse: 30, text: "იგალობეს, და გავიდნენ ზეთისხილის მთაზე." },
  { verse: 31, text: "მაშინ უთხრა მათ იესომ: თქვენ ყველანი შეცდებით ამაღამ ჩემს გამო; ვინაიდან დაწერილია: დავცემ მწყემსს, და განიბნევიან ფარის ცხვრები." },
  { verse: 32, text: "ხოლო ჩემი აღდგომის შემდეგ წინ წაგიძღვებით გალილეისკენ." },
  { verse: 33, text: "მიუგო პეტრემ და უთხრა მას: ყველა რომ შეცდეს შენს გამო, მე არასოდეს შევცდები." },
  { verse: 34, text: "უთხრა იესომ: ჭეშმარიტად გეუბნები შენ: ამაღამ, მამლის ყივილამდე, სამჯერ უარმყოფ მე." },
  { verse: 35, text: "მიუგო მას პეტრემ: შენთან ერთადაც რომ მიწიოს სიკვდილმა, არასოდეს უარგყოფ შენ. და ასევე ამბობდა ყველა მოწაფე." },
  { verse: 36, text: "მაშინ იესო მათთან ერთად მივიდა იმ ადგილას, რომელსაც ჰქვია გეთსემანე, და უთხრა მათ: მანდ ისხედით, ვიდრე მივალ და ვილოცებ იქ." },
  { verse: 37, text: "თან წაიყვანა პეტრე და ზებედეს ორი ძე, და იწყო მწუხარება და ურვა." },
  { verse: 38, text: "მაშინ უთხრა მათ იესომ: მწუხარეა ჩემი სული, ვიდრე სიკვდილამდე; იყავით აქ და იფხიზლეთ ჩემთან ერთად." },
  { verse: 39, text: "ცოტაზე გაშორდა მათ, პირქვე დაემხო, ლოცულობდა და ამბობდა: მამაო ჩემო! თუკი შესაძლოა, ამცდეს ეს სასმისი; თუმცა არა როგორც მე მნებავს, არამედ - როგორც შენ." },
  { verse: 40, text: "მივიდა თავის მოწაფეებთან და მძინარენი ჰპოვა ისინი, და უთხრა პეტრეს: ასე, ერთ საათსაც ვერ შესძელით გეფხიზლათ ჩემთან ერთად?" },
  { verse: 41, text: "იფხიზლეთ და ილოცეთ, რათა არ შეხვიდეთ საცდუნებელში: სული მხნეა, მაგრამ ხორცია უძლური." },
  { verse: 42, text: "მეორედაც გაშორდა მათ, ლოცულობდა და ამბობდა: მამაო ჩემო! თუკი შეუძლებელია ამცდეს ეს სასმისი, რათა არ შევსვა იგი, დე, იყოს ნება შენი." },
  { verse: 43, text: "მივიდა და კვლავ მძინარენი ჰპოვა ისინი, რადგან თვალები დამძიმებოდათ." },
  { verse: 44, text: "მიატოვა ისინი, მესამედაც გაშორდა მათ, და კვლავ იგივე სიტყვები წარმოთქვა." },
  { verse: 45, text: "მერე მივიდა მოწაფეებთან და უთხრა მათ: კვლავინდებურად გძინავთ და განისვენებთ? აჰა, მოაწია დრომ, და ძე კაცისა მიეცემა ცოდვილთა ხელში." },
  { verse: 46, text: "ადექით, წავიდეთ: აჰა, მოგვიახლოვდა ჩემი გამცემი." },
  { verse: 47, text: "სიტყვა არ დაესრულებინა, რომ, აჰა, იუდა, ერთი თორმეტთაგანი, მოვიდა და მასთან ერთად დიდძალი ხალხი მახვილებითა და წათებით, მღვდელმთავართა და ხალხის უხუცესთაგან." },
  { verse: 48, text: "ხოლო მის გამცემს ნიშანი მიეცა მათთვის და ეთქვა: ვისაც მე ვეამბორები, ის არის: შეიპყარით იგი." },
  { verse: 49, text: "მსწრაფლ მიეახლა იესოს და უთხრა: გიხაროდეს, რაბი! და ეამბორა." },
  { verse: 50, text: "ხოლო იესომ უთხრა მას: მოყვასო, რისთვის მოსულხარ? მაშინ მისცვივდნენ, ხელი სტაცეს იესოს და შეიპყრეს იგი." },
  { verse: 51, text: "და აჰა, იესოს ერთმა თანამდგომმა ხელი გაიწოდა, მახვილი იშიშვლა, დაჰკრა მღვდელმთავრის მონას და ყური ჩამოათალა." },
  { verse: 52, text: "მაშინ იესომ უთხრა მას: ჩააგე მახვილი ქარქაშში, რადგანაც ყველა, ვინც აიღებს მახვილს, მახვილითვე დაიღუპება." },
  { verse: 53, text: "ან იქნებ გგონია, რომ არ შემიძლია შევევედრო მამას ჩემსას, და წარმომიდგენს ანგელოზთა თორმეტ ლეგიონს და უფრო მეტსაც." },
  { verse: 54, text: "როგორღა აღსრულდება წერილი, რომ ასე უნდა მოხდეს?" },
  { verse: 55, text: "მაშინ იესომ უთხრა ხალხს: როგორც ავაზაკს, მახვილებითა და წათებით მომიხტით შესაპყრობად; დღენიადაგ ტაძარში მჯდომი გასწავლიდით და არ შეგიპყრივართ მე." },
  { verse: 56, text: "ყოველივე ეს იქმნა, რათა აღსრულდეს დაწერილი წინასწარმეტყველთა მიერ. მაშინ ყველა მოწაფემ მიატოვა ის და გაიქცა." },
  { verse: 57, text: "ხოლო მათ შეიპყრეს იესო და მიიყვანეს იგი კაიაფა მღვდელმთავრისას, სადაც შეკრებილიყვნენ მწიგნობარნი და უხუცესნი." },
  { verse: 58, text: "პეტრე კი, მღვდელმთავრის ეზომდე შორიახლო მისდევდა მას: შევიდა შიგნით და მსახურებთან დაჯდა, რათა ეხილა დასასრული." },
  { verse: 59, text: "ხოლო მღვდელმთავარნი, უხუცესნი და მთელი სინედრიონი ცრუ მოწმობას ეძებდნენ იესოს წინააღმდეგ, რათა მოეკლათ იგი," },
  { verse: 60, text: "მაგრამ ვერ იპოვეს, თუმცა ბევრი ცრუმოწმე იყო მოსული. ბოლოს მოვიდა ორი ცრუმოწმე," },
  { verse: 61, text: "რომლებმაც თქვეს: ეს ამბობდა: შემიძლია დავანგრიო ღმრთის ტაძარი და სამ დღეში კვლავ ავაშენოო." },
  { verse: 62, text: "მაშინ წამოდგა მღვდელმთავარი და უთხრა მას: რატომ არაფერს იტყვი იმის პასუხად, რასაც ესენი მოწმობენ შენს წინააღმდეგ?" },
  { verse: 63, text: "მაგრამ იესო დუმდა, და მღვღელმთავარმა უთხრა მას: გაფიცებ ცოცხალ ღმერთს, გვითხარი, შენ ხარ თუ არა ქრისტე, ძე ღმრთისა?" },
  { verse: 64, text: "უთხრა იესომ: შენ სთქვი. მე კი ამასაც გეტყვით: ამიერიდან მალე იხილავთ ძეს კაცისას, მჯდომარეს ძალის მარჯვნივ და მომავალს ზეცის ღრუბლებით." },
  { verse: 65, text: "მაშინ მღვდელმთავარმა შემოიხია სამოსი და თქვა: მან ღმერთი ჰგმო; მაშ, რაღად გვინდა მოწმენი? ხომ მოისმინეთ ღვთისგმობა მისი?" },
  { verse: 66, text: "რას იტყვით? ხოლო მათ პასუხად თქვეს: სიკვდილის ღირსია." },
  { verse: 67, text: "მაშინ სახეში დაუწყეს ფურთხება და ცემა, სხვები კი სილას აწნავდნენ" },
  { verse: 68, text: "და ეუბნებოდნენ: გვიწინასწარმეტყველე, ქრისტე, ვინ დაგარტყა შენ?" },
  { verse: 69, text: "პეტრე კი გარეთ იჯდა, ეზოში. მიადგა ერთი მხევალი და უთხრა: შენც ხომ იესო გალილეველთან იყავი?" },
  { verse: 70, text: "ხოლო მან ყველას წინაშე უარყო და თქვა: არ ვიცი, რას ამბობ." },
  { verse: 71, text: "და როცა ჭიშკარში გამოდიოდა, მეორე მხევალმა დაინახა და იქვე მდგომთ უთხრა: ესეც იესო ნაზორეველთან იყო." },
  { verse: 72, text: "ისევ უარყო პეტრემ ფიცით: არ ვიცნობ იმ კაცსო." },
  { verse: 73, text: "ცოტა ხნის შემდეგ იქ მდგომნიც მივიდნენ და უთხრეს პეტრეს: ჭეშმარიტად შენც ერთი მათთაგანი ხარ, რადგანაც შენივე კილო გამხილებს." },
  { verse: 74, text: "მაშინ ის მოჰყვა წყევლას და ფიცს, რომ არ იცნობს იმ კაცს, და სწორედ ამ დროს იყივლა მამალმა." },
  { verse: 75, text: "გაახსენდა პეტრეს იესოს ნათქვამი: მამლის ყივილამდე სამჯერ უარმყოფო; გამოვიდა გარეთ და მწარედ ატირდა." },
],

27: [
  { verse: 1, text: "როცა ინათა, მღვდელმთავრებმა და ხალხის უხუცესებმა ბჭობა გამართეს იესოს წინააღმდეგ, რათა მოეკლათ იგი." },
  { verse: 2, text: "შეკრეს იგი, წაიყვანეს, და მისცეს პონტიუს პილატეს, მთავარს." },
  { verse: 3, text: "მაშინ, რა იხილა იუდამ, მისმა გამცემმა, რომ მსჯავრი დასდეს, შეინანა და დაუბრუნა ოცდაათი ვერცხლი მღვდელმთავრებსა და უხუცესთ," },
  { verse: 4, text: "და თქვა: შევცოდე, რომ მოგეცით მართალი სისხლი. ხოლო მათ უთხრეს: ჩვენ რა? შენ იკითხე." },
  { verse: 5, text: "დაყარა ვერცხლი ტაძარში და იქაურობას გაეცალა: წავიდა და თავი ჩამოიხრჩო." },
  { verse: 6, text: "ხოლო მღვდელმთავრებმა აკრიფეს ვერცხლი და თქვეს: არ ეგება ტაძრის საგანძურში ამის დადება, ვინაიდან სისხლის საფასურია." },
  { verse: 7, text: "ბჭობა გამართეს და, უცხოთა სასაფლაოდ, იყიდეს იმით მეთუნის მიწა." },
  { verse: 8, text: "ამიტომაც ეწოდება ამ მიწას სისხლის მიწა დღევანდელ დღემდე." },
  { verse: 9, text: "მაშინ აღსრულდა თქმული იერემია წინასწარმეტყველის მიერ, რომელიც ამბობს: და აიღეს ოცდაათი ვერცხლი, საფასური შეფასებულისა, რომელიც შეფასდა ისრაელის ძეთა მიერ;" },
  { verse: 10, text: "და მისცეს ის მეთუნის მიწაში, როგორც მიბრძანა მე უფალმა." },
  { verse: 11, text: "ხოლო იესო წარდგა მთავრის წინაშე, და ჰკითხა მამთავარმა: შენა ხარ იუდეველთა მეფე? ხოლო იესომ მიუგო: შენ ამბობ." },
  { verse: 12, text: "და როდესაც მღვდელმთავრებმა და უხუცესებმა ბრალი დასდეს, არაფერი მიუგო მათ." },
  { verse: 13, text: "მაშინ უთხრა მას პილატემ: არ გესმის, რამდენ რასმე გწამებენ?" },
  { verse: 14, text: "მაგრამ არცერთ სიტყვაზე არაფერი მიუგო მას; ასე რომ, დიდად უკვირდა მთავარს." },
  { verse: 15, text: "ხოლო დღესასწაულზე ჩვევად ჰქონდა მთავარს, გაეთავისუფლებინა ხალხისთვის ერთი პატიმარი, რომელსაც მოისურვებდნენ." },
  { verse: 16, text: "იმხანად ჰყავდათ ერთი ცნობილი პატიმარი, რომელსაც ერქვა ბარაბა." },
  { verse: 17, text: "ამრიგად, როცა შეიკრიბნენ ისინი, უთხრა მათ პილატემ: ვინ გინდათ გაგითავისუფლოთ: ბარაბა თუ იესო, რომელსაც ჰქვია ქრისტე?" },
  { verse: 18, text: "რადგანაც იცოდა, რომ შურით გასცეს იგი." },
  { verse: 19, text: "და როცა სამსჯავრო სავარძელზე იჯდა, ცოლმა კაცის პირით შემოუთვალა: ნურაფერს დაუშავებ მაგ მართალს, ვინაიდან წუხელ სიზმარში ბევრი ვიტანჯე მის გამო." },
  { verse: 20, text: "მაგრამ მღვდელმთავრებმა და უხუცესებმა წააქეზეს ხალხი, გამოეთხოვათ ბარაბა, ხოლო იესო გაეწირათ." },
  { verse: 21, text: "და როცა მთავარმა ჰკითხა მათ: ვინ გინდათ გაგითავისუფლოთ ამ ორთაგანო, ხალხმა მიუგო: ბარაბა." },
  { verse: 22, text: "ჰკითხა მათ პილატემ: კი მაგრამ, რა ვუყო იესოს, რომელსაც ჰქვია ქრისტე? ყველამ მიუგო: ჯვარს ეცვას!" },
  { verse: 23, text: "ხოლო მთავარმა იკითხა: რა დააშავა? მაგრამ ისინი უფრო ხმამაღლა აყვირდნენ: ჯვარს ეცვას!" },
  { verse: 24, text: "და რაკი იხილა პილატემ, რომ ვერაფერს შველის, არამედ უფრო იზრდება შფოთი, მოითხოვა წყალი, ხალხის წინაშე დაიბანა ხელები და თქვა: მე უბრალო ვარ ამ მართლის სისხლში. თქვენ იკითხეთ." },
  { verse: 25, text: "მიუგო მთელმა ხალხმა და უთხრა: ჩვენზე იყოს და ჩვენს შვილებზე მაგისი სისხლი." },
  { verse: 26, text: "მაშინ გაუთავისუფლა მათ ბარაბა, ხოლო იესო გაამათრახებინა და ჯვარზე საცმელად მისცა მათ." },
  { verse: 27, text: "მაშინ მთავრის ჯარისკაცებმა პრეტორიუმში წაიყვანეს იესო, და გარს შემოერტყა მთელი რაზმი." },
  { verse: 28, text: "ტანთ გახადეს და შემოსეს მეწამული ქლამიდით." },
  { verse: 29, text: "დაწნეს ეკლის გვირგვინი და თავზე დაადგეს, მარჯვენა ხელში კი ლერწამი მისცეს; მუხლს იყრიდნენ მის წინაშე, დასცინოდნენ და ეუბნებოდნენ: გიხაროდეს, მეუფეო იუდეველთა!" },
  { verse: 30, text: "და აფურთხებდნენ, აიღეს ლერწამი და თავზე ამტვრევდნენ მას." },
  { verse: 31, text: "ხოლო როცა დაცინვით გული იჯერეს, შემოაძარცვეს ქლამიდი, კვლავ თავისი სამოსი ჩააცვეს და წაიყვანეს, რათა ჯვარს ეცვათ." },
  { verse: 32, text: "გზაში შემოხვდათ ერთი კირენელი კაცი, სახელად სიმონი; და აიძულეს წამოეღო იესოს ჯვარი." },
  { verse: 33, text: "და როცა მიაღწიეს იმ ადგილს, რომელსაც ჰქვია გოლგოთა, რაც ნიშნავს თხემის ადგილს," },
  { verse: 34, text: "მისცეს მას სასმელად ნაღველნარევი ძმარი, და როცა გემო გაუსინჯა, აღარ მოუნდა დალევა." },
  { verse: 35, text: "და როცა ჯვარს აცვეს, წილი ყარეს და გაიყვეს მისი სამოსი, რათა აღსრულდეს თქმული წინასწარმეტყველის მიერ, რომელიც ამბობს: ერთმანეთში გაიყვეს ჩემი სამოსი და ჩემს კვართზე იყარეს წილი." },
  { verse: 36, text: "ისხდნენ და იქ დარაჯობდნენ მას." },
  { verse: 37, text: "და დაუდგეს თავთით დაწერილი ბრალდება: ეს არის იესო, იუდეველთა მეფე!" },
  { verse: 38, text: "მაშინ ჯვარს აცვეს მასთან ერთად ორი ავაზაკი, ერთი მარჯვნივ და მეორე მარცხნივ." },
  { verse: 39, text: "ხოლო გამვლელნი აგინებღნენ, თავებს აქნევდნენ" },
  { verse: 40, text: "და ამბობდნენ: ტაძრის დამრღვევო და სამ დღეში აღმშენებელო, იხსენი შენი თავი; თუ ღმერთის ძე ხარ, ჩამოდი ჯვრიდან." },
  { verse: 41, text: "ასევე მღვდელმთავრები მწიგნობრებთან, უხუცესებსა და ფარისევლებთან ერთად დასცინოდნენ და ამბობდნენ:" },
  { verse: 42, text: "სხვები იხსნა და თავის ხსნა კი არ შეუძლია; თუ ისრაელის მეუფეა, დე, ჩამოვიდეს ჯვრიდან და ვიწამებთ მას." },
  { verse: 43, text: "ღმერთს იყო მინდობილი, და, თუ ნებავს, დე, იხსნას ახლა ღმერთმა, ვინაიდან თქვა: ძე ვარო ღმრთისა." },
  { verse: 44, text: "მის გვერდით ჯვარცმული ავაზაკნი ასევე აგინებდნენ მას." },
  { verse: 45, text: "ხოლო მეექვსე საათიდან მეცხრე საათამდე წყვდიადმა მოიცვა მთელი ქვეყანა." },
  { verse: 46, text: "და ასე, მეცხრე საათს ხმამაღლა შეღაღადა იესომ: ელი, ელი, ლამა საბაქთანი? რაც ნიშნავს, ღმერთო ჩემო, ღმერთო ჩემო, რად მიმატოვე მე?" },
  { verse: 47, text: "ზოგიერთმა იქ მდგომმა გაიგონა ეს და თქვა, ელიას უხმობსო." },
  { verse: 48, text: "მყისვე გაიქცა ერთი მათგანი, აიღო ღრუბელი, ძმრით გაჟღინთა, ლერწამზე წამოაგო და მიაწოდა სასმელად." },
  { verse: 49, text: "სხვები კი ამბობდნენ: მოიცათ, ვნახოთ, მოვა თუ არა ელია მის სახსნელად." },
  { verse: 50, text: "ხოლო იესომ კვლავ შეღაღადა ხმამაღლა და განუტევა სული." },
  { verse: 51, text: "და, აჰა, ზემოდან ქვემომდე, შუა ჩაიხა ტაძრის ფარდა, იძრა მიწა და დასკდნენ კლდენი." },
  { verse: 52, text: "განიხვნენ საფლავნი და წმიდა განსვენებულთა მრავალი გვამი აღდგა." },
  { verse: 53, text: "საფლავებიდან გამოვიდნენ მისი აღდგომის შემდეგ, წმიდა ქალაქში შევიდნენ და გამოეცხადნენ მრავალს." },
  { verse: 54, text: "ხოლო როდესაც იხილეს მიწისძვრა და ყოველივე ის, რაც მოხდა, ასისთავი და მასთან ერთად იესოს მოდარაჯენი, ძალიან შეშინდნენ და თქვეს: ჭეშმარიტად ღმრთის ძე იყო იგი." },
  { verse: 55, text: "იყო იქ აგრეთვე შორიდან მაცქერალი მრავალი ქალი, რომლებიც გალილეიღან მოჰყვებოდნენ იესოს და ემსახურებოდნენ მას." },
  { verse: 56, text: "მათ შორის იყვნენ მარიამ მაგდალელი, მარიამი, დედა იაკობისა და იოსებისა, და ზებედეს ძეთა დედა." },
  { verse: 57, text: "მწუხრის ჟამს მოვიდა მდიდარი არიმათიელი კაცი, სახელად იოსები, რომელიც აგრეთვე იესოს მოწაფე იყო." },
  { verse: 58, text: "მივიდა იგი პილატესთან და გამოითხოვა იესოს გვამი; და მაშინ ბრძანა პილატემ, მიეცათ მისთვის." },
  { verse: 59, text: "წამოიღო მისი გვამი იოსებმა, და შეახვია წმიდა ტილოში." },
  { verse: 60, text: "და დაასვენა იგი ახალ სამარხში, რომელიც კლდეში გამოეკვეთა; დიდი ლოდი მიაყუდა სამარხის კარს და წავიდა." },
  { verse: 61, text: "იყო იქ მარიამ მაგდალელი, და მეორე მარიამიც, რომლებიც სამარხის წინ ისხდნენ." },
  { verse: 62, text: "ხოლო მეორე დღეს, რომელიც მოსდევს პარასკევს, შეიკრიბნენ მღვდელმთავარნი და ფარისეველნი პილატეს კარზე" },
  { verse: 63, text: "და თქვეს: ბატონო, გაგვახსენდა, რომ ამ მაცდურმა სიცოცხლეში თქვა: სამი დღის შემდეგ აღვდგებიო." },
  { verse: 64, text: "მაშ, ბრძანე მესამე დღემდე უდარაჯონ სამარხს, რათა მისი მოწაფეები არ მივიდნენ ღამით, არ მოიპარონ იგი და უთხრან ხალხს: მკვდრეთით აღდგაო. და უკანასკნელი სიცრუე პირველზე უარესი იქნება." },
  { verse: 65, text: "უთხრა მათ პილატემ: დარაჯნი თქვენა გყავთ, წადით და უდარაჯეთ, როგორც გჩვევიათ." },
  { verse: 66, text: "ისინიც წავიდნენ, სამარხის დასაცავად დაბეჭდეს ლოდი და დარაჯი დაუყენეს." },
],
28: [
  { verse: 1, text: "ხოლო შაბათის დამლევს, კვირის პირველი დღის განთიადისას, მოვიდა მარიამ მაგდალელი და მეორე მარიამიც სამარხის სანახავად." },
  { verse: 2, text: "და, აჰა, საშინლად იძრა მიწა, ვინაიდან უფლის ანგელოზი ჩამოეშვა ზეცით, მივიდა, სამარხის კარიდან გადააგორა ლოდი და ზედ ჩამოჯდა." },
  { verse: 3, text: "სახე მისი იყო როგორც ელვა და სამოსი მისი - სპეტაკი, როგორც თოვლი." },
  { verse: 4, text: "მისი შიშით შეძრწუნდნენ საფლავის მცველნი და მკვდრებს დაემგვანენ." },
  { verse: 5, text: "მიმართა ანგელოზმა ქალებს და უთხრა: ნუ გეშინიათ, ვიცი, რომ ჯვარცმულ იესოს ეძებთ." },
  { verse: 6, text: "აქ აღარ არის, არამედ აღდგა, როგორც თქვა: მოდით და იხილეთ ის ადგილი, სადაც ესვენა." },
  { verse: 7, text: "დაუყოვნებლივ წადით, და უთხარით მის მოწაფეებს, რომ მკვდრეთით აღდგა და წინ მიგიძღვით გალილეისკენ; იქ იხილავთ მას. აჰა, გითხარით თქვენ." },
  { verse: 8, text: "ხოლო ისინი მსწრაფლ გამოვიდნენ სამარხიდან, შიშითა და დიდი სიხარულით მირბოდნენ, რათა ეუწყებინათ მისი მოწაფეებისათვის." },
  { verse: 9, text: "და, აჰა, შემოხვდა მათ იესო და უთხრა: გიხაროდეთ! ხოლო ისინი მივიდნენ, მუხლებზე მოეხვივნენ და თაყვანი სცეს მას." },
  { verse: 10, text: "მაშინ უთხრა მათ იესომ: ნუ გეშინიათ; წადით, აუწყეთ ჩემს ძმებს, რომ გალილეას წავიდნენ და იქ მიხილავენ." },
  { verse: 11, text: "და როცა ისინი წავიდნენ, აჰა, ზოგიერთი დარაჯთაგანი ქალაქში შევიდა და მოახსენა მღვდელმთავრებს ყველაფერი, რაც მოხდა." },
  { verse: 12, text: "ხოლო ისინი შეიკრიბნენ უხუცესებთან ერთად, ბჭობა გამართეს, დიდძალი ფული მისცეს ჯარისკაცებს" },
  { verse: 13, text: "და უთხრეს: თქვით, რომ მისი მოწაფეები მოვიდნენ ღამით და, ვიდრე გეძინათ, მოიპარეს იგი." },
  { verse: 14, text: "და თუ ეს ხმა მიაღწევს მთავრამდე, ჩვენ დავარწმუნებთ მას და უსიამოვნებისაგან გიხსნით." },
  { verse: 15, text: "მათაც აიღეს ფული და ისე მოიქცნენ, როგორც დარიგებულნი იყვნენ. და გავრცელდა ეს ხმა იუდეველთა შორის დღევანდელ დღემდე." },
  { verse: 16, text: "ხოლო თერთმეტი მოწაფე გალილეას წავიდა, იმ მთაზე, იესომ რომ დაუთქვა მათ." },
  { verse: 17, text: "იხილეს იგი და თაყვანი სცეს; ხოლო ზოგიერთი შეეჭვდა." },
  { verse: 18, text: "მიუახლოვდა იესო და უთხრა მათ: მომეცა მე მთელი ხელმწიფება ცაზედაც და მიწაზედაც." },
  { verse: 19, text: "მაშ, წადით, დაიმოწაფეთ ყველა ხალხი და ნათელი ეცით მათ მამის და ძის და სული წმიდის სახელით;" },
  { verse: 20, text: "ასწავლეთ მათ დაიცვან ყველაფერი, რაც გამცნეთ; და, აჰა, მე თქვენთანა ვარ დღემუდამ ვიღრე ქვეყნის დასასრულამდე. ამინ." },
],
};

